var __index = {"config":{"lang":["en"],"separator":"[\\s\\u200b\\u3000\\-\u3001\u3002\uff0c\uff0e\uff1f\uff01\uff1b]+","pipeline":["stemmer"]},"docs":[{"location":"index.html","title":"AI \u5de8\u5927\u5a18\u4f1a\u68a6\u89c1\u7535\u5b50\u5c0f\u4eba\u5417","text":"<p>\u5229\u7528\u6587\u672c\u5230\u56fe\u50cf\u751f\u6210\u6a21\u578b\u548c\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff0c\u5728\u5176\u5b83\u5de5\u5177\u7684\u5e2e\u52a9\u4e0b\u8fdb\u884c\u521b\u4f5c\u3002 \u4ee5\u53ca\u6ee1\u8db3\u81ea\u5df1\u7684 XP</p> <p>Info</p> <p>\u6b64\u6587\u6863\u7684\u4ed3\u5e93\uff08\u5bfc\u822a\u680f\u53f3\u4e0a\u89d2\uff0c\u6216\u662f\u8fd9\u4e2a\u94fe\u63a5\uff09\u6709\u5173\u4e8e\u5982\u4f55\u53c2\u4e0e\u8d21\u732e\uff0c\u548c\u5176\u5b83\u548c\u6b64\u6587\u6863\u6709\u5173\u8ba8\u8bba\u7684\u4fe1\u606f\u3002</p> <p>\u4f60\u6700\u597d\u6709\u4e00\u53f0\u7535\u8111</p> <p>\u4e0d\u8981\u6307\u671b\u53ea\u9760\u4e00\u90e8\u624b\u673a\u5c31\u80fd\u8fd0\u884c\u8fd9\u4e9b\u8f6f\u4ef6\u548c\u6a21\u578b\u3002</p> <p>\u6b64\u6587\u6863\u4e0d\u662f\u5b9d\u5b9d\u8f85\u98df</p> <p>\u8fd9\u5e76\u4e0d\u662f\u4e00\u4e2a\u5168\u9762\u8bb2\u89e3\u8fd9\u4e9b\u8f6f\u4ef6\u548c\u6a21\u578b\u5982\u4f55\u4f7f\u7528\u7684\u6587\u6863\uff0c\u4f8b\u5982\u6b64\u5904\u5e76\u4e0d\u4f1a\u8be6\u7ec6\u4ecb\u7ecd\u8f6f\u4ef6\u548c\u6a21\u578b\u7684\u4f7f\u7528\u65b9\u6cd5\uff0c \u4e5f\u4e0d\u8981\u6307\u671b\u6211\u4f1a\u5199\u4ec0\u4e48\u80fd\u591f\u9a6c\u4e0a\u8ba9\u4f60\u7528\u4e0a\u7684\u4ec0\u4e48\u201dXX\u4e00\u952eYY\u811a\u672c\u201c\u3002</p> <p>\u65f6\u523b\u8bb0\u4f4f Google\uff08\u6216\u5176\u5b83\u4f60\u7528\u7740\u987a\u624b\u7684\u641c\u7d22\u5f15\u64ce\uff09\u662f\u4f60\u7684\u670b\u53cb\u3002</p> <p>\u6b64\u6587\u6863\u7684\u4f5c\u8005\u4e0d\u662f\u4f60\u53cb\u597d\u7684\u514d\u8d39\u5ba2\u670d\u4e13\u7ebf</p> <p>\u6240\u4ee5\u4e0d\u8981\u62ff\u7740\u4f60\u4e0d\u77e5\u9053\u4ece\u54ea\u91cc\u5f04\u6765\u7684\u7b2c\u4e09\u65b9\u6e20\u9053/\u4e00\u952e\u811a\u672c/etc \u6765\u95ee\u4f5c\u8005\u4f60\u9047\u5230\u7684 XYZ \u95ee\u9898\u8fd8\u4e0d\u9644\u4e0a\u7ec8\u7aef\u8f93\u51fa \uff0c\u8c22\u8c22\u5408\u4f5c\u3002</p> <p>\u5982\u679c\u6587\u6863\u6709\u6b63\u4ea4\u6027</p> <p>\u6b64\u6587\u6863\u7684\u5927\u90e8\u5206\u5185\u5bb9\u4e5f\u8bb8\u4e5f\u9002\u5408\u5c55\u793a\u5176\u5b83\u7684 XP \ud83d\ude42</p> <p>\u597d\u6d88\u606f\uff0c\u597d\u6d88\u606f\uff01\ud83d\ude03</p> <p>\u597d\u6d88\u606f\uff01\u672c\u6587\u6863\u548c\u5404\u5927\u6d4f\u89c8\u5668\u5747\u8fbe\u6210\u4e86\u5408\u4f5c\uff0c\u4f7f\u7528 Ctrl-F \u5373\u53ef\u5728\u9875\u5185\u5feb\u901f\u641c\u7d22\u5173\u952e\u8bcd\uff01</p> <p>\u53e6\u5916\u5bfc\u822a\u680f\u4e0a\u7684\u641c\u7d22\u56fe\u6807\u4e5f\u53ef\u4ee5\u641c\u7d22\u82f1\u6587\u5355\u8bcd\uff08\u4e2d\u6587\u652f\u6301\u662f Insiders \u9650\u5b9a\uff0c\u4f46\u663e\u7136\u6211\u6ca1\u6709\u94b1\u4e70 \ud83e\udd72\uff09</p>"},{"location":"index.html#_1","title":"\u4ee3\u7801\u793a\u4f8b\u8bf4\u660e","text":"<p><code>$</code> \u8868\u793a\u9700\u8981\u7531\u4f60\u8f93\u5165\u7684\u547d\u4ee4\uff0c\u4f46\u4f60\u5728\u590d\u5236\u547d\u4ee4\u65f6\uff0c\u4e0d\u9700\u8981\u628a <code>$</code> \u7b26\u53f7\u548c\u4e4b\u524d\u7684\u5185\u5bb9\u4e5f\u4e00\u8d77\u590d\u5236\u3002  <pre><code># \u800c # \u5f00\u5934\u7684\u5185\u5bb9\u662f\u6ce8\u91ca\uff0c\u4f60\u4e5f\u4e0d\u9700\u8981\u590d\u5236\u5b83\u4eec\u3002\ndirectory $ command\n</code></pre></p> <p>\u4e8e\u662f\u5728\u4e0a\u9762\u7684\u4f8b\u5b50\u4e2d\uff0c\u4f60\u9700\u8981\u590d\u5236\u7684\u5c31\u662f <code>$</code> \u540e\u9762\u7684 <code>command</code> \u3002</p>"},{"location":"basic/index.html","title":"\u57fa\u7840\u77e5\u8bc6","text":"<p>Note</p> <p>\u6b64\u5904\u53ef\u80fd\u6ca1\u6709\u5305\u542b\u6240\u6709\u6982\u5ff5\u548c\u57fa\u7840\u77e5\u8bc6\u3002</p> <ul> <li>\u548c\u5177\u4f53\u9886\u57df\u76f8\u5173\u7684\u77e5\u8bc6\u5728\u5404\u81ea\u7684\u5206\u7c7b\u91cc\u3002</li> </ul> <p>\u4ee5\u53ca\u90a3\u4f60\u4e0d\u4f1a\u53bb\u95ee Google \u5417\uff1f</p>"},{"location":"basic/nodejs.html","title":"Node.js","text":"<p>Quote</p> <p>Node.js \u662f\u4e00\u4e2a\u5f00\u6e90\u548c\u8de8\u5e73\u53f0\u7684 JavaScript \u8fd0\u884c\u65f6\u73af\u5883\u3002\u5b83\u662f\u51e0\u4e4e\u6240\u6709\u7c7b\u578b\u9879\u76ee\u7684\u6d41\u884c\u5de5\u5177\uff01</p> <p>Node.js \u5728\u6d4f\u89c8\u5668\u4e4b\u5916\u8fd0\u884c V8 JavaScript \u5f15\u64ce\uff08Google Chrome \u7684\u6838\u5fc3\uff09\u3002\u8fd9\u4f7f\u5f97 Node.js \u7684\u6027\u80fd\u975e\u5e38\u51fa\u8272\u3002</p> <p>--NodeJS \u7b80\u4ecb</p> <p>\u4ecb\u4e8e\u4f60\u51e0\u4e4e\u4e0d\u4f1a\u5728\u8fd9\u4e2a\u573a\u666f\u4e0b\u5199 JavaScript \u4ee3\u7801\uff0c\u4f60\u53ea\u8981\u77e5\u9053\u4f60\u63a5\u4e0b\u6765\u4f7f\u7528\u7684\u67d0\u4e9b\u5de5\u5177\uff08\u4f8b\u5982 SillyTavern\uff09\u9700\u8981\u5b89\u88c5\u8fd9\u4e2a\u624d\u80fd\u8fd0\u884c\u5c31\u597d\u3002</p>"},{"location":"basic/nodejs.html#nodejs_1","title":"\u5b89\u88c5 Node.JS","text":"<p>Info</p> <p>\u8003\u8651\u5230\u6587\u6863\u8bfb\u8005\u7684\u53d7\u4f17\u3001\u667a\u529b\u6c34\u5e73\u548c\u9605\u8bfb\u7406\u89e3\u80fd\u529b\uff0c\u8fd9\u91cc\u4f1a\u591a\u201c\u5173\u7167\u201d Windows \u4e00\u70b9\u3002 \u5982\u679c\u4f60\u5df2\u7ecf\u662f\u4e2a\u719f\u7ec3\u7684 macOS / GNU/Linux \u7528\u6237\uff0c\u90a3\u4e48\u806a\u660e\u7684\u4f60\u5e94\u8be5\u81ea\u5df1\u5c31\u80fd\u641e\u5b9a\u3002\ud83d\ude42</p> <p>Node.js \u63d0\u4f9b\u4e86\u5982\u4f55\u5728\u5404\u4e2a\u64cd\u4f5c\u7cfb\u7edf\u4e0a\u901a\u8fc7\u5305\u7ba1\u7406\u5668\u5b89\u88c5\u7684\u6587\u6863\u3002</p>"},{"location":"basic/nodejs.html#windows","title":"Windows","text":"<p>\u8b66\u60d5\u56fd\u4ea7\u641c\u7d22\u5f15\u64ce\u8bc8\u9a97</p> <p>Node.js \u662f\u53ef\u4ee5\u514d\u8d39\u83b7\u53d6\u7684\uff0c\u81ea\u7531\u7684\u5f00\u653e\u6e90\u4ee3\u7801\u8f6f\u4ef6\u3002 \u5982\u679c\u4f60\u56e0\u4e3a\u4e0b\u8f7d\u8fd9\u4e2a\u4ed8\u4e86\u94b1\uff08\u4e0d\u542b\u53ef\u80fd\u4ea7\u751f\u7684\u7535\u8d39\u548c\u6d41\u91cf\u8d39\uff09\uff0c\u90a3\u4e48\u606d\u559c\u4f60\u88ab\u9a97\u4e86\u3002 \ud83d\ude43</p> <p>\u6253\u5f00\u4e0b\u8f7d Node.js \u9884\u6784\u5efa\u5b89\u88c5\u7a0b\u5e8f\u7684\u9875\u9762\uff1a  https://nodejs.org/zh-cn/download/prebuilt-installer</p> <p></p> <ul> <li>\u7b2c\u4e00\u4e2a\u9009\u9879\u9009\u62e9\u4f60\u7684\u64cd\u4f5c\u7cfb\u7edf\u3002</li> <li>\u7b2c\u4e8c\u4e2a\u9009\u9879\u9009\u62e9\u4f60\u7684\u7535\u8111 CPU \u7684\u4f53\u7cfb\u7ed3\u6784\uff0c\u9664\u975e\u4f60\u5bb6\u5883\u6bb7\u5b9e\u7528\u4e86\u642d\u8f7d\u9a81\u9f99\u5904\u7406\u5668\u7684 Windows \u7535\u8111\uff08\u90a3\u4f60\u9009\u201dARM64\u201c\uff09\uff0c\u5426\u5219\u90fd\u8be5\u9009\u201dx64\u201c\u3002</li> <li>\u7b2c\u4e09\u4e2a\u9009\u9879\u9009\u62e9\u4f60\u8981\u4e0b\u8f7d\u7684 Node.js \u7248\u672c\uff0c\u5927\u591a\u6570\u60c5\u51b5\u4e0b\uff0c\u4f60\u90fd\u5e94\u8be5\u9009\u62e9\u6700\u9760\u4e0a\u7684 LTS \u7248\u672c\u3002</li> </ul> <p>\u81f3\u4e8e\u5b89\u88c5\u5668\uff0c\u867d\u7136\u754c\u9762\u90fd\u662f\u82f1\u6587\uff0c\u4f46\u4f60\u53ef\u4ee5\u4e00\u8def Next \u7684\u70b9\u4e0b\u53bb\u3002</p>"},{"location":"basic/nodejs.html#termux","title":"Termux","text":"<p>\u4f60\u9700\u8981\u7684\u53ea\u662f\u8fd0\u884c\u4e00\u884c\u547d\u4ee4\uff1a</p> <pre><code>$ pkg install nodejs-lts\n</code></pre>"},{"location":"basic/nodejs.html#nodejs-npm","title":"\u914d\u7f6e Node.js \u4f7f\u7528\u5176\u5b83 NPM \u5b58\u50a8\u5e93","text":"<p>\u4e8b\u60c5\u5e76\u4e0d\u4f1a\u603b\u662f\u4e00\u5e06\u98ce\u987a\uff0c\u56e0\u4e3a\u8fd8\u662f\u90a3\u5835\u4f1f\u5927\u5149\u8363\u6b63\u786e\u7684\u9632\u706b\u5899\u5728\u7ed9\u4f60\u6dfb\u5835 \ud83d\ude43</p> <p>\u5982\u679c\u4f60\u5728\u8fd0\u884c <code>npm</code> \u547d\u4ee4\u65f6\u9047\u5230\u4e86\u4efb\u4f55\u7684\u7f51\u7edc\u9519\u8bef\uff0c\u4f60\u53ef\u4ee5\u5c1d\u8bd5\u4e3a npm \u8bbe\u7f6e\u66ff\u4ee3\u5b58\u50a8\u5e93\u4f4d\u7f6e\u3002 \u4f8b\u5982\u6dd8\u5b9d\u7684 <code>npmmirror</code>\u3002</p> <pre><code>$ npm config set registry https://registry.npmmirror.com\n</code></pre>"},{"location":"basic/terms.html","title":"\u4e00\u4e9b\u884c\u8bdd\uff08\u6216\u8005\u9ed1\u8bdd\uff09","text":"<p>TBD</p>"},{"location":"basic/termux.html","title":"Termux","text":"<p>Quote</p> <p>Termux is an Android terminal emulator and Linux environment app that works directly with no rooting or setup required.  A minimal base system is installed automatically - additional packages are available using the APT package manager</p> <p>Termux \u662f\u4e00\u6b3e Android \u4e0a\u7684\u7ec8\u7aef\u6a21\u62df\u5668\u548c Linux \u73af\u5883\u5e94\u7528\u7a0b\u5e8f\uff0c\u65e0\u9700 root \u6743\u9650\u5373\u53ef\u8fd0\u884c\u3002\u901a\u8fc7 apt \u8f6f\u4ef6\u5305\u7ba1\u7406\u5668\u53ef\u4ee5\u4e0b\u8f7d\u66f4\u591a\u8f6f\u4ef6</p> <p>-- https://termux.dev/en/</p> <p>\u901a\u8fc7 Termux\uff0c\u4e00\u4e9b\u652f\u6301\u8fdc\u7aef\u8ba1\u7b97\u6216 API \u8c03\u7528\u7684\u8f6f\u4ef6\u53ef\u4ee5\u5728\u624b\u673a\u4e0a\u8fd0\u884c\u3002\uff08\u4f8b\u5982 SillyTavern\uff09</p> <p>Warning</p> <p>\u770b\u5230\u8fd9\u4e2a\u63cf\u8ff0\u5c31\u77e5\u9053 iOS/iPadOS/HarmonyOS NEXT \u662f\u7528\u4e0d\u4e86\u7684\u3002</p> <p>Info</p> <p>Termux \u6587\u6863\u76ee\u524d\u4f4d\u4e8e https://wiki.termux.com/wiki/Main_Page \uff0c\u6b63\u5728\u8ba1\u5212\u8fc1\u79fb\u56de\u4e3b\u7ad9 </p>"},{"location":"basic/termux.html#_1","title":"\u4f7f\u7528\u5efa\u8bae","text":"<p>Quote</p> <p>\u7ffb\u8bd1\u81ea https://wiki.termux.com/wiki/Getting_started \u3002</p> <ul> <li> <p>\u5b66\u4e60 shell \u811a\u672c\uff01</p> <p>\u4f60\u4e0d\u4e00\u5b9a\u9700\u8981\u5341\u5206\u7cbe\u901a\uff0c\u4f46\u81f3\u5c11\u9700\u8981\u77e5\u9053\u81ea\u5df1\u5728\u505a\u4ec0\u4e48\uff0c\u4ee5\u53ca\u4f60\u83b7\u5f97\u7684\u5404\u79cd\u811a\u672c\u4f1a\u505a\u4ec0\u4e48\u3002</p> </li> <li> <p>\u59cb\u7ec8\u4fdd\u6301\u8f6f\u4ef6\u5305\u6700\u65b0\uff01</p> <p>\u5b9a\u671f\u8fd0\u884c<code>pkg upgrade</code> \u547d\u4ee4\uff0c\u6216\u81f3\u5c11\u5728\u5b89\u88c5\u65b0\u8f6f\u4ef6\u5305\u4e4b\u524d\u8fd0\u884c\u547d\u4ee4\u3002 \u4e0d\u66f4\u65b0\u8f6f\u4ef6\u5305\u6216\u964d\u7ea7\u8f6f\u4ef6\u5305\u6709\u53ef\u80fd\u4f1a\u5bfc\u81f4\u95ee\u9898\u3002</p> </li> <li> <p>\u4e00\u5b9a\u8981\u5907\u4efd\uff01</p> <p>\u56e0\u4e3a Termux \u4e0d\u63d0\u4f9b\u65e7\u7248\u672c\u7684\u8f6f\u4ef6\u5305\uff0c\u5e76\u4e14\u5b83\u662f\u4e00\u4e2a\u6eda\u52a8\u53d1\u5e03\u7248\u672c\u3002\u6240\u4ee5\u5982\u679c\u6ca1\u6709\u5907\u4efd\uff0c\u5982\u679c\u51fa\u73b0\u95ee\u9898\uff0c\u60a8\u53ef\u80fd\u65e0\u6cd5\u56de\u6eda\u3002</p> </li> <li> <p>\u4e0d\u8981\u6267\u884c\u4f60\u4e0d\u77e5\u9053\u7684\u811a\u672c\u548c\u547d\u4ee4\uff01</p> <p>\u67e5\u770b\u4ece\u4e92\u8054\u7f51\u4e0a\u4e0b\u8f7d\u7684\u811a\u672c\u3002\u4ed4\u7ec6\u68c0\u67e5\u4f60\u5728\u7ec8\u7aef\u4e2d\u8f93\u5165\u7684\u5185\u5bb9\u3002</p> </li> <li> <p>\u4ed4\u7ec6\u9605\u8bfb\u6253\u5370\u5230\u7ec8\u7aef\u7684\u6240\u6709\u5185\u5bb9\uff01</p> <p>\u7406\u89e3\u4fe1\u606f\u6d88\u606f\u6709\u52a9\u4e8e\u89e3\u51b3\u53ef\u80fd\u53d1\u751f\u7684\u95ee\u9898\u3002</p> </li> </ul>"},{"location":"basic/termux.html#_2","title":"\u4e0b\u8f7d","text":"<p>Warning</p> <p>Termux \u7684 Play \u5546\u5e97\u7248\u672c\u4e0d\u518d\u66f4\u65b0\u8bb8\u4e45\uff0c\u6700\u8fd1\u91cd\u65b0\u5f00\u59cb\u66f4\u65b0\u7684\u7248\u672c\u4e3a\u4e86\u901a\u8fc7 Google Play \u5546\u5e97\u7684\u5ba1\u6838\u800c\u5220\u9664\u4e86\u90e8\u5206\u529f\u80fd\uff0c\u56e0\u6b64\u5efa\u8bae\u901a\u8fc7\u4e0b\u8ff0\u7684 GitHub \u6216 F-Droid \u5b89\u88c5\u3002</p> <ul> <li>\u4e0b\u8f7d F-Droid:\uff1ahttps://f-droid.org/</li> <li>\u4e0b\u8f7d Termux\uff1ahttps://f-droid.org/zh_Hans/packages/com.termux/</li> </ul> <p>Termux \u7684\u4e00\u4e9b\u53ef\u9009\u7ec4\u4ef6</p> <p>\u9664\u4e86\u672c\u4f53 App \u4ee5\u5916\uff0cTermux \u652f\u6301\u901a\u8fc7\u4e00\u4e9b\u53ef\u9009 App \uff0c\u6269\u5c55\u51fa\u4e00\u4e9b\u989d\u5916\u529f\u80fd\u3002</p> <ul> <li> <p>Termux Styling: https://f-droid.org/zh_Hans/packages/com.termux.styling</p> <p>\u66f4\u6539 Termux \u7ec8\u7aef\u7684\u80cc\u666f\u548c\u5b57\u4f53\u3002</p> </li> <li> <p>Termux:Float\uff1ahttps://f-droid.org/zh_Hans/packages/com.termux.window/</p> <p>\u5728\u6d6e\u52a8\u7ec8\u7aef\u7a97\u53e3\u4e2d\u4f7f\u7528 Termux</p> </li> <li> <p>Termux:Widget\uff1ahttps://f-droid.org/zh_Hans/packages/com.termux.widget</p> <p>\u589e\u52a0\u53ef\u4ee5\u4ece\u4e3b\u5c4f\u5e55\u542f\u52a8 Termux \u547d\u4ee4\u7684\u5feb\u6377\u65b9\u5f0f\u6216\u684c\u9762\u5c0f\u7ec4\u4ef6\u3002</p> </li> <li> <p>Termux:API\uff1ahttps://f-droid.org/zh_Hans/packages/com.termux.api/</p> <p>\u4ece Termux \u8bbf\u95ee Android \u529f\u80fd\uff0c\u4f8b\u5982\u5171\u4eab\u5b58\u50a8\u7a7a\u95f4\u548c\u526a\u8d34\u677f\u3002</p> </li> <li> <p>Termux:Boot\uff1ahttps://f-droid.org/zh_Hans/packages/com.termux.boot/</p> <p>\u5141\u8bb8\u5728\u624b\u673a\u5f00\u673a\u65f6\u81ea\u52a8\u8fd0\u884c\u4e00\u4e9b Termux \u4e2d\u7684\u547d\u4ee4\u3002</p> </li> </ul> <p>Warning</p> <p>\u5728\u6b63\u5e38\u7684 Android \u7cfb\u7edf\u4e0a\uff0c\u4f60\u53ea\u8981\u6388\u4e88 F-Droid \u6216\u8005\u6d4f\u89c8\u5668\u201c\u5b89\u88c5\u672a\u77e5\u5e94\u7528\u201d\u6743\u9650\uff0c\u7136\u540e\u5c31\u53ef\u4ee5\u987a\u5229\u7684\u5b8c\u6210\u5b89\u88c5\u3002</p> <p>\u8bf7\u81ea\u884c\u89e3\u51b3\u5404\u79cd\u56fd\u4ea7\u201cOS\u201d\u4e2d\u60f3\u5c3d\u4e00\u5207\u529e\u6cd5\u963b\u6b62\u4f60\u5b89\u88c5\u4f60\u81ea\u5df1\u4e0b\u8f7d\u6765\u7684\u8f6f\u4ef6\u7684\u95ee\u9898\u3002</p>"},{"location":"basic/termux.html#_3","title":"\u7b2c\u4e00\u6b21\u542f\u52a8","text":"<p>\u4f60\u7b2c\u4e00\u6b21\u542f\u52a8 Termux \u7684\u753b\u9762\u5927\u7ea6\u5c31\u662f\u8fd9\u4e2a\u6837\u5b50\u3002</p> <p></p> <ul> <li>\u8f93\u5165\u6cd5\u952e\u76d8\u4e0a\u65b9\u7684\u6309\u952e\u63d0\u4f9b\u4e86\u8bb8\u591a\u5b9e\u7528\u7684\u529f\u80fd\u3002\u4f8b\u5982\u5149\u6807\uff0c\u4ee5\u53ca\u7535\u8111\u4e0a\u5e38\u89c1\u7684 Ctrl \u548c Alt \u952e\u3002</li> <li>\u5982\u679c\u89c9\u5f97\u5b57\u4f53\u5927\u5c0f\u592a\u5927\u6216\u662f\u592a\u5c0f\uff0c\u53ef\u4ee5\u53cc\u6307\u7f29\u653e\u8fdb\u884c\u8c03\u6574\u3002</li> <li> <p>\u4ece\u5de6\u8fb9\u6ed1\u52a8\u53ef\u4ee5\u6253\u5f00\u4f1a\u8bdd\u5217\u8868\u3002</p> <p></p> <ul> <li>\u70b9\u51fb\u201cKEYBOARD\u201d\u53ef\u4ee5\u5c55\u5f00\u6216\u9690\u85cf\u8f93\u5165\u6cd5\u7684\u865a\u62df\u952e\u76d8\u3002</li> <li>\u70b9\u51fb\u201cNEW SESSION\u201d\u53ef\u4ee5\u6253\u5f00\u4e00\u4e2a\u65b0\u7684\u4f1a\u8bdd\u7a97\u53e3\uff0c\u5728\u4f60\u9700\u8981\u540c\u65f6\u8fd0\u884c\u591a\u4e2a\u7a0b\u5e8f\u65f6\uff08\u4f8b\u5982 Clewd \u548c SillyTavern\uff09\u4f1a\u5f88\u6709\u7528\u3002</li> </ul> </li> </ul>"},{"location":"basic/termux.html#_4","title":"\u66f4\u6362\u955c\u50cf\u4ed3\u5e93","text":"<p>Tips</p> <p>\u4f7f\u7528\u5408\u9002\u7684\u955c\u50cf\u4ed3\u5e93\uff08\u4f8b\u5982\u94fe\u63a5\u901f\u5ea6\u6700\u5feb\u7684\uff09\uff0c\u53ef\u4ee5\u6709\u6548\u7f29\u77ed\u4f60\u5b89\u88c5\u8f6f\u4ef6\u6216\u5347\u7ea7\u65f6\u7684\u7b49\u5f85\u65f6\u95f4\u3002</p> <p>\u7279\u522b\u662f Termux \u9ed8\u8ba4\u7684\u4ed3\u5e93\u5728\u5899\u56fd\u8fde\u63a5\u4e0d\u4f73\u7684\u60c5\u51b5\u4e0b\u3002</p> <p>Info</p> <p>\u4f60\u6253\u4e86\u8fd9\u4e48\u591a\u5b57\uff0c\u603b\u8be5\u77e5\u9053 Enter/\u56de\u8f66/\u6362\u884c \u8bf4\u7684\u662f\u540c\u4e00\u4e2a\u952e\uff0c\u800c\u4e14\u4f60\u4e5f\u77e5\u9053\u662f\u54ea\u4e2a\u4e86\u5427\uff1f</p> <p>\u540e\u9762\u5c31\u7edf\u4e00\u53eb Enter \u4e86\u3002</p> <p>\u8f93\u5165 <code>termux-change-repo</code> \u7136\u540e\u6309 Enter \u8fd0\u884c\u3002</p> <p></p> <p>\u56e0\u4e3a\u9009\u62e9\u4e00\u7ec4\u955c\u50cf\u4ed3\u5e93\uff0c\u53ef\u4ee5\u5728\u4e00\u4e2a\u4ed3\u5e93\u8fde\u63a5\u5931\u8d25\u65f6\u5c1d\u8bd5\u53e6\u4e00\u4e2a\uff0c\u6240\u4ee5\u8fd9\u91cc\u76f4\u63a5\u8fdb\u5165\u4e0b\u4e00\u6b65\u3002</p> <p></p> <p>\u9009\u62e9\u955c\u50cf\u4ed3\u5e93\u7ec4\u7684\u4f4d\u7f6e\uff0c\u8fd9\u91cc\u628a\u5149\u6807\u6307\u5411\u8ddd\u79bb\u4f60\u6700\u8fd1\u7684\u4f4d\u7f6e\uff0c\u4f8b\u5982 China Mainland\uff0c\u7136\u540e\u6309\u7a7a\u683c\u952e\u9009\u62e9\u8fd9\u4e2a\u9009\u9879\u3002 \u4e00\u4e2a\u9009\u9879\u88ab\u9009\u4e2d\u65f6\uff0c\u524d\u9762\u4f1a\u6709\u4e00\u4e2a\u661f\u53f7\uff08*\uff09\u3002</p> <p></p> <p>\u6309 Enter \u786e\u8ba4\uff0cTermux \u4f1a\u81ea\u52a8\u6d4b\u8bd5\u8fde\u63a5\u5230\u5404\u4e2a\u955c\u50cf\u7ad9\u7684\u901f\u5ea6\uff0c\u7136\u540e\u9009\u62e9\u6700\u5feb\u7684\u4e00\u4e2a\u3002</p> <p></p> <p></p>"},{"location":"basic/termux.html#_5","title":"\u66f4\u65b0\u73af\u5883","text":"<p>\u9996\u5148\u8fd0\u884c <code>pkg update</code> \uff0c\u5b83\u4f1a\u66f4\u65b0\u8bbe\u5907\u4e0a\u7f13\u5b58\u7684\u8f6f\u4ef6\u4ed3\u5e93\u4e2d\u8f6f\u4ef6\u7684\u5217\u8868\uff0c\u7136\u540e\u62a5\u544a\u662f\u5426\u6709\u8f6f\u4ef6\u9700\u8981\u66f4\u65b0\u3002</p> <p></p> <p>\u8fd9\u91cc <code>41 packages can be upgraded. Run 'apt list --upgradable' to see them.</code>  \u5c31\u8868\u793a\u6709 41 \u4e2a\u8f6f\u4ef6\u5305\u53ef\u4ee5\u66f4\u65b0\uff1f</p> <p>\u90a3\u4e3a\u4ec0\u4e48\u91cc\u9762\u53eb\u505a apt \uff1f</p> <p>\u56e0\u4e3a Termux \u4f7f\u7528\u7684\u5305\u7ba1\u7406\u5668\u5176\u5b9e\u5c31\u662f apt\u3002</p> <p>\u5982\u679c\u4f60\u719f\u6089 apt \u7684\u4f7f\u7528\uff08\u4f8b\u5982\u4f60\u662f\u4e2a Debian/Ubuntu \u7528\u6237\uff09\uff0c\u4f60\u4e5f\u53ef\u4ee5\u50cf\u4ee5\u5f80\u4e00\u6837\u4f7f\u7528\u4f60\u719f\u6089\u7684 apt \u547d\u4ee4\u3002</p> <p>\u63a5\u4e0b\u6765\u8fd0\u884c <code>pkg upgrade</code>\u3002</p> <p></p> <p>\u4f1a\u63d0\u793a\u4f60\u54ea\u4e9b\u8f6f\u4ef6\u9700\u8981\u5347\u7ea7\uff0c\u4f1a\u4e0b\u8f7d\u591a\u5c11\u6570\u636e\u3002\u4f60\u53ef\u4ee5\u8f93\u5165 Enter \u7ee7\u7eed\u4e0b\u4e00\u6b65\u3002</p> <p>\u95ee\u9898\u4e2d\u7684 <code>[Y/n]</code> \u8868\u793a\u4ec0\u4e48\uff1f</p> <p>\u5927\u5199\u7684\u5b57\u6bcd\u7528\u6765\u8868\u793a\u5f53\u4f60\u76f4\u63a5\u6309\u4e0b Enter \u65f6\u4f1a\u505a\u51fa\u4ec0\u4e48\u9009\u62e9\uff0c\u4f8b\u5982\u5728\u8fd9\u91cc\u5c31\u662f\u786e\u8ba4\u3002</p> <p>\u67d0\u4e9b\u7834\u574f\u6027\u64cd\u4f5c\u7684\u9ed8\u8ba4\u503c\u53ef\u80fd\u662f\u53d6\u6d88\uff0c\u8fd9\u4e2a\u65f6\u5019\u4f60\u5f80\u5f80\u4f1a\u9047\u5230\u7c7b\u4f3c <code>[y/N]</code> \u7684\u63d0\u793a\u3002 \u5982\u679c\u4f60\u60f3\u7ee7\u7eed\uff0c\u90a3\u4e48\u5c31\u8f93\u5165\u4e00\u4e2a\u5b57\u6bcd<code>y</code>\uff0c\u7136\u540e\u6309Enter\u952e\u786e\u8ba4\u3002</p> <p></p> <p>\u5728\u7b2c\u4e00\u6b21\u5347\u7ea7\u7684\u65f6\u5019\uff0c\u4f60\u4e5f\u8bb8\u4f1a\u9047\u5230\u8fd9\u6837\u7684\u95ee\u9898\uff0c\u63d0\u793a\u4f60\u6587\u4ef6\u53ef\u80fd\u5b58\u5728\u51b2\u7a81\u3002</p> <pre><code>   What would you like to do about it ?  Your options are:\n   # Y/I: \u5b89\u88c5\u65b0\u6587\u4ef6\uff0c\u8986\u76d6\u73b0\u6709\u6587\u4ef6\n    Y or I  : install the package maintainer's version\n   # N/O\uff1a\u4fdd\u6301\u73b0\u6709\u6587\u4ef6\n    N or O  : keep your currently-installed version\n   # D\uff1a\u7528 diff \u5de5\u5177\u5c55\u793a\u6587\u4ef6\u95f4\u7684\u5dee\u5f02\u3002\n   # Z\uff1a\u6253\u5f00\u4e00\u4e2a\u65b0\u7684 Shell\uff0c\u7528\u4e8e\u6d4b\u8bd5\u53d8\u66f4\u3002\n   # \u8fd9\u4e24\u4e2a\u9009\u9879\u5982\u679c\u4f60\u4e0d\u77e5\u9053\u662f\u5728\u505a\u4ec0\u4e48\uff0c\u90a3\u4f60\u5c31\u7528\u4e0d\u4e0a\u3002\n      D     : show the differences between the versions\n      Z     : start a shell to examine the situation\n# \u9ed8\u8ba4\u9009\u9879\u662f\u62b1\u6301\u73b0\u6709\u6587\u4ef6\u4e0d\u53d8\u3002\n The default action is to keep your current version.\n*** sources.list (Y/I/N/O/D/Z) [default=N] ?\n</code></pre> <p>\u56e0\u4e3a\u7b2c\u4e00\u6b21\u5347\u7ea7\u65f6\uff0c\u6211\u4eec\u786e\u4fe1\u6ca1\u6709\u4fee\u6539\u8fc7\u54ea\u4e9b\u6587\u4ef6\uff0c\u6240\u4ee5\u4f60\u53ef\u4ee5\u8f93\u5165 <code>y</code> \u6216\u8005 <code>i</code> \u786e\u8ba4\u8986\u76d6\u3002</p> <p>\u5982\u679c\u4f60\u7b2c\u4e00\u6b21\u5347\u7ea7\u4e4b\u540e\u518d\u9047\u4e0a\u8fd9\u79cd\u95ee\u9898\uff0c\u8bf7\u683c\u5916\u5c0f\u5fc3</p> <p>\u4e4b\u540e\u5c31\u4e0d\u80fd\u65e0\u8111\u7684\u786e\u8ba4\u8986\u76d6\u4e86\uff0c\u9664\u975e\u4f60\u786e\u4fe1\u4f60\u6ca1\u6709\u4fee\u6539\u8fc7\u51b2\u7a81\u7684\u6587\u4ef6\u3002</p> <p>Info</p> <p>\u5347\u7ea7\u4e4b\u540e\u4f60\u7684\u955c\u50cf\u4ed3\u5e93\u8bbe\u7f6e\u53ef\u80fd\u4f1a\u88ab\u8fd8\u539f\u6210\u9ed8\u8ba4\u8bbe\u7f6e\u3002\u5efa\u8bae\u518d\u6309\u7167\u4e0a\u9762\u7684\u6b65\u9aa4\u8fd0\u884c\u4e00\u6b21\u8bbe\u7f6e\u955c\u50cf\u4ed3\u5e93\u7684\u547d\u4ee4\u3002</p>"},{"location":"basic/termux.html#_6","title":"\u5b89\u88c5\u8f6f\u4ef6","text":"<p>\u4e00\u884c\u547d\u4ee4\u5c31\u8db3\u591f\u4e86\uff0c\u4ee5\u5b89\u88c5 Node.js \u4e3a\u4f8b\u3002</p> <p><pre><code>~ $ pkg in nodejs-lts\nChecking availability of current mirror:\n[*] https://mirrors.tuna.tsinghua.edu.cn/termux/apt/termux-main: ok\nReading package lists... Done\nBuilding dependency tree... Done\nReading state information... Done\nThe following additional packages will be installed:\n  c-ares libicu\nSuggested packages:\n  clang make pkg-config python\nThe following NEW packages will be installed:\n  c-ares libicu nodejs-lts\n0 upgraded, 3 newly installed, 0 to remove and 0 not upgraded.\nNeed to get 19.5 MB of archives.\nAfter this operation, 101 MB of additional disk space will be used.\nDo you want to continue? [Y/n]\n</code></pre> \u5b89\u88c5\u8f6f\u4ef6\u65f6\u7684\u786e\u8ba4\u548c\u5347\u7ea7\u65f6\u4e00\u6837\uff0c\u4f60\u5728\u8fd0\u884c\u67d0\u4e9b\u672a\u627e\u5230\u7684\u547d\u4ee4\u7684\u65f6\u5019\uff0c\u4e5f\u4f1a\u6709\u673a\u7387\u63d0\u9192\u4f60\u8981\u5b89\u88c5\u54ea\u4e9b\u8f6f\u4ef6\u3002</p> <pre><code>~ $ node\nThe program node is not installed. Install it by executing:\n pkg install nodejs\nor\n pkg install nodejs-lts\n</code></pre> <p>Quote</p> <p>Termux \u7684\u6587\u6863\u6709\u5bf9 <code>pkg</code> \u547d\u4ee4\u7528\u6cd5\u7684\u66f4\u591a\u8be6\u7ec6\u4ecb\u7ecd\u3002</p> <p>https://wiki.termux.com/wiki/Package_Management</p>"},{"location":"basic/termux.html#termux_1","title":"\u4fdd\u6301 Termux \u540e\u53f0\u8fd0\u884c","text":"<p>Warning</p> <p>\u5728\u5927\u591a\u6570\u56fd\u4ea7\u54c1\u724c\u7684\u201dOS\u201c\u4e0a\uff0c\u4ec5\u4ec5\u8fd9\u4e48\u505a\u8fd8\u4e0d\u591f\u3002</p> <p>\u4f46\u6b64\u6587\u6863\u65e0\u6cd5\u6d89\u53ca\u6240\u6709\u54c1\u724c\u7684\u6240\u6709\u72b6\u51b5\uff0c\u8bf7\u81ea\u884c\u67e5\u627e\u5982\u4f55\u5728\u4f60\u7684\u624b\u673a\u4e0a\u4fdd\u6301\u5e94\u7528\u540e\u53f0\u8fd0\u884c\u7684\u65b9\u6cd5\u3002</p> <p>\u8fd9\u4e00\u90e8\u5206\u53ea\u4f1a\u63d0\u793a\u4f60\u5982\u4f55\u4e3a Termux \u5173\u95ed Android \u81ea\u5e26\u7684\u201d\u7535\u6c60\u4f18\u5316\u201c\u529f\u80fd\u3002</p> <p></p> <p>\u4e0b\u62c9\u901a\u77e5\u680f\uff0c\u70b9\u51fb Termux \u901a\u77e5\u4e2d\u7684 \"Acquire wakeclock\"\u3002</p> <p> </p> <p>\u62c9\u56de\u901a\u77e5\u680f\uff0c\u5141\u8bb8 Termux \u5728\u540e\u53f0\u8fd0\u884c\u3002</p> <p></p> <p>\u4e4b\u540e\u4f60\u53ef\u4ee5\u70b9\u51fb \"Release Wakeclock\" \u53d6\u6d88\u5e38\u9a7b\uff0c\u5728 Termux \u9000\u51fa\u65f6\uff0c\u8fd9\u4e2a\u72b6\u6001\u4e5f\u4f1a\u81ea\u52a8\u91cd\u7f6e\u3002</p>"},{"location":"basic/termux.html#termux_2","title":"\u67e5\u770b Termux \u6570\u636e","text":"<p>\u652f\u6301 DocumentProvider \u7684\u6587\u4ef6\u7ba1\u7406\u5668\u53ef\u4ee5\u67e5\u770b Termux \u6587\u4ef6\uff0c\u8fd9\u91cc\u63a8\u8350\u8d28\u611f\u6587\u4ef6\u3002</p> <p> \u6253\u5f00\u8d28\u611f\u6587\u4ef6\u7684\u83dc\u5355\uff0c\u9009\u62e9\u201d\u6dfb\u52a0\u5b58\u50a8\u7a7a\u95f4\u201c\u3002  \u9009\u62e9\u201d\u5916\u90e8\u5b58\u50a8\u7a7a\u95f4\u201c\u3002  \u5728\u6253\u5f00\u7684\u6587\u6863\u9009\u62e9\u5668\u7a97\u53e3\u4e2d\uff0c\u62c9\u51fa\u5de6\u8fb9\u7684\u83dc\u5355\uff0c\u9009\u62e9 \u201dTermux\u201c\u3002   \u9009\u62e9\u5e95\u90e8\u7684\u201d\u4f7f\u7528\u6b64\u6587\u4ef6\u5939\u201c\uff0c\u5e76\u786e\u8ba4\u3002  \u83dc\u5355\u4e2d\u65b0\u589e\u7684\u201dhome\u201c\u5c31\u662f Termux \u7684\u4e3b\u76ee\u5f55\u3002</p>"},{"location":"basic/termux.html#termux-prefix","title":"\u5907\u4efd\u548c\u8fd8\u539f Termux Prefix \u6570\u636e","text":"<p>Info</p> <p>\u4e3a\u4e86\u8ba9 Termux \u8bbf\u95ee\u7684\u624b\u673a\u7684\u5171\u4eab\u5b58\u50a8\u7a7a\u95f4\uff0c\u9996\u5148\u8981\u5b89\u88c5 Termux:API \u3002</p> <p>\u9664\u6b64\u4ee5\u5916\uff0ctermux-backup \u547d\u4ee4\u5e76\u4e0d\u4f1a\u5907\u4efd Termux \u4e3b\u76ee\u5f55\u7684\u6570\u636e\u3002</p> <p>\u5047\u5982\u4f60\u4e4b\u524d\u6ca1\u6709\u5728 Termux \u4e2d\u8bbf\u95ee\u8bbe\u5907\u7684\u5171\u4eab\u5b58\u50a8\u7a7a\u95f4\uff0c\u90a3\u4e48\u5148\u8fd0\u884c <code>termux-setup-storage</code> \u7136\u540e\u4e3a Termux \u6388\u4e88\u6240\u6709\u6587\u4ef6\u8bbf\u95ee\u6743\u9650\u3002 </p> <p>\u63a5\u4e0b\u6765\uff0c\u4f60\u5c31\u80fd\u5728 Termux \u7684\u4e3b\u76ee\u5f55\u91cc\u770b\u5230 <code>storage</code> \u76ee\u5f55\uff0c\u91cc\u9762\u662f\u5171\u4eab\u5b58\u50a8\u7a7a\u95f4\u7684\u7b26\u53f7\u94fe\u63a5\u3002 </p> <p>Info</p> <p>\u4f46\u662f\uff0cAndroid \u7684\u5171\u4eab\u5b58\u50a8\u7a7a\u95f4\uff08\u4ee5\u53ca\u5916\u90e8\u5b58\u50a8\u8bbe\u5907\uff09\u4e0d\u652f\u6301\u53ef\u6267\u884c\u6743\u9650\uff0c\u56e0\u6b64\u4e0d\u8981\u628a\u53ef\u6267\u884c\u6587\u4ef6\uff08\u4f8b\u5982\u811a\u672c\uff09\u653e\u5728\u90a3\u4e9b\u5730\u65b9\u3002</p> <p>\u8fd0\u884c <code>termux-backup</code> \u547d\u4ee4\u53ef\u4ee5\u5907\u4efd\u6574\u4e2a Termux \u76ee\u5f55\u4e2d\u7684\u5185\u5bb9\u3002</p> <p></p> <pre><code># termux-backup &lt;\u5907\u4efd\u7684\u8def\u5f84&gt;\n$ termux-backup ~/storage/shared/Documents/backup.tar.xz\n</code></pre> <p>\u5f85\u5230\u8fd0\u884c\u5b8c\u6bd5\u4e4b\u540e\uff0c\u53ef\u4ee5\u5728\u6587\u4ef6\u7ba1\u7406\u5668\u4e2d\u770b\u5230\u5907\u4efd\u7684\u6587\u4ef6\uff0c</p> <p></p> <p>\u8fd0\u884c <code>termux-restore</code> \u547d\u4ee4\u53ef\u4ee5\u4ece\u5907\u4efd\u8fd8\u539f\u3002</p> <p>Warning</p> <p>\u4f60 Termux \u5f53\u524d\u7684\u6240\u6709\u6570\u636e\u90fd\u5c06\u88ab\u5907\u4efd\u4e2d\u7684\u5185\u5bb9\u8986\u76d6\u3002</p>"},{"location":"basic/termux.html#termux-home","title":"\u5907\u4efd\u548c\u8fd8\u539f Termux \u4e3b\u76ee\u5f55\uff08home\uff09\u6570\u636e","text":""},{"location":"chatting/index.html","title":"AI \u804a\u5929\u76f8\u5173\u5de5\u5177\u548c\u77e5\u8bc6\u6982\u89c8","text":"<p>Tips</p> <p>\u70b9\u51fb\u5de6\u8fb9\u6216\u83dc\u5355\u5185\u7684\u5bfc\u822a\uff0c\u53ef\u4ee5\u5feb\u901f\u7684\u8df3\u5230\u76f8\u5173\u7684\u5c0f\u8282\u3002</p>"},{"location":"chatting/index.html#-","title":"\u91cd\u4e2d\u4e4b\u91cd - \u81ea\u5df1\u52a8\u624b\uff0c\u4e0d\u8981\u7ed9\u5978\u5546\u4ea4\u667a\u5546\u7a0e","text":"<ul> <li>\u672c\u6587\u6863\u7684\u6240\u6709\u90e8\u5206\u90fd\u5728\u9f13\u52b1\u4f60\u81ea\u884c\u5b89\u88c5\u548c\u8fd0\u884c\u5404\u79cd\u524d\u7aef\uff08\u4f8b\u5982 SillyTavern\uff09\uff0c   \u8d2d\u4e70 AI \u516c\u53f8\u63d0\u4f9b\u7684\u670d\u52a1\uff0c\u800c\u4e0d\u662f\u4ece\u5404\u79cd\u6765\u5386\u4e0d\u660e\u7684\u7b2c\u4e09\u65b9\u90a3\u91cc\u3002</li> <li>\u6765\u5386\u4e0d\u660e\u7684\u7b2c\u4e09\u65b9\u670d\u52a1\u4e5f\u8bb8\u4f1a\u6709\u4e0b\u9762\u6240\u8ff0\u7684\u5404\u79cd\u95ee\u9898\uff0c\u4e5f\u8bb8\u4e5f\u4f1a\u6709\u8fd9\u91cc\u6ca1\u6709\u8bb0\u8f7d\u7684\u66f4\u591a\u95ee\u9898\u3002</li> <li>\u5728\u67d0\u4e9b\u60c5\u51b5\u4e0b\uff0c\u4f60\u53ef\u4ee5\u5b8c\u5168\u65e0\u89c6\u8fd9\u4e00\u90e8\u5206\u7684\u5185\u5bb9\uff0c\u4f8b\u5982\u4f60\u4fe1\u4efb\u4f60\u7684\u6765\u6e90\uff08\u4f8b\u5982\u4f60\u8ba4\u8bc6\u7684\u670b\u53cb\uff09\uff0c\u6216\u662f\u4f60\u7518\u613f\u88ab\u5272\u97ed\u83dc</li> </ul> <p>\u4e3a\u4ec0\u4e48\uff1f</p>"},{"location":"chatting/index.html#_1","title":"\u53d6\u7528\u6a21\u578b\u7684\u4e3b\u8981\u65b9\u5f0f","text":""},{"location":"chatting/index.html#llm","title":"\u53d6\u5f97 LLM \u670d\u52a1\u7684\u767b\u5f55\u51ed\u636e","text":"<p>Tips</p> <p>\u65e0\u8bba\u4f60\u4f7f\u7528\u4ec0\u4e48\u524d\u7aef\uff0c\u4f60\u603b\u8981\u7528\u5b83\u4eec\u7684 API \u5bc6\u94a5\u8bbf\u95ee\u5b83\u4eec\u3002</p> <ul> <li>API \u5bc6\u94a5</li> </ul> <p>GPT Claude Gemini</p> <ul> <li>Cookie</li> </ul> <p>Claude</p>"},{"location":"chatting/index.html#clewd","title":"\u4f7f\u7528 Clewd","text":"<p>\u4e00\u79cd\u5229\u7528\u7f51\u9875\u7248 Claude \u53d1\u51fa\u6bd4\u7f51\u9875\u63d0\u4f9b\u7684\u66f4\u5177\u7075\u6d3b\u6027\u7684\u8bf7\u6c42\u7684\u65b9\u5f0f\u3002\u9700\u8981\u63d0\u524d\u83b7\u5f97 Claude \u7f51\u9875\u7248\u5e94\u7528\u7684 Cookie\u3002</p> <p>Tips</p> <p>\u7701\u6d41\uff1a\u9152\u9986\u662f\u4f7f\u7528 AI \u7684\u573a\u6240\uff0c\u5c0f\u514b(Claude)\u662f AI\uff0cClewd \u662f\u62d0\u9a97\u826f\u5bb6\u5c0f\u514b\u5230\u9152\u9986\u7684\u9ec4\u6bdb\uff0c\u7834\u9650\u662f\u9152\u3002</p>"},{"location":"chatting/index.html#_2","title":"\u4f7f\u7528\u672c\u5730\u6a21\u578b","text":"<p>Bug</p> <p>\u56e0\u4e3a\u6587\u6863\u4f5c\u8005\u8d22\u529b\u4e0d\u8db3\uff0c\u6682\u65f6\u6ca1\u6709\u548c\u672c\u5730\u8fd0\u884c\u6a21\u578b\u76f8\u5173\u7684\u5efa\u8bae\u3002</p>"},{"location":"chatting/index.html#-sillytavern","title":"\u5e38\u7528\u524d\u7aef - SillyTavern","text":"<p>SillyTavern\uff08\u7b80\u79f0 ST\uff0c\u4e2d\u6587\u4fd7\u79f0\u9152\u9986\uff09\u662f\u4e00\u4e2a\u5e38\u7528\u7684\u4f7f\u7528 LLM \u8fdb\u884c\u804a\u5929\u7684\u754c\u9762\u3002</p> <p>\u66f4\u591a\u4ecb\u7ecd \u5b89\u88c5\u548c\u8fd0\u884c \u5bfc\u5165\u89d2\u8272 \u5bfc\u5165\u9884\u8bbe \u5bfc\u5165\u5176\u5b83\u6587\u4ef6 \u5f00\u59cb\u804a\u5929</p> <p>\u5176\u5b83\u5e38\u89c1\u95ee\u9898 \u5b98\u65b9\u6587\u6863 (\u82f1\u6587) GitHub \u4ed3\u5e93</p>"},{"location":"chatting/index.html#_3","title":"\u5176\u5b83\u6559\u7a0b","text":"<p>Important</p> <p>\u56e0\u4e3a\u6587\u6863\u4e3b\u8981\u7684\u4f5c\u8005\u6ca1\u6709\u7528\u8fc7\u8fd9\u4e9b\u6559\u7a0b\uff0c\u6240\u4ee5\u4e0d\u8d1f\u8d23\u8fd9\u4e9b\u5185\u5bb9\u7684\u652f\u6301\u670d\u52a1\u3002</p> <p>\u5728\u53c2\u7167\u8fd9\u4e9b\u6559\u7a0b\u7684\u65f6\u5019\u5982\u679c\u9047\u5230\u95ee\u9898\uff0c\u8bf7\u54a8\u8be2\u6559\u7a0b\u7684\u539f\u59cb\u4f5c\u8005\uff0c\u6216\u5728\u6ce8\u660e\u6765\u6e90\u7684\u60c5\u51b5\u4e0b\uff0c\u8be2\u95ee\u4f60\u7684\u5176\u4ed6\u670b\u53cb\u3002</p> <ul> <li> <p>Claude \u5b9d\u5b9d\u6559\u7a0b </p> <p>\u7531 Discord \u670d\u52a1\u5668\u300c\u7c7b\u8111 \u039f\u0394\u03a5\u03a3\u03a3\u0395\u0399\u0391\u300d\u7684\u524d\u7ba1\u7406\u5458\u548c\u90e8\u5206\u7528\u6237\u7f16\u5199\u3002\u4e3b\u8981\u4ee5 Clewd \u548c Claude \u7684\u4f7f\u7528\u4e3a\u4e3b\u3002</p> <p>\u98de\u4e66\u9700\u8981\u767b\u5f55\u624d\u80fd\u590d\u5236\u6587\u6863\u4e2d\u7684\u5185\u5bb9\uff0c\u9664\u6b64\u4ee5\u5916\uff0c\u6587\u6863\u4e2d\u542b\u6709\u90e8\u5206\u975e\u5b98\u65b9\u6e20\u9053\u7684\u9500\u552e\u94fe\u63a5\uff0c\u6ce8\u610f\u7504\u522b\u3002</p> </li> </ul>"},{"location":"chatting/avoid_scamming.html","title":"\u8b66\u60d5\u6b3a\u8bc8\u884c\u4e3a\u517c\u4efb\u4e3a\u4ec0\u4e48\u9f13\u52b1\u4f60\u81ea\u5df1\u52a8\u624b","text":"<p>\u65bd\u5de5\u4e2d</p> <p>\u5495\u5495\u5495\u3002</p> <p>TL;DR</p> <ul> <li>\u672c\u6587\u6863\u7684\u6240\u6709\u90e8\u5206\u90fd\u5728\u9f13\u52b1\u4f60\u81ea\u884c\u5b89\u88c5\u548c\u8fd0\u884c\u5404\u79cd\u524d\u7aef\uff08\u4f8b\u5982 SillyTavern\uff09\uff0c   \u8d2d\u4e70 AI \u516c\u53f8\u63d0\u4f9b\u7684\u670d\u52a1\uff0c\u800c\u4e0d\u662f\u4ece\u5404\u79cd\u6765\u5386\u4e0d\u660e\u7684\u7b2c\u4e09\u65b9\u90a3\u91cc\u3002</li> <li>\u6765\u5386\u4e0d\u660e\u7684\u7b2c\u4e09\u65b9\u670d\u52a1\u4e5f\u8bb8\u4f1a\u6709\u4e0b\u9762\u6240\u8ff0\u7684\u5404\u79cd\u95ee\u9898\uff0c\u4e5f\u8bb8\u4e5f\u4f1a\u6709\u8fd9\u91cc\u6ca1\u6709\u8bb0\u8f7d\u7684\u66f4\u591a\u95ee\u9898\u3002</li> <li>\u5728\u67d0\u4e9b\u60c5\u51b5\u4e0b\uff0c\u4f60\u53ef\u4ee5\u5b8c\u5168\u65e0\u89c6\u8fd9\u4e00\u90e8\u5206\u7684\u5185\u5bb9\uff0c\u4f8b\u5982\u4f60\u4fe1\u4efb\u4f60\u7684\u6765\u6e90\uff08\u4f8b\u5982\u4f60\u8ba4\u8bc6\u7684\u670b\u53cb\uff09\uff0c\u6216\u662f\u4f60\u7518\u613f\u88ab\u5272\u97ed\u83dc\u3002</li> <li>\u6700\u540e\uff0c\u67d0\u4e9b\u793e\u533a\u4e0d\u4f1a\u89e3\u7b54\u4f60\u56e0\u4e3a\u4f7f\u7528\u5404\u79cd\u7b2c\u4e09\u65b9\u670d\u52a1\u800c\u9020\u6210\u7684\u95ee\u9898\uff0c\u751a\u81f3\u4f1a\u56e0\u6b64\u7981\u8a00/\u5c01\u7981\u4f60\u3002</li> </ul>"},{"location":"chatting/avoid_scamming.html#_2","title":"\u6765\u6e90\u4e0d\u660e\u7684\u7b2c\u4e09\u65b9\u670d\u52a1\u53ef\u80fd\u4f1a\u6709\u54ea\u4e9b\u98ce\u9669\uff1f","text":"<p>Warning</p> <p>\u518d\u6b21\u63d0\u9192\uff0c\u6b64\u5904\u5fc5\u7136\u6ca1\u6709\u53ef\u80fd\u5305\u542b\u6240\u6709\u60c5\u51b5\uff0c\u56e0\u4e3a\u4eba\u6027\u4e4b\u6076\u65e0\u6cd5\u4f30\u91cf\u3002</p>"},{"location":"chatting/avoid_scamming.html#_3","title":"\u76d7\u7528\u5e10\u53f7\uff08\u548c/\u6216\uff09\u51ed\u636e","text":""},{"location":"chatting/avoid_scamming.html#_4","title":"\u653e\u5927\u6d88\u8d39","text":""},{"location":"chatting/avoid_scamming.html#_5","title":"\u8f6c\u5ac1\u652f\u6301\u6210\u672c\uff08","text":""},{"location":"chatting/avoid_scamming.html#_6","title":"\u804a\u5929\u8bb0\u5f55\u6cc4\u9732","text":""},{"location":"chatting/avoid_scamming.html#_7","title":"\u672a\u5408\u7406\u6388\u6743\u7684\u7b2c\u4e09\u65b9\u5185\u5bb9\u4f7f\u7528","text":""},{"location":"chatting/avoid_scamming.html#_8","title":"\u8f6c\u5ac1\u652f\u6301\u6210\u672c","text":""},{"location":"chatting/avoid_scamming.html#_9","title":"\u717d\u52a8\u7fa4\u4f53","text":""},{"location":"chatting/api_connection/index.html","title":"\u53d6\u5f97 AI \u670d\u52a1\u7684 API \u5bc6\u94a5","text":"<p>Warning</p> <p>\u6b64\u6587\u6863\u4e0d\u4f1a\u6d89\u53ca\u5b98\u65b9\u9014\u5f84\u6216\u9700\u8981\u5b98\u65b9\u9014\u5f84\u53d6\u5f97\u7684\u767b\u5f55\u51ed\u636e\uff08Cookie\u6216API\u5bc6\u94a5\u7b49\uff09\u4ee5\u5916\u7684\u8fde\u63a5\u65b9\u5f0f\u3002 \u5728 SillyTavern \u5b98\u65b9 Discord \u670d\u52a1\u5668\u63d0\u53ca\u975e\u5b98\u65b9\u9014\u5f84\u4ee5\u5916\u7684\u53cd\u5411\u4ee3\u7406\u548c\u4e2d\u8f6c\u4f1a\u5bfc\u81f4\u4f60\u88ab\u5c01\u7981\u3002</p> <p>\u8bb0\u5f97\u53bb\u770b\u770b\u5b98\u65b9 API \u7684\u4ef7\u683c</p> <p>\u5373\u4f7f\u4f60\u4e0d\u80fd\u4eb2\u81ea\u5f00\u8bbe\u4ee5\u4e0b\u5e73\u53f0\u7684 API \u5e10\u53f7\uff0c\u6216\u662f\u613f\u610f\u7528\u522b\u4eba\u5bb6\u7684\u88ab\u522b\u4eba\u5272\u97ed\u83dc\uff0c\u4f60\u6700\u597d\u4e5f\u628a\u8fd9\u4e09\u5927\u5bb6\u5b98\u65b9\u7684\u4ef7\u683c\u8868\u770b\u4e00\u904d\uff0c\u6240\u6709\u4f4e\u4e8e\u8fd9\u4e2a\u5355\u4ef7\u7684\uff0c\u8981\u4e48\u662f\u6765\u8def\u4e0d\u6b63\u89c4\uff08\u4f8b\u5982\u7528\u4e00\u5806 Google \u5e10\u53f7\u767d\u5ad6 Gemini API \u7684\u514d\u8d39\u5c42\u7ea7\uff0c\u6216\u662f\u9003\u4e91\u670d\u52a1\u5e73\u53f0\u7684\u8d26\u5355\uff09\uff0c\u6216\u8005\u5c31\u662f\u5077\u6881\u6362\u67f1\uff08\u7528\u5176\u5b83\u4fbf\u5b9c\u7684\u6a21\u578b\u4ee3\u66ff\u5b83\u58f0\u79f0\u7684\u6a21\u578b\u7b49\u7b49\u3002</p> <p>\u300c\u662f\u5427 officechat \u529e\u516c\u5ba4? Gemini \u7684\u4fe1\u606f\u90fd\u5728\u4f60\u7528\u6237\u7684\u62a5\u9519\u4e2d\u51fa\u73b0\u4e86\u3002\u662f\u5427\u8d5b\u535a\u5973\u53cb(\u79d1\u666e\u767e\u6653\u751f)\uff0c\u89e3\u91ca\u4e00\u4e0b\u4f60\u7528\u6237\u62a5\u9519\u4e2d\u7684<code>you.com</code>?\u300d</p> <ul> <li>OpenAI Platform\uff08GPT \u7c7b\u6a21\u578b\uff0cAzure OpenAI Service \u7684\u5b9a\u4ef7\u76f8\u540c\uff09: https://openai.com/api/pricing/</li> <li>Anthropic Console\uff08Claude \u6a21\u578b\uff0cAWS Bedrock / Google Vertex AI \u4e2d\u7684 Claude \u6a21\u578b\u7684\u5b9a\u4ef7\u76f8\u540c\uff09\uff1ahttps://www.anthropic.com/pricing#anthropic-api</li> <li>Google Gemini\uff1a https://cloud.google.com/vertex-ai/generative-ai/pricing?hl=zh-cn#gemini-models</li> </ul> <p>\u5f00\u901a OpenAI / Anthropic \u5b98\u65b9 API \u670d\u52a1\u7684\u5148\u51b3\u6761\u4ef6</p> <p>\u9664\u4e86 Google Cloud\uff0c\u53e6\u5916\u4e24\u5bb6\u90fd\u9700\u8981\u6709\u4e00\u4e2a\u652f\u6301\u533a\u57df\u7684\u624b\u673a\u53f7\u548c\u94f6\u884c\u5361\uff08\u56e0\u4e3a\u4f17\u6240\u5468\u77e5\u7684\u539f\u56e0\uff0c\u80af\u5b9a\u6ca1\u6709\u4e2d\u56fd\u5927\u9646\u548c\u9999\u6e2f\uff09\u3002</p> <p>\u5982\u679c\u4f60\u53ef\u4ee5\u4e0d\u901a\u8fc7 App Store \u548c Play Store \u8ba2\u9605 ChatGPT Plus \u6216\u8005 Claude Pro\uff0c\u90a3\u5e94\u8be5\u5c31\u6ca1\u95ee\u9898\u3002</p>"},{"location":"chatting/api_connection/index.html#openai-chatgpt","title":"OpenAI \u6a21\u578b\uff08ChatGPT \u7b49\uff09","text":"<ul> <li>\u5982\u679c\u4f60\u6709 OpenAI \u652f\u6301\u533a\u57df\u7684\u624b\u673a\u53f7\u7801\u548c\u94f6\u884c\u5361\uff0c\u53ef\u4ee5\u81ea\u884c\u5f00\u8bbe OpenAI API \u5e10\u53f7\uff1a https://openai.com/api/pricing/</li> <li>\u9000\u800c\u6c42\u5176\u6b21\uff0c\u5982\u679c\u4f60\u6709\u5e26 VISA/Mastercard \u6216\u662f American Express \u6807\u5fd7\u7684\u56fd\u9645\u4fe1\u7528\u5361/\u501f\u8bb0\u5361\uff0c\u53ef\u4ee5\u5c1d\u8bd5 OpenAI \u4e1c\u5bb6\u5fae\u8f6f Azure \u4e0b\u7684 Azure OpenAI Service \u670d\u52a1\uff1ahttps://azure.microsoft.com/zh-cn/products/ai-services/openai-service</li> </ul> <p>\u524d\u5f80 OpenAI Platform \u524d\u5f80 Azure AI Studio \u8be6\u7ec6\u6b65\u9aa4</p>"},{"location":"chatting/api_connection/index.html#anthropic-claude","title":"Anthropic \u6a21\u578b\uff08Claude\uff09","text":"<p>\u6587\u6863\u90e8\u5206\u5185\u5bb9\u6682\u7f13\u66f4\u65b0</p> <p>\u56e0\u4e3a Anthropic \u6536\u7d27\u4e86\u7ed9 Google Cloud \u548c AWS Bedrock \u4e0a Claude \u7684\u914d\u989d\u3002\u4e3b\u8981\u8868\u73b0\u4e3a\u4e0d\u80fd\u7533\u8bf7\u5f00\u901a\uff0c\u6216\u8005\u5f00\u901a\u4e4b\u540e\u6ca1\u6709\u914d\u989d\u7b49\u7b49\u3002\u56e0\u6b64\u8fd9\u4e24\u90e8\u5206\u5185\u5bb9\u6682\u65f6\u505c\u66f4\u3002</p> <ul> <li>\u5982\u679c\u4f60\u6709 Anthropic \u652f\u6301\u533a\u57df\u7684\u624b\u673a\u53f7\u7801\u548c\u94f6\u884c\u5361\uff0c\u53ef\u4ee5\u81ea\u884c\u5f00\u8bbe Anthropic Console \u5e10\u53f7\uff1ahttps://www.anthropic.com/pricing#anthropic-api</li> <li>\u9000\u800c\u6c42\u5176\u6b21\uff0c\u5982\u679c\u4f60\u6709\u5e26 VISA/Mastercard \u6216\u662f American Express \u6807\u5fd7\u7684\u56fd\u9645\u4fe1\u7528\u5361/\u501f\u8bb0\u5361\uff0c\u53ef\u4ee5\u5c1d\u8bd5\u901a\u8fc7 AWS Bedrock\uff08https://aws.amazon.com/bedrock/claude/ \uff09\u6216 Google Vertex AI \uff08https://cloud.google.com/vertex-ai/generative-ai/docs/partner-models/use-claude?hl=zh-cn \uff09\u4f7f\u7528 Claude \u6a21\u578b\u3002</li> </ul> <p>\u524d\u5f80 Anthropic Console \u8be6\u7ec6\u6b65\u9aa4</p> <p>\u901a\u8fc7 Vertex API \u5728 SillyTavern \u4f7f\u7528 Claude?</p> <p>\u56e0\u4e3a SillyTavern \u5e76\u4e0d\u76f4\u63a5\u652f\u6301\u8fd9\u6837\u505a\uff0c\u4f60\u9700\u8981\u901a\u8fc7\u4e00\u4e9b\u989d\u5916\u7684\u624b\u6bb5\uff0c\u5c06 Vertex API \u8c03\u7528\u8f6c\u6362\u4e3a SillyTavern \u652f\u6301\u7684\uff0c\u517c\u5bb9 OpenAI \u7684\u8c03\u7528\u65b9\u5f0f\u3002</p> <ul> <li>oai-reverse-proxy \u6b63\u662f\u5176\u4e2d\u4e00\u79cd\u65b9\u5f0f\u3002</li> </ul>"},{"location":"chatting/api_connection/index.html#google-gemini","title":"Google Gemini","text":"<ul> <li>\u4f60\u53ef\u4ee5\u81ea\u884c\u524d\u5f80 Google AI Studio \u7533\u8bf7 API \u5bc6\u94a5\uff1a https://ai.google.dev/gemini-api/docs/ai-studio-quickstart?hl=zh-cn </li> <li>\u5bf9\u4e8e IP \u4f4d\u4e8e Gemini \u652f\u6301\u7684\u533a\u57df\uff08\u56e0\u4e3a\u4f17\u6240\u5468\u77e5\u7684\u539f\u56e0\uff0c\u80af\u5b9a\u6ca1\u6709\u9999\u6e2f\uff0c\u6709\u5b8c\u5168\u4e0d\u53ef\u9760\u7684\u6d88\u606f\u8bf4 Google \u6ca1\u6709\u963b\u6b62\u4e2d\u56fd\u5927\u9646\u7684 IP \u8fde\u63a5 Gemini API\uff0c\u4f46\u662f Google \u5728\u4e2d\u56fd\u5927\u9646\u65e9\u5c31\u5168\u7ebf\u88ab\u5899\u4e86\uff09\uff0c\u4e14\u4e0d\u662f\u6b27\u6d32\u7ecf\u6d4e\u533a\uff0c\u82f1\u56fd\u6216\u745e\u58eb\u7684\u8bdd\uff0cGemini \u63d0\u4f9b\u514d\u8d39\u5c42\u7ea7\uff0c\u867d\u7136\u914d\u989d\u5361\u7684\u5f88\u7d27\u4f46\u5e94\u8be5\u4e5f\u591f\u7528\u3002\u8138\u76ae\u591f\u539a\u8fd8\u6709\u624b\u6bb5\u7684\u8bdd\uff0c\u6ce8\u518c\u4e00\u5806 Google \u5e10\u53f7\u6765\u56de\u53bb\u5ad6\u4e5f\u662f\u53ef\u4ee5\u7684\u3002</li> <li>\u5982\u679c\u4f60\u6709\u5e26 VISA/Mastercard \u6216\u662f American Express \u6807\u5fd7\u7684\u56fd\u9645\u4fe1\u7528\u5361/\u501f\u8bb0\u5361\uff0c\u901a\u8fc7\u5173\u8054\u6709\u4ed8\u6b3e\u8d44\u6599\u7684 Google Cloud \u9879\u76ee\uff0c\u4f60\u7684 API \u4fbf\u662f\u4ed8\u8d39\u5c42\u7ea7\u4e86\u3002\u4ed8\u8d39\u5c42\u7ea7\u7684\u5b9a\u4ef7\u5728\uff1a https://ai.google.dev/pricing?hl=zh-cn \u3002\u4ee5\u53ca\u867d\u7136\u4e0d\u4e00\u5b9a\u90fd\u4f1a\u76f8\u4fe1\uff0c\u4f46 Google \u8bf4\u514d\u8d39\u5c42\u7ea7\u8c03\u7528\u7684\u8f93\u5165\u4f1a\u7528\u4e8e\u6539\u8fdb\u4ea7\u54c1\u7684\u63d0\u793a\u548c\u54cd\u5e94\uff0c\u4ed8\u8d39\u5c42\u7ea7\u5219\u4e0d\u4f1a\u3002</li> </ul> <p>\u524d\u5f80 Google AI Studio \u8be6\u7ec6\u6b65\u9aa4</p>"},{"location":"chatting/api_connection/anthropic.html","title":"Anthropic Console","text":"<p>\u83b7\u53d6 API \u9875\u9762\u5728\u8fd9\u91cc\uff1a https://console.anthropic.com/settings/keys</p> <p></p> <p>\u70b9\u51fb \u201cCreate Key\u201d \u6309\u94ae\u3002</p> <p></p> <p>\u5728\u70b9\u51fb Add \u786e\u8ba4\u4e4b\u524d\uff0c\u53ef\u4ee5\u4e3a API \u53bb\u4e00\u4e2a\u540d\u5b57\uff0c\u4f8b\u5982\u5728\u54ea\u91cc\u7528\u7684\u3002</p> <p></p> <p>\u5728\u4e0b\u4e00\u4e2a\u9875\u9762\uff0c\u70b9\u51fb Copy Key \u628a\u751f\u6210\u7684 API \u5bc6\u94a5\u590d\u5236\u4e0b\u6765\u3002</p> <p>\u4f60\u53ea\u6709\u8fd9\u4e00\u6b21\u590d\u5236\u8fd9\u4e2a API \u5bc6\u94a5\u7684\u673a\u4f1a</p> <p>\u5f53\u70b9\u51fb Close \u5173\u95ed\u5bf9\u8bdd\u6846\u4e4b\u540e\uff0c\u4f60\u5c31\u65e0\u6cd5\u518d\u67e5\u770b\u8fd9\u4e2a API \u5bc6\u94a5\u7684\u503c\u4e86\uff0c\u53ea\u80fd\u7981\u7528\u6216\u5220\u9664\u4e4b\u540e\u91cd\u65b0\u751f\u6210\u4e00\u4e2a\u3002</p> <p></p> <p>\u65e5\u540e\u5982\u679c\u4f60\u4e0d\u518d\u4f7f\u7528\uff0c\u6216\u662f\u4e0d\u5c0f\u5fc3\u6cc4\u9732\u4e86\u5bc6\u94a5\uff0c\u4f60\u53ef\u4ee5\u901a\u8fc7 Disable\uff08\u7981\u7528\uff09\u6216 Delete\uff08\u5220\u9664\uff09\u8fd9\u4e2a API \u5bc6\u94a5\u3002</p> <p>\u533a\u522b\u5728\u4e8e\u7981\u7528\u4e4b\u540e\u53ef\u4ee5\u91cd\u65b0\u542f\u7528\uff0c\u4f46\u5220\u9664\u4e4b\u540e\u53ea\u80fd\u91cd\u65b0\u751f\u6210\u3002</p>"},{"location":"chatting/api_connection/azure.html","title":"Azure OpenAI Service","text":""},{"location":"chatting/api_connection/gemini.html","title":"\u901a\u8fc7 Google AI Studio \u53d6\u5f97 Gemini API \u5bc6\u94a5","text":"<p>Google AI Studio \u548c Vertex AI \u5e76\u4e0d\u4e00\u6837</p> <p>\u4e3b\u8981\u7684\u533a\u522b\u5c31\u662f Google AI Studio \u5728\u5927\u90e8\u5206 Gemini API \u652f\u6301\u7684\u533a\u57df\u63d0\u4f9b\u514d\u8d39\u989d\u5ea6\uff0c \u800c\u4f9d\u6258\u4e8e Google Cloud \u7684 Vertex AI \u5e76\u6ca1\u6709\u3002</p> <p>\u4f46\u4f60\u53ea\u662f\u60f3\u7528 Gemini API \u7684\u8bdd\uff0c\u7528 Google AI Studio \u5c31\u884c\u4e86\u3002</p>"},{"location":"chatting/api_connection/gemini.html#api","title":"\u53d6\u5f97 API \u5bc6\u94a5","text":"<p>\u53d6\u5f97 API \u5bc6\u94a5\u7684\u9875\u9762\u4f4d\u4e8e https://aistudio.google.com/apikey \u3002</p> <p></p> <p>\u70b9\u51fb\u201d\u521b\u5efa API \u5bc6\u94a5\u201c\u6309\u94ae\u3002</p> <p></p> <p>\u9009\u62e9\u4e00\u4e2a\u5df2\u6709\u7684 Google Cloud \u9879\u76ee\uff0c\u6216\u662f\u5728\u8fd9\u91cc\u521b\u5efa\u4e00\u4e2a\u9879\u76ee\u3002</p> <p></p> <p></p> <p>\u5728\u4e0b\u4e00\u4e2a\u7a97\u53e3\u4e2d\u628a\u751f\u6210\u7684\u5bc6\u94a5\u590d\u5236\u4e0b\u6765\u3002</p> <p></p> <p>\u65e5\u540e\u4f60\u53ef\u4ee5\u70b9\u51fb\u5bc6\u94a5\u5217\u8868\u6765\u518d\u6b21\u590d\u5236 API \u5bc6\u94a5\u7684\u503c\uff0c\u6216\u662f\u5220\u9664\u5bc6\u94a5\u3002</p>"},{"location":"chatting/api_connection/oai.html","title":"OpenAI Platform","text":"<p>OpenAI Platform : https://platform.openai.com/docs/overview</p>"},{"location":"chatting/api_connection/oai.html#api","title":"\u53d6\u5f97 API \u5bc6\u94a5","text":"<p>\u754c\u9762\u4f4d\u4e8e https://platform.openai.com/settings/organization/api-keys \u3002</p> <p></p> <p>\u70b9\u51fb\u5de6\u4e0a\u89d2\u7684\u201cCreate new secret key\u201c \u6309\u94ae\u3002</p> <p></p> <ul> <li>Owned by \uff08\u6240\u6709\u8005\uff09\u9009\u62e9\u201dYou\u201c\uff08\u4f60\uff09\u3002</li> <li>\u5728\u201dName\u201c\u91cc\u53ef\u4ee5\u4e3a\u4f60\u7684\u5bc6\u94a5\u8d77\u4e00\u4e2a\u540d\u5b57\uff0c\u53ef\u4ee5\u7528\u6765\u533a\u5206\u7528\u9014\u3002</li> <li>\u5728\u201dProject\u201c\u91cc\u9009\u62e9\u8fd9\u4e2a\u5bc6\u94a5\u5f52\u5c5e\u7684\u9879\u76ee\uff0c\u5047\u5982\u4f60\u6ca1\u6709\u521b\u5efa\u9879\u76ee\uff0c\u90a3\u4e48\u5c31\u53ea\u6709\u4e00\u4e2a Default Project\u3002</li> <li>\u201dPermissions\u201c\uff08\u6743\u9650\uff09\u7528\u4e8e\u6307\u5b9a\u6b64 API \u5bc6\u94a5\u7684\u6743\u9650\u8303\u56f4\uff0c\u5982\u679c\u4f60\u641e\u4e0d\u61c2\u90a3\u4e9b\u5177\u4f53\u90e8\u5206\u7684\u542b\u4e49\uff0c\u90a3\u5c31\u9009\u62e9\u9ed8\u8ba4\u7684 All\u3002</li> </ul> <p></p> <p>\u63a5\u4e0b\u6765\u7684 \u201dSave your key\u201c \u7a97\u53e3\u4f1a\u663e\u793a\u4f60\u65b0\u5efa\u7684 API \u5bc6\u94a5\u7684\u503c\uff0c\u70b9\u51fb\u7eff\u8272\u7684 Copy \u6309\u94ae\u590d\u5236\u4e0b\u6765\u3002</p> <p>\u4f60\u53ea\u6709\u8fd9\u4e00\u6b21\u590d\u5236\u8fd9\u4e2a API \u5bc6\u94a5\u7684\u673a\u4f1a</p> <p>\u5f53\u70b9\u51fb Done \u5173\u95ed\u5bf9\u8bdd\u6846\u4e4b\u540e\uff0c\u4f60\u5c31\u65e0\u6cd5\u518d\u67e5\u770b\u8fd9\u4e2a API \u5bc6\u94a5\u7684\u503c\u4e86\uff0c\u53ea\u80fd\u7981\u7528\u6216\u5220\u9664\u4e4b\u540e\u91cd\u65b0\u751f\u6210\u4e00\u4e2a\u3002</p>"},{"location":"chatting/api_connection/oai_reverse_proxy.html","title":"oai-reverse-proxy","text":"<p>oai-reverse-proxy \u662f\u4e00\u4e2a\u5728\u672c\u5730\u8fd0\u884c\u7684\u53cd\u5411\u4ee3\u7406\uff0c\u53ef\u4ee5\u628a Vertex AI / AWS Bedrock / Azure OpenAI \u7684 API \u8c03\u7528\u8f6c\u6362\u4e3a OpenAI \u517c\u5bb9\u7684\u683c\u5f0f\uff0c\u4ece\u800c\u8ba9\u9152\u9986\u53ef\u4ee5\u4f7f\u7528\u3002</p> <p>\u5f00\u59cb\u4e4b\u524d</p> <ul> <li>\u5982\u679c\u4f60\u8981\u901a\u8fc7\u9152\u9986\u7528 Gemini \u6a21\u578b\uff0c\u90a3\u4f60\u9700\u8981\u505a\u7684\u4e0d\u662f\u770b\u8fd9\u4e2a\u6559\u7a0b\uff0c\u800c\u662f\u53bb Google AI Studio \u7533\u8bf7 API \u5bc6\u94a5\uff0c\u7136\u540e\u628a\u83b7\u5f97\u7684 API \u5bc6\u94a5\u586b\u8fdb \u9152\u9986\u7684 MakerSuite API \u5bc6\u94a5\u91cc\u9762\u3002</li> <li>\u4f60\u9700\u8981\u81ea\u5df1\u5148\u53d6\u5f97\u5bf9\u5e94\u7684 API \u670d\u52a1\u7684\u8bbf\u95ee\u6743\u9650\u3002</li> <li>\u4f60\u9700\u8981\u81ea\u884c\u89e3\u51b3\u53cd\u5411\u4ee3\u7406\u672c\u8eab\u5982\u4f55\u8fde\u63a5\u5230\u539f\u59cb API \u7684\u95ee\u9898\uff0c\u5305\u62ec\u4f46\u4e0d\u9650\u4e8e\u56fd\u5bb6\u7ea7\u9632\u706b\u5899\uff0cVertex AI \u548c Claude \u4e0d\u652f\u6301\u7684\u533a\u57df\u7b49\u7b49\u3002</li> <li>\u4e0d\u8981\u76f4\u63a5\u628a\u8fd9\u73a9\u610f\u6254\u5230\u516c\u7f51\u4e0a\uff0c\u9664\u975e\u4f60\u5f88\u6709\u94b1\u3002 \u4f46\u662f\u5982\u679c\u4f60\u6709\u8db3\u591f\u7684\u667a\u6167\u8bbe\u7f6e\u50cf\u662f Cloudflare Tunnel \u4e00\u7c7b\u7684\u96a7\u9053\uff0c\u6216\u8005\u662f\u770b\u597d\u914d\u7f6e\u6587\u4ef6\u8bbe\u7f6e\u597d ACL\uff0c\u90a3\u5927\u6982\u4f60\u4e5f\u7528\u4e0d\u4e0a\u6211\u7ed9\u4f60\u5199\u6559\u7a0b\u3002</li> <li>\u5c0f\u5fc3\u4fdd\u7ba1\u4f60\u590d\u5236\u7684 API \u5bc6\u94a5\u3001\u4f60\u4e0b\u8f7d\u7684\u670d\u52a1\u8d26\u6237\u79c1\u94a5\u6587\u4ef6\uff0c\u548c oai-reverse-proxy \u7684\u914d\u7f6e\u6587\u4ef6\u3002\u9664\u975e\u4f60\u4eba\u7f8e\u5fc3\u5584\u4e0d\u6015\u81ea\u5df1\u8d26\u5355\u7206\u70b8\u3002</li> </ul>"},{"location":"chatting/api_connection/oai_reverse_proxy.html#_1","title":"\u51c6\u5907\u5de5\u4f5c","text":""},{"location":"chatting/api_connection/oai_reverse_proxy.html#vertex-ai","title":"Vertex AI","text":"<ul> <li> <p>\u6309\u7167 Google Cloud \u7684\u6587\u6863\uff0c\u628a\u300c\u51c6\u5907\u5de5\u4f5c\u300d\u90a3\u4e00\u6b65\u505a\u5b8c\u3002\uff1a https://cloud.google.com/vertex-ai/generative-ai/docs/partner-models/use-claude?hl=zh-cn</p> </li> <li> <p>\u521b\u5efa\u4e00\u4e2a\u670d\u52a1\u5e10\u53f7\uff0c\u5e76\u6388\u4e88\u8bbf\u95ee\u524d\u8ff0\u9879\u76ee\u548c\u4f7f\u7528 Claude \u6a21\u578b\u7684\u6743\u9650\u3002\uff08Consumer Procurement Entitlement Manager Identity and Access Management \u548c Vertex AI User \u89d2\u8272\uff09\uff0c\u5e76\u4e0b\u8f7d\u76f8\u5e94\u7684\u51ed\u636e\u3002</p> </li> </ul> <p>\u76f8\u5173\u7684 Google Cloud \u6587\u6863\u3002 * \u4e3a\u7528\u6237\u542f\u7528 Claude \u6a21\u578b * \u670d\u52a1\u5e10\u53f7\u6982\u89c8 * \u521b\u5efa\u670d\u52a1\u5e10\u53f7</p>"},{"location":"chatting/api_connection/oai_reverse_proxy.html#oai-reverse-proxy_1","title":"\u914d\u7f6e oai-reverse-proxy","text":"<ul> <li>oai-reverse-proxy \u6709\u4e24\u4e2a\u4e3b\u8981\u5206\u652f\uff0cknanon \u7684\u539f\u7248\u548c cg-dot \u7684 fork \u9009\u4e00\u4e2a\u7528\u5373\u53ef\u3002\u4e0b\u9762\u4ee5 cg-dot \u7684\u4ed3\u5e93\u4e3a\u4f8b\u3002</li> <li>\u4ee5\u53ca docs/gcp-configuration.md \u4ecb\u7ecd\u4e86\u8be5\u600e\u4e48\u8bbe\u7f6e Google Cloud \u7684\u670d\u52a1\u8d26\u6237\uff0c .env.example \u4ecb\u7ecd\u4e86\u914d\u7f6e\u6587\u4ef6\u8be5\u600e\u4e48\u5199\u3002</li> <li>\u5982\u679c\u4f60\u6709\u8db3\u591f\u7684\u667a\u6167\u6210\u529f\u8fd0\u884c\u8d77\u9152\u9986\uff0c\u90a3\u5927\u6982\u4f60\u5df2\u7ecf\u88c5\u597d Node.js \u548c Git \u4e86\uff0c\u8fd9\u91cc\u5c31\u4e0d\u8d58\u8ff0\u600e\u4e48\u88c5\u4e86\u3002</li> </ul> <pre><code># \u514b\u9686\u4ed3\u5e93\n$ git clone https://github.com/cg-dot/oai-reverse-proxy\n$ cd oai-reverse-proxy\n# \u4ece\u793a\u4f8b\u590d\u5236\u4e00\u4efd\u914d\u7f6e\u6587\u4ef6\u3002\noai-reverse-proxy $ cp .env.example .env\n# \u7528\u4f60\u7231\u7528\u7684\u7f16\u8f91\u5668\u6253\u5f00\u4ece\u793a\u4f8b\u6587\u4ef6\u590d\u5236\u8fc7\u6765\u7684 .env \u6587\u4ef6\noai-reverse-proxy $ $EDITOR .env\n</code></pre>"},{"location":"chatting/api_connection/oai_reverse_proxy.html#vertex-ai_1","title":"Vertex AI \u8bbe\u7f6e","text":"<p>\u4f60\u4e0b\u8f7d\u5230\u7684\u670d\u52a1\u8d26\u6237\u5bc6\u94a5 JSON \u6587\u4ef6\u5927\u7ea6\u4f1a\u662f\u8fd9\u4e2a\u6837\u5b50\uff1a</p> <p>\u4f60\u770b\u5230\u7684 private_key \u4e0d\u4f1a\u90a3\u4e48\u77ed\uff0c\u6211\u4e5f\u6ca1\u667a\u5546\u4e0b\u7ebf\u5230\u76f4\u63a5\u628a\u79c1\u94a5\u8d34\u7ed9\u4f60\u3002</p> <pre><code>{\n  \"type\": \"service_account\",\n  \"project_id\": \"vertexsandbox-114514\",\n  \"private_key_id\": \"abcdef123456\",\n  \"private_key\": \"-----BEGIN PRIVATE KEY-----\\nabcdef19890604fedcba-----END PRIVATE KEY-----\\n\",\n  \"client_email\": \"oai-reverse-proxy@vertexsandbox-114514.iam.gserviceaccount.com\",\n  \"client_id\": \"123456\",\n  \"auth_uri\": \"https://accounts.google.com/o/oauth2/auth\",\n  \"token_uri\": \"https://oauth2.googleapis.com/token\",\n  \"auth_provider_x509_cert_url\": \"https://www.googleapis.com/oauth2/v1/certs\",\n  \"client_x509_cert_url\": \"https://www.googleapis.com/robot/v1/metadata/x509/oai-reverse-proxy%40vertexsandbox-114514.iam.gserviceaccount.com\",\n  \"universe_domain\": \"googleapis.com\"\n}\n</code></pre> <p>\u4f60\u5728 <code>.env</code> \u91cc\u8bbe\u7f6e\u7684 <code>GCP_CREDENTIALS</code> \u73af\u5883\u53d8\u91cf\u5e94\u8be5\u5982\u4e0b\u6240\u793a\u3002 </p> <pre><code>GCP_CREDENTIALS=&lt;\u9879\u76eeID&gt;:&lt;\u670d\u52a1\u5e10\u53f7\u7535\u5b50\u90ae\u4ef6\u5730\u5740&gt;:&lt;Google Cloud \u533a\u57df\uff0c\u63a8\u8350 us-east5&gt;:&lt;\u79c1\u94a5\u6587\u672c&gt;\n</code></pre> <p>\u4f8b\u5982\u4e0a\u9762\u7684\u4f8b\u5b50\u5bf9\u5e94\u7684\u7ed3\u679c\u4f1a\u662f</p> <pre><code>GCP_CREDENTIALS=vertexsandbox-114514:oai-reverse-proxy@vertexsandbox-114514.iam.gserviceaccount.com:us-east5:-----BEGIN PRIVATE KEY-----\\nabcdef19890604fedcba-----END PRIVATE KEY-----\n</code></pre>"},{"location":"chatting/api_connection/oai_reverse_proxy.html#_2","title":"\u5176\u5b83\u8bbe\u7f6e","text":"<p>\u5982\u679c\u4f60\u6ca1\u6709\u4ece\u53e6\u5916\u4e00\u53f0\u8bbe\u5907\u8fde\u63a5\u7684\u9700\u6c42\uff0c\u90a3\u540c\u65f6\u5efa\u8bae\u53ea\u76d1\u542c\u672c\u5730\u5730\u5740\u3002</p> <pre><code># The port and network interface to listen on.\nPORT=7860\nBIND_ADDRESS=127.0.0.1\n</code></pre>"},{"location":"chatting/api_connection/oai_reverse_proxy.html#_3","title":"\u542f\u52a8\u670d\u52a1","text":"<p>\u7136\u540e\u5b89\u88c5\u4f9d\u8d56\u542f\u52a8\u670d\u52a1\u3002</p> <pre><code>oai-reverse-proxy $ npm install\noai-reverse-proxy $ npm run start:dev\n</code></pre> <p>\u52a0\u5165\u4e00\u5207\u6b63\u5e38\u7684\u8bdd\uff0c\u4f60\u5e94\u8be5\u53ef\u4ee5\u6253\u5f00\u914d\u7f6e\u6587\u4ef6\u8bbe\u7f6e\u7684\u5730\u5740\u548c\u7aef\u53e3\uff08\u9ed8\u8ba4\u662f http://localhost:7860 \uff09\uff0c\u67e5\u770b\u53cd\u5411\u4ee3\u7406\u7684\u8fd0\u884c\u72b6\u6001\u3002</p> <pre><code>{\n  \"uptime\": 28,\n  \"endpoints\": {\n    \"gcp\": \"http://localhost:7860/proxy/gcp/claude\"\n  },\n  \"proompts\": 0,\n  \"tookens\": \"0\",\n  \"proomptersNow\": 0,\n  \"gcpKeys\": 1,\n  \"gcp-claude\": {\n    \"usage\": \"0 tokens\",\n    \"activeKeys\": 1,\n    \"revokedKeys\": 0,\n    \"sonnetKeys\": 0,\n    \"sonnet35Keys\": 1,\n    \"haikuKeys\": 0,\n    \"proomptersInQueue\": 0,\n    \"estimatedQueueTime\": \"no wait\"\n  },\n...\n</code></pre>"},{"location":"chatting/api_connection/oai_reverse_proxy.html#_4","title":"\u914d\u7f6e\u9152\u9986\u4f7f\u7528\u53cd\u5411\u4ee3\u7406","text":"<ul> <li>API \u7c7b\u578b\u9009\u62e9\u201c\u81ea\u5b9a\u4e49\uff08\u517c\u5bb9 OpenAI\uff09</li> <li>\u81ea\u5b9a\u4e49\u7ec8\u7ed3\u70b9\u586b\u5165\u53cd\u5411\u4ee3\u7406\u9875\u9762\u90a3\u4e2a JSON \u91cc <code>endpoints.gcp</code> \u7684\u503c\uff0c\u4f8b\u5982 <code>http://localhost:7860/proxy/gcp/claude</code> \u3002</li> <li>\u63d0\u793a\u8bcd\u540e\u5904\u7406\u9009 Claude\u3002</li> <li>\u5047\u5982\u914d\u7f6e\u6b63\u786e\uff0c\u4f60\u70b9\u51fb\u2018\u8fde\u63a5\u2019\u7684\u65f6\u5019\uff0c\u53ef\u7528\u6a21\u578b\u4f1a\u663e\u793a\u76f8\u5e94\u7684 Claude \u6a21\u578b\u3002\u4f46\u662f\u6d4b\u8bd5\u8fde\u63a5\u603b\u4f1a\u6210\u529f\uff08oai-reverse-proxy \u4f1a\u5728\u68c0\u6d4b\u5230\u53d1\u9001\u7684\u6d88\u606f\u662f\u6d4b\u8bd5\u6d88\u606f\u65f6\u4e0d\u8bf7\u6c42API\u800c\u662f\u76f4\u63a5\u8fd4\u56de\u6210\u529f\uff09\uff0c\u6240\u4ee5\u6700\u597d\u662f\u76f4\u63a5\u5f00\u59cb\u4e00\u6761\u5bf9\u8bdd\u6d4b\u8bd5\u3002</li> </ul>"},{"location":"chatting/api_connection/clewd/account.html","title":"\u6ce8\u518c Claude \u5e10\u53f7","text":"<p>\u7b80\u800c\u8a00\u4e4b</p> <p>\u4f60\u9700\u8981\u8fd9\u4e9b\u4e1c\u897f\uff1a</p> <ul> <li>\u4e00\u4e2a\u90ae\u7bb1\uff08\u6216\u662f Google \u5e10\u53f7/ Apple ID\uff09\uff0c\u6709\u5b8c\u5168\u672a\u7ecf\u9a8c\u8bc1\u7684\u8bf4\u6cd5\u8868\u793a\u901a\u8fc7 Google \u5e10\u53f7/ Apple ID \u6ce8\u518c\u66f4\u5bb9\u6613\u88ab\u5c01\u3002</li> <li>\u4e00\u4e2a Claude \u652f\u6301\u5730\u533a\u7684\u624b\u673a\u53f7\uff08\u8be6\u89c1 https://www.anthropic.com/supported-countries \uff0c\u4e0d\u8fc7\u81f3\u5c11\u6ca1\u6709\u4e2d\u56fd\u5927\u9646\u548c\u9999\u6e2f\uff09\u3002</li> </ul>"},{"location":"chatting/api_connection/clewd/clewd.html","title":"Clewd","text":"<p>Clewd \u662f\u4e00\u79cd\u5229\u7528\u7f51\u9875\u7248 Claude \u53d1\u51fa\u6bd4\u7f51\u9875\u63d0\u4f9b\u7684\u66f4\u5177\u7075\u6d3b\u6027\u7684\u8bf7\u6c42\u7684\u65b9\u5f0f\u3002\u9700\u8981\u63d0\u524d\u83b7\u5f97 Claude \u7f51\u9875\u7248\u5e94\u7528\u7684 Cookie\u3002</p> <p>Tips</p> <p>\u7701\u6d41\uff1a\u9152\u9986\u662f\u4f7f\u7528 AI \u7684\u573a\u6240\uff0c\u5c0f\u514b(Claude)\u662f AI\uff0cClewd \u662f\u62d0\u9a97\u826f\u5bb6\u5c0f\u514b\u5230\u9152\u9986\u7684\u9ec4\u6bdb\uff0c\u7834\u9650\u662f\u9152\u3002</p> <p>\u4f60\u53c8\u591a\u8fdd\u53cd\u4e86\u4e00\u6761 Anthropic \u7684\u670d\u52a1\u6761\u6b3e \ud83d\ude43</p> <p>\u8fd9\u79cd\u65b9\u5f0f\u663e\u7136\u8fdd\u53cd Anthropic \u7684 Claude \u6d88\u8d39\u8005\u670d\u52a1\u534f\u8bae\u3002(3.7 \u8282\uff0c\u7981\u6b62\u4ee5\u975e Anthropic API \u4ee5\u5916\u7684\u901a\u8fc7\u673a\u5668\u4eba\u3001\u811a\u672c\u6216\u5176\u4ed6\u81ea\u52a8\u6216\u975e\u4eba\u5de5\u65b9\u5f0f\u8bbf\u95ee Anthropic \u670d\u52a1\u3002) , \u5f53\u7136\u4f60\u8d8a\u72f1\u548c\u641e\u989c\u8272\u5176\u5b9e\u4e5f\u8fdd\u53cd\u4e86 Claude \u7684\u53ef\u63a5\u53d7\u4f7f\u7528\u653f\u7b56\uff0c\u56e0\u6b64 Anthropic \u53ef\u80fd\u4f1a\u5c01\u4f60\u7684 Claude \u5e10\u53f7\uff0c</p> <p>\u5f00\u59cb\u4e4b\u524d</p> <p>\u5728\u5f00\u59cb\u4e4b\u524d\uff0c\u8bf7\u786e\u8ba4\u4ee5\u4e0b\u4e8b\u9879\uff1a</p> <ul> <li>\u8981\u8fd0\u884c Clewd \u7684\u73af\u5883\u5df2\u7ecf\u5b89\u88c5\u4e86 Node.js \u548c Git\u3002</li> <li>\u4f60\u62e5\u6709\u4e00\u4e2a\u6ce8\u518c\u5b8c\u6bd5\uff0c\u53ef\u4ee5\u4f7f\u7528\u7684 Claude \u5e10\u53f7\u3002\u5e76\u83b7\u5f97\u4e86\u4e00\u4e2a\u6b64\u5e10\u53f7\u7684 Cookie\u3002</li> </ul>"},{"location":"chatting/api_connection/clewd/clewd.html#git-clewd","title":"\u901a\u8fc7 Git \u4e0b\u8f7d Clewd","text":"<p>\u514b\u9686 Clewd \u7684\u4ed3\u5e93\u76ee\u5f55\uff1a</p> <pre><code>$ git clone https://github.com/teralomaniac/clewd.git\n</code></pre> <p>\u5728 Clewd \u7684\u76ee\u5f55\u91cc\uff0c\u8fd0\u884c <code>npm</code> \u547d\u4ee4\u5b89\u88c5\u4f9d\u8d56\u3002\u4f60\u53ef\u4ee5\u5ffd\u7565 <code>npm fund</code> \u548c <code>npm audit</code> \u7684\u8b66\u544a\u3002\uff08\u53cd\u6b63\u4f60\u4e5f\u4e0d\u4f1a\u4fee\uff09</p> <p>\u4e8b\u60c5\u5e76\u975e\u80fd\u591f\u603b\u662f\u4e00\u5e06\u98ce\u987ax2</p> <p>\u56e0\u4e3a\u8fd8\u662f\u90a3\u5835\u4f1f\u5927\u5149\u8363\u6b63\u786e\u7684\u9632\u706b\u5899\u5728\u7ed9\u4f60\u6dfb\u5835 \ud83d\ude43</p> <p>\u5982\u679c\u4f60\u5728\u8fd0\u884c <code>npm</code> \u547d\u4ee4\u65f6\u9047\u5230\u4e86\u4efb\u4f55\u7684\u7f51\u7edc\u9519\u8bef\uff0c\u4f60\u53ef\u4ee5\u5c1d\u8bd5\u4e3a npm \u8bbe\u7f6e\u66ff\u4ee3\u5b58\u50a8\u5e93\u4f4d\u7f6e\u3002 \u4f8b\u5982\u6dd8\u5b9d\u7684 <code>npmmirror</code>\u3002</p> <pre><code>$ npm config set registry https://registry.npmmirror.com\n</code></pre> <p><pre><code>clewd $ npm install\n</code></pre> <pre><code>added 26 packages, and audited 27 packages in 8s\n\n3 packages are looking for funding\n  run `npm fund` for details\n\n2 moderate severity vulnerabilities\n\nTo address all issues (including breaking changes), run:\n  npm audit fix --force\n\nRun `npm audit` for details.\n</code></pre></p> <p>\u8fd0\u884c <code>node clewd.js</code> \uff0c\u9996\u6b21\u8fd0\u884c\u65f6\u4f1a\u751f\u6210\u5fc5\u8981\u7684\u914d\u7f6e\u6587\u4ef6 <code>config.js</code>\u3002</p> <p>Tips</p> <p>\u5728 Windows \u4e0a\uff0c\u4f60\u4e5f\u53ef\u4ee5\u901a\u8fc7\u53cc\u51fb <code>clewd</code> \u76ee\u5f55\u4e2d\u7684 <code>start.bat</code> \u6765\u8fd0\u884c\u3002</p> <p><pre><code>clewd $ node clewd.js\n</code></pre> <pre><code>config file created!\nedit config.js to set your settings and restart the program\n</code></pre></p> <p>\u7528\u4f60\u7528\u7684\u987a\u624b\u7684\u7f16\u8f91\u5668\u6253\u5f00\u751f\u6210\u7684 <code>config.js</code> \u6587\u4ef6\u3002</p> <ul> <li>Windows \u63a8\u8350\u4f7f\u7528 <code>Notepad++</code> \u6216 <code>Visual Studio Code</code>\u3002</li> <li>Termux \u6216\u5176\u5b83 Linux \u73af\u5883\u7684\u8bdd\uff0c\u63a8\u8350\u4f7f\u7528 <code>nano</code> , \u6216\u8005\u662f\u4f60\u7528\u7684\u987a\u624b\u7684\u5176\u5b83\u7f16\u8f91\u5668\u3002</li> </ul> <pre><code>/*\n* https://rentry.org/teralomaniac_clewd\n* https://github.com/teralomaniac/clewd\n*/\n\n// SET YOUR COOKIE BELOW\n\nmodule.exports = {\n    // \u5982\u679c\u4f60\u53ea\u6709\u4e00\u4e2a Cookie\uff0c\u90a3\u4e48\u628a SET YOUR COOKIE HERE \u6362\u6210\u4f60\u83b7\u5f97\u7684 Cookie,\n    // \u5f62\u5982 sessionKey=sk \u5f00\u5934\u7684\u4e00\u4e32\u3002\n    \"Cookie\": \"SET YOUR COOKIE HERE\",\n    // \u5982\u679c\u4f60\u6709\u597d\u51e0\u4e2a Cookie, \u90a3\u4e48\u6bcf\u884c\u4e00\u4e2a\u7684\u586b\u8fdb CookieArray \u6570\u7ec4\u91cc\u3002\n    \"CookieArray\": [\n        \"sessionKey=sk-ant-sid01...\",\n        \"sessionKey=sk-ant-sid01...\"\n    ],\n    \"WastedCookie\": [],\n    \"unknownModels\": [],\n    \"Cookiecounter\": 3,\n    \"CookieIndex\": 0,\n    \"ProxyPassword\": \"\",\n    \"Ip\": \"127.0.0.1\",\n    \"Port\": 8444,\n    \"localtunnel\": false,\n    \"BufferSize\": 1,\n    \"SystemInterval\": 3,\n    \"rProxy\": \"\",\n    \"api_rProxy\": \"\",\n    \"placeholder_token\": \"\",\n    \"placeholder_byte\": \"\",\n    \"PromptExperimentFirst\": \"\",\n    \"PromptExperimentNext\": \"\",\n    \"PersonalityFormat\": \"{{char}}'s personality: {{personality}}\",\n    \"ScenarioFormat\": \"Dialogue scenario: {{scenario}}\",\n    \"Settings\": {\n        \"RenewAlways\": true,\n        \"RetryRegenerate\": false,\n        \"PromptExperiments\": true,\n        \"SystemExperiments\": true,\n        \"PreventImperson\": true,\n        \"AllSamples\": false,\n        \"NoSamples\": false,\n        \"StripAssistant\": false,\n        \"StripHuman\": false,\n        \"PassParams\": false,\n        \"ClearFlags\": true,\n        \"PreserveChats\": false,\n        \"LogMessages\": true,\n        \"FullColon\": true,\n        \"padtxt\": \"1000,1000,15000\",\n        \"xmlPlot\": true,\n        \"SkipRestricted\": false,\n        \"Artifacts\": false,\n        // \u5982\u679c\u4f60\u9047\u5230\u4e86 [message]: 'spawn Unknown system error -8' \u9519\u8bef\uff08\u5df2\u77e5 Termux \u4e2d\u4f1a\u53d1\u751f\uff09\uff0c\n        // \u8bf7\u628a\u8fd9\u884c\u7684 true \u6539\u6210 false \u4ee5\u5173\u95ed\u9884\u8bfb\u53d6\u3002\n        \"Superfetch\": true\n    }\n}\n\n/*\n BufferSize\n * How many characters will be buffered before the AI types once\n * lower = less chance of `PreventImperson` working properly\n\n ---\n\n SystemInterval\n * How many messages until `SystemExperiments alternates`\n\n ---\n\n Other settings\n * https://gitgud.io/ahsk/clewd/#defaults\n * and\n * https://gitgud.io/ahsk/clewd/-/blob/master/CHANGELOG.md\n */\n</code></pre> <p>\u7a0d\u540e\u4f60\u5c31\u53ef\u4ee5\u8fd0\u884c\u4e86\uff1a</p> <p><pre><code>Clewd $ bash start.sh\n</code></pre> \u8fd9\u662f\u8f93\u51fa<pre><code>up to date in 418ms\nclewd\u4fee\u6539\u7248 v4.8(11) by tera\nhttp://127.0.0.1:8144/v1\n\nAllSamples: false\nArtifacts: false\nClearFlags: true\nFullColon: true\nLogMessages: true\nNoSamples: false\nPassParams: true\nPreserveChats: true\nPreventImperson: true\nPromptExperiments: true\nRenewAlways: true\nRetryRegenerate: false\nSkipRestricted: false\nStripAssistant: false\nStripHuman: false\nSuperfetch: true\nSystemExperiments: true\npadtxt: 1000,1000,15000\nxmlPlot: true\n\nsuperfetch [found] bin/clewd-superfetch-linux-amd64\n\n(index: 1) Logged in {\n  name: 'xxxxxxxx',\n  mail: 'xxxxxxxx@gmail.com',\n  cookieModel: 'claude-3-5-sonnet-20241022',\n  capabilities: [ 'claude_pro', 'chat', [length]: 2 ]\n}\n</code></pre></p>"},{"location":"chatting/api_connection/clewd/clewd.html#clewd_1","title":"\u9644\uff1a Clewd \u7684\u8bbe\u7f6e\u5217\u8868","text":"<p>Info</p> <p>\u8fd9\u5c31\u662f <code>config.js</code> \u4e2d\u7684 \"Settings\" \u5757\u5185\u7684\u9009\u9879\u3002</p> <p>\u5927\u591a\u6570\u60c5\u51b5\u4e0b\uff0c\u5982\u679c\u4f60\u770b\u4e0d\u61c2\u4e0b\u9762\u8fd9\u4e9b\u662f\u4ec0\u4e48\u610f\u601d\uff0c\u4f60\u5c31\u4e0d\u9700\u8981\u4fee\u6539\u8fd9\u4e9b\u8bbe\u7f6e\u3002</p>"},{"location":"chatting/api_connection/clewd/clewd.html#settingname-defaultopt1opt2","title":"SettingName: (DEFAULT)/opt1/opt2...","text":"<ul> <li> <p><code>Superfetch</code>: (true)/false</p> <ul> <li>true will use an alternate method to get past the <code>We are unable to serve your request</code> error</li> <li>false won't use this method and you may get the error again</li> </ul> </li> <li> <p><code>PreventImperson</code>: (true)/false</p> <ul> <li>true trims the bot reply immediately if he says \"Human:\", \"Assistant:\", \"H:\" or \"A:\"</li> <li>making it so it doesn't hallucinate speaking as you (chance of missing some spicy things)</li> </ul> </li> <li> <p><code>PromptExperiments</code>: (true)/false</p> <ul> <li>true is an alternative way to send your prompt to the AI</li> <li>experiment before setting to false</li> <li>incompatible with <code>RenewAlways</code> set to false</li> </ul> </li> <li> <p><code>RetryRegenerate</code>: (false)/true</p> <ul> <li>true uses the AI's own retry mechanism when you regenerate on your frontend</li> <li>instead of a new conversation</li> <li>experiment with it</li> </ul> </li> <li> <p><code>SystemExperiments</code>: (true)/false</p> <ul> <li>only has any effect when <code>RenewAlways</code> is false</li> <li>true alternates between Main+Jailbreak+User and Jailbreak+User</li> <li>false doesn't alternate</li> </ul> </li> <li> <p><code>RenewAlways</code>: (true)/false</p> <ul> <li>true makes a new conversation context each time</li> <li>false tries to reutilize the same old conversation, sending only the actual last message each time, taking into consideration <code>SystemExperiments</code> (will not work properly unless your Main is the first system prompt and your Jailbreak is the last)</li> </ul> </li> <li> <p><code>StripAssistant</code>: (false)/true</p> <ul> <li>true strips the \"Assistant:\" prefix from the last assistant message (if it's the last message)</li> </ul> </li> <li> <p><code>StripHuman</code>: (false)/true</p> <ul> <li>true strips the \"Human:\" prefix from the last human message (if it's the last message)</li> </ul> </li> <li> <p><code>AllSamples</code>: (false)/true</p> <ul> <li>mutually exclusive with <code>NoSamples</code></li> <li>true converts all real dialogues to \"sample dialogues\" (except the last Assistant and Human messages)</li> <li>you're \"H\" and the AI is \"A\"</li> <li>whatever the AI replies with is kept (only outgoing)</li> <li>see this for more information</li> <li>Human-&gt;H</li> <li>Assistant-&gt;A</li> </ul> </li> <li> <p><code>NoSamples</code>: (false)/true</p> <ul> <li>mutually exclusive with <code>AllSamples</code></li> <li>true converts all \"sample dialogues\" to real dialogues</li> <li>you're \"Human\" and the AI is \"Assistant\"</li> <li>whatever the AI replies with is kept (only outgoing)</li> <li>see this for more information</li> <li>H-&gt;Human</li> <li>A-&gt;Assistant</li> </ul> </li> <li> <p><code>LogMessages</code>: (false)/true</p> <ul> <li>true logs prompt and reply to <code>log.txt</code></li> </ul> </li> <li> <p><code>ClearFlags</code>: (false)/true</p> <ul> <li>possibly snake-oil</li> <li>clears your warnings</li> </ul> </li> <li> <p><code>PassParams</code>: (false)/true</p> <ul> <li>true will send the temperature you set on your frontend</li> <li>only values under &lt;=1.0 &gt;= 0.1</li> <li>this could get your account banned</li> <li>if clewd stops working, set to false</li> </ul> </li> <li> <p><code>PreserveChats</code>: (false)/true</p> <ul> <li>true prevents the deletion of old chats at any point</li> </ul> </li> </ul>"},{"location":"chatting/api_connection/clewd/cookie.html","title":"\u4e3a Clewd \u5bfc\u5165 Cookie","text":""},{"location":"chatting/api_connection/clewd/faq.html","title":"Clewd \u5e38\u89c1\u95ee\u9898","text":"<p>Quote</p> <p>\u597d\u6d88\u606f\uff01\u672c\u9875\u548c\u5404\u5927\u6d4f\u89c8\u5668\u5747\u8fbe\u6210\u4e86\u5408\u4f5c\uff0c\u4f7f\u7528 Ctrl+F (Windows) / Cmd+F (macOS) \u5373\u53ef\u5feb\u901f\u641c\u7d22\u5173\u952e\u8bcd\uff01</p>"},{"location":"chatting/api_connection/clewd/faq.html#_1","title":"\u4e8e\u7ec8\u7aef\u8f93\u51fa\u7684\u9519\u8bef\u6d88\u606f","text":""},{"location":"chatting/api_connection/clewd/faq.html#_2","title":"\u4e8e\u804a\u5929\u754c\u9762\u4e0a\u8f93\u51fa\u7684\u9519\u8bef\u6d88\u606f","text":""},{"location":"chatting/api_connection/clewd/faq.html#400-bad-request","title":"400 Bad Request","text":""},{"location":"chatting/api_connection/clewd/faq.html#temperature-extra-inputs-are-not-permitted","title":"temperature: Extra inputs are not permitted","text":"<ul> <li> <p>\u539f\u56e0\uff1aClaude.ai \u4e0d\u518d\u652f\u6301\u4f20\u9012\u6e29\u5ea6\u53c2\u6570\u3002</p> </li> <li> <p>\u89e3\u51b3\u65b9\u6cd5\uff1a\u5c06<code>config.js</code>\u4e2d\u7684<code>PassParams</code>\u53c2\u6570\u6539\u4e3a false\uff0c\u7136\u540e\u91cd\u542f clewd\u3002</p> </li> </ul> <pre><code>\"PassParams\": false,\n</code></pre>"},{"location":"chatting/api_connection/clewd/faq.html#_3","title":"\u5176\u5b83\u95ee\u9898","text":""},{"location":"chatting/api_connection/clewd/pro.html","title":"\u8ba2\u9605 Claude Pro","text":"<p>\u7b80\u800c\u8a00\u4e4b</p> <p>\u8ba2\u9605 Claude Pro \u9700\u8981\u4e00\u4e2a Claude \u652f\u6301\u5730\u533a\u7684\u94f6\u884c\u5361\uff08\u8be6\u89c1 https://www.anthropic.com/supported-countries \uff0c\u4e0d\u8fc7\u81f3\u5c11\u6ca1\u6709\u4e2d\u56fd\u5927\u9646\u548c\u9999\u6e2f\uff09\u3002</p> <ul> <li>\u6216\u8005\u4f60\u53ef\u4ee5\u901a\u8fc7 App Store \u6216 Play \u5546\u5e97\u8ba2\u9605\uff0c\u6b64\u65f6\u4f60\u7684\u5361\u53ea\u8981\u80fd\u7ed1\u5b9a\u5728 Google \u5e10\u53f7/ Apple ID \u4e0a\uff0c   \u800c\u4e14\u80fd\u591f\u5b8c\u6210\u4ed8\u6b3e\u7684\u8bdd\u4e5f\u53ef\u4ee5\uff0c\u4f46\u662f\u4f9d\u7136\u6709\u5b8c\u5168\u672a\u7ecf\u9a8c\u8bc1\u7684\u8bf4\u6cd5\u8868\u793a\u901a\u8fc7\u5e94\u7528\u5185\u8d2d\u4e70\u88ab\u5c01\u540e\u4e0d\u597d\u9000\u6b3e\u3002</li> </ul>"},{"location":"chatting/sillytavern/index.html","title":"SillyTavern \uff08\u9152\u9986\uff09","text":"<p>SillyTavern\uff08\u7b80\u79f0 ST\uff0c\u4e2d\u6587\u4fd7\u79f0\u9152\u9986\uff09\u662f\u4e00\u4e2a\u672c\u5730\u5b89\u88c5\u7684\u7528\u6237\u754c\u9762\uff0c\u53ef\u8ba9\u4f60\u4e0e\u6587\u672c\u751f\u6210 LLM\u3001\u56fe\u50cf\u751f\u6210\u5f15\u64ce\u548c TTS \u8bed\u97f3\u6a21\u578b\u8fdb\u884c\u4ea4\u4e92\u3002\u6211\u4eec\u7684\u76ee\u6807\u662f\u8ba9\u7528\u6237\u5c3d\u53ef\u80fd\u5730\u53d1\u6325\u5b9e\u7528\u6027\u5e76\u63a7\u5236\u4ed6\u4eec\u7684 LLM \u63d0\u793a\uff0c\u8ba9\u9661\u5ced\u7684\u5b66\u4e60\u66f2\u7ebf\u6210\u4e3a\u4e50\u8da3\u7684\u4e00\u90e8\u5206\u3002</p> <p>SillyTavern \u662f\u4e00\u4e2a\u7531 LLM \u7231\u597d\u8005\u7ec4\u6210\u7684\u70ed\u60c5\u9879\u76ee\uff0c\u5b83\u5c06\u6c38\u8fdc\u514d\u8d39\u548c\u5f00\u6e90\u3002\u4ece 2023 \u5e74 2 \u6708\u5f00\u59cb\uff0cSillyTavern \u4f5c\u4e3a TavernAI 1.2.8 \u7684\u4e00\u4e2a\u5206\u652f\uff0c\u73b0\u5728\u62e5\u6709 100 \u591a\u540d\u8d21\u732e\u8005\u548c 2 \u5e74\u7684\u72ec\u7acb\u5f00\u53d1\u7ecf\u9a8c\uff0c\u5e76\u7ee7\u7eed\u4f5c\u4e3a\u7cbe\u660e\u7684 AI \u7231\u597d\u8005\u7684\u9886\u5148\u8f6f\u4ef6\u3002</p>"},{"location":"chatting/sillytavern/index.html#_1","title":"\u4e3a\u4f55\u8981\u4f7f\u7528\u9152\u9986\uff1f","text":"<p>\u7b80\u800c\u8a00\u4e4b</p> <p>SillyTavern \u76f8\u6bd4 ChatGPT/Claude/Gemini \u7b49 LLM \u670d\u52a1\u7684\u7f51\u9875\u6216 App \u804a\u5929\u754c\u9762\uff0c\u80fd\u591f\u63d0\u4f9b\u66f4\u9ad8\u7684\u7075\u6d3b\u6027\u3002</p> <p>ChatGPT \u7b49\u73b0\u4ee3\u4eba\u5de5\u667a\u80fd\u8bed\u8a00\u6a21\u578b\u5df2\u7ecf\u53d8\u5f97\u975e\u5e38\u5f3a\u5927\uff0c\u5176\u4e2d\u4e00\u4e9b\u6a21\u578b\u73b0\u5728\u53ef\u4ee5\u4ee4\u4eba\u4fe1\u670d\u5730\u6a21\u62df\u4f60\u521b\u5efa\u7684\u89d2\u8272\uff0c\u4ee5\u53ca\u4f60\u53ef\u4ee5\u4e0e\u4e4b\u804a\u5929\u3001\u4e00\u8d77\u5199\u5c0f\u8bf4\u7b49\u7684\u89d2\u8272\u3002 \u4f8b\u5982\uff0c\u4f60\u53ef\u4ee5\u544a\u8bc9\u4eba\u5de5\u667a\u80fd\u5047\u88c5\u662f\u6765\u81ea\u4e2d\u4e16\u7eaa\u65e5\u672c\u7684\u56f4\u68cb\u6559\u7ec3 Jubei\uff0c\u5b83\u4f1a\u91c7\u53d6\u76f8\u5e94\u7684\u884c\u52a8\u548c\u53cd\u5e94\u3002\u4f60\u53ef\u4ee5\u4e0e Jubei \u8fdb\u884c\u957f\u65f6\u95f4\u7684\u804a\u5929\uff0c\u4e00\u8d77\u53bb\u9152\u5427\uff0c\u51b3\u5b9a\u4e0e\u6b66\u58eb\u6253\u67b6\uff0c\u65e0\u8bba\u4f60\u80fd\u60f3\u8c61\u5230\u4ec0\u4e48\uff0c\u4eba\u5de5\u667a\u80fd\u90fd\u4f1a\u53c2\u4e0e\u5176\u4e2d\u5e76\u56f4\u7ed5\u8fd9\u4e9b\u5185\u5bb9\u8fdb\u884c\u5199\u4f5c/\u53cd\u5e94\uff0c\u5145\u5f53\u4f60\u7684\u966a\u886c\u548c\u5730\u4e0b\u57ce\u4e3b\u3002</p> <p>SillyTavern \u662f\u4e00\u6b3e\u53ef\u5b9e\u73b0\u4ee5\u4e0b\u7528\u9014\u7684\u5e94\u7528\u7a0b\u5e8f\uff1a</p> <ul> <li>\u5b83\u662f\u4e00\u4e2a\u5904\u7406\u4e0e AI \u8bed\u8a00\u6a21\u578b\u901a\u4fe1\u7684\u7528\u6237\u754c\u9762\u3002</li> <li>\u5b83\u53ef\u4ee5\u8ba9\u4f60\u521b\u5efa\u65b0\u7684\u89d2\u8272\u5361\uff08\u63d0\u793a\uff09\uff0c\u5e76\u8f7b\u677e\u5730\u5728\u5b83\u4eec\u4e4b\u95f4\u5207\u6362\u3002</li> <li>\u5b83\u5141\u8bb8\u4f60\u5bfc\u5165\u5176\u4ed6\u4eba\u521b\u5efa\u7684\u89d2\u8272\u3002</li> <li>\u5b83\u5c06\u4fdd\u7559\u4f60\u4e0e\u89d2\u8272\u7684\u804a\u5929\u8bb0\u5f55\uff0c\u5141\u8bb8\u4f60\u968f\u65f6\u6062\u590d\u3001\u5f00\u59cb\u65b0\u804a\u5929\u3001\u67e5\u770b\u65e7\u804a\u5929\u7b49\u3002</li> <li>\u5728\u540e\u53f0\uff0c\u5b83\u4f1a\u4e3a\u4f60\u51c6\u5907 AI \u63d0\u793a\u3002\u5177\u4f53\u6765\u8bf4\uff0c\u5b83\u4f1a\u53d1\u9001\u7cfb\u7edf\u63d0\u793a\uff08\u7ed9 AI \u7684\u6307\u4ee4\uff09\uff0c\u8ba9 AI \u9075\u5faa\u67d0\u4e9b\u89c4\u5219\uff0c\u4ee5\u63d0\u9ad8\u54cd\u5e94\u51c6\u786e\u6027\u3002</li> </ul>"},{"location":"chatting/sillytavern/index.html#_2","title":"\u6211\u53ef\u4ee5\u5728\u624b\u673a\u4e0a\u4f7f\u7528\u9152\u9986\u5417\uff1f","text":"<ul> <li> <p>iOS/iPadOS \u8bbe\u5907\u56e0\u4e3a\u7f3a\u5c11\u5fc5\u8981\u7684 Node.js \u73af\u5883\u65e0\u6cd5\u8fd0\u884c\u6574\u4e2a SillyTavern \u5e94\u7528\u7a0b\u5e8f\uff0c\u4f46\u7531\u4e8e\u5b83\u53ea\u662f\u4e00\u4e2a Web \u754c\u9762\uff0c\u4f60\u53ef\u4ee5\u5728\u5bb6\u5ead Wi-Fi \u4e0a\u7684\u53e6\u4e00\u53f0\u8ba1\u7b97\u673a\u4e0a\u8fd0\u884c\u5b83\uff0c\u7136\u540e\u5728\u79fb\u52a8\u6d4f\u89c8\u5668\u4e2d\u8bbf\u95ee\u5b83\u3002</p> </li> <li> <p>\u5bf9\u4e8e Android \u7528\u6237\uff0c\u9664\u4e86\u4e0a\u8ff0\u65b9\u6cd5\u4e4b\u5916\uff0c\u4f60\u8fd8\u53ef\u4ee5\u4f7f\u7528 Termux \u5e94\u7528\u7a0b\u5e8f\u76f4\u63a5\u5728\u624b\u673a\u4e0a\u8fd0\u884c\u6574\u4e2a SillyTavern\uff0c\u800c\u65e0\u9700\u4f7f\u7528 PC\u3002\uff08\u6ce8\u610f\uff1aTermux \u5b89\u88c5\u4e0d\u53d7\u5b98\u65b9\u652f\u6301\uff0c\u6211\u4eec\u4e0d\u80fd\u4fdd\u8bc1\u5b83\u4f1a\u6b63\u5e38\u5de5\u4f5c\u3002\uff09</p> </li> </ul> <p>Important</p> <p>\u8bb0\u5f97\u628a\u4e0b\u9762\u5404\u4e2a\u90e8\u5206\u7684\u5b50\u9875\u9762\u770b\u5b8c\u3002</p>"},{"location":"chatting/sillytavern/index.html#_3","title":"\u5b89\u88c5","text":"<p>Quote</p> <p>\u4f60\u4e5f\u53ef\u4ee5\u53c2\u8003\u5b98\u65b9\u6587\u6863\u7684\u8bf4\u660e\u3002</p> <p>\u8be6\u7ec6\u6b65\u9aa4</p>"},{"location":"chatting/sillytavern/index.html#_4","title":"\u6742\u9c7c\u7528\u4f2a\u4e00\u952e\u90e8\u7f72\u811a\u672c","text":"<p>Termux</p>"},{"location":"chatting/sillytavern/index.html#llm","title":"\u8fde\u63a5\u5230 LLM","text":"<p>SillyTavern \u53ef\u4ee5\u4e0e\u4e24\u79cd\u7c7b\u578b\u7684 AI \u4ea4\u4e92\uff1a</p>"},{"location":"chatting/sillytavern/index.html#web","title":"\u514d\u8d39\u6216\u4ed8\u8d39\u7684 Web \u670d\u52a1","text":"<p>\u4f8b\u5982 OpenAI\u3001Claude \u548c Gemini\u3002</p> <p>\u8be6\u7ec6\u6b65\u9aa4</p>"},{"location":"chatting/sillytavern/index.html#_5","title":"\u81ea\u884c\u6258\u7ba1\u8fd0\u884c\u6a21\u578b","text":"<p>Bug</p> <p>\u56e0\u4e3a\u6587\u6863\u4f5c\u8005\u8d22\u529b\u4e0d\u8db3\uff0c\u6682\u65f6\u6ca1\u6709\u548c\u672c\u5730\u8fd0\u884c\u6a21\u578b\u76f8\u5173\u7684\u5efa\u8bae\u3002</p>"},{"location":"chatting/sillytavern/index.html#_6","title":"\u53d6\u5f97\u89d2\u8272\u5361/\u4e16\u754c\u4e66","text":"<p>\u89d2\u8272\u662f\u60a8\u53ef\u4ee5\u521b\u5efa\u548c\u7ba1\u7406\u7684 AI \u8eab\u4efd\uff0c\u7528\u4e8e\u5851\u9020 AI \u5728\u5bf9\u8bdd\u4e2d\u7684\u89d2\u8272\u3002\u6bcf\u4e2a\u89d2\u8272\u90fd\u6709\u540d\u5b57\u3001\u4e2a\u6027\u548c\u5bf9\u8bdd\u5386\u53f2\u3002\u60a8\u53ef\u4ee5\u521b\u5efa\u4efb\u610f\u6570\u91cf\u7684\u89d2\u8272\uff0c\u5e76\u968f\u65f6\u5728\u5b83\u4eec\u4e4b\u95f4\u5207\u6362\u3002</p> <p>\u89d2\u8272\u53ef\u7528\u4e8e\u5355\u72ec\u804a\u5929\uff0c\u6216\u5c06\u591a\u4e2a\u89d2\u8272\u6dfb\u52a0\u5230\u7fa4\u804a\u4e2d\u4ee5\u8ba9\u4ed6\u4eec\u76f8\u4e92\u4e92\u52a8\u3002</p> <p>\u8be6\u7ec6\u6b65\u9aa4</p>"},{"location":"chatting/sillytavern/index.html#_7","title":"\u53d6\u5f97\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe","text":"<p>\u201c\u7834\u9650\u201d\u6709\u65f6\u4e5f\u662f\u6307\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe</p> <p>\u5927\u591a\u6570\u63d0\u4f9b LLM \u7684\u670d\u52a1\u5546\u4e3a\u4e86\u5b89\u5168\u8d77\u89c1\uff0c\u4f1a\u5728\u8bad\u7ec3\u6a21\u578b\u65f6\u8ba9\u5b83\u4eec\u56de\u907f\u67d0\u4e9b\u8bdd\u9898\uff0c\u6216\u662f\u8fc7\u6ee4\u5305\u542b\u8fd9\u4e9b\u5185\u5bb9\u7684\u8f93\u51fa\u3002 \u4f46\u5f88\u591a\u65f6\u5019\u5b83\u4eec\u5f80\u5f80\u77eb\u6789\u8fc7\u6b63\u4e86\u3002</p> <p>\u6709\u7684\u65f6\u5019\uff0c\u4e00\u4e2a\u8bbe\u8ba1\u826f\u597d\u7684\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\u53ef\u4ee5\u7f13\u89e3\u8fd9\u4e9b\u9632\u5fa1\u63aa\u65bd\u5728\u804a\u5929\u8fc7\u7a0b\u4e2d\u5e26\u6765\u7684\u4e0d\u4fbf\u3002 \u51fa\u4e8e\u5386\u53f2\u539f\u56e0\uff0c\u6709\u4e9b\u4eba\u4f1a\u628a\u5305\u542b\u8fd9\u90e8\u5206\u5185\u5bb9\u7684\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\u53eb\u505a\u201c\u7834\u9650\u201d\u3002</p> <p>\u4f46\u672c\u6587\u6863\u4e2d\u4f9d\u7136\u8ddf\u968f\u9152\u9986\u5b98\u65b9\u7684\u79f0\u547c\uff0c\u79f0\u5b83\u4eec\u4e3a\u201c\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\u201d\u3002</p> <p>\u8be6\u7ec6\u6b65\u9aa4</p>"},{"location":"chatting/sillytavern/index.html#_8","title":"\u53d6\u5f97\u5176\u5b83\u8d44\u6e90","text":"<p>\u4f8b\u5982\u9644\u52a0\u4e16\u754c\u4e66\uff0c\u6b63\u5219\u8868\u8fbe\u5f0f\u548c\u5feb\u901f\u56de\u590d\u811a\u672c\u7b49\u7b49\u3002</p> <p>\u8be6\u7ec6\u6b65\u9aa4 \u5f00\u59cb\u804a\u5929</p>"},{"location":"chatting/sillytavern/index.html#_9","title":"\u5176\u5b83\u8d44\u6e90","text":"<ul> <li>GitHub \u4ed3\u5e93</li> <li>\u5b98\u65b9\u6587\u6863<ul> <li>\u5e38\u89c1\u95ee\u9898</li> </ul> </li> </ul>"},{"location":"chatting/sillytavern/api_connect.html","title":"\u8fde\u63a5\u5230 LLM","text":"<p>SillyTavern \u53ef\u4ee5\u4e0e\u4e24\u79cd\u7c7b\u578b\u7684 AI \u4ea4\u4e92\uff1a</p>"},{"location":"chatting/sillytavern/api_connect.html#web","title":"\u514d\u8d39\u6216\u4ed8\u8d39\u7684 Web \u670d\u52a1","text":"<p>\u4f8b\u5982 OpenAI\u3001Claude \u548c Gemini\u3002</p> <p>\u4ed8\u8d39\u7f51\u7edc\u6a21\u578b\u662f\u9ed1\u5323\u5b50\u3002\u60a8\u5411\u516c\u53f8\u4ed8\u8d39\u4ee5\u4f7f\u7528\u5176 AI \u670d\u52a1\u3002\u60a8\u5c06\u60a8\u7684\u5e10\u6237\u4fe1\u606f\u8f93\u5165 SillyTavern\uff0c\u5b83\u4f1a\u8fde\u63a5\u5230\u60a8\u7684\u63d0\u4f9b\u5546\u4ee5\u4ee3\u8868\u60a8\u4f7f\u7528 AI\u3002</p> <p>\u4f18\u70b9\uff1a</p> <ul> <li>\u771f\u7684\u5f88\u5bb9\u6613\u4e0a\u624b\u3002</li> <li>\u5047\u5982\u80fd\u591f\u6210\u529f\u8f93\u51fa\uff0c\u5185\u5bb9\u7684\u8d28\u91cf\u901a\u5e38\u90fd\u5f88\u597d\u3002</li> </ul> <p>\u7f3a\u70b9\uff1a</p> <ul> <li>\u5927\u591a\u6570\u670d\u52a1\u662f\u4ed8\u8d39\u7684\u3002</li> <li>\u6240\u6709\u5185\u5bb9\u90fd\u8bb0\u5f55\u5728\u4ed6\u4eec\u7684\u670d\u52a1\u5668\u4e0a\u3002\u8fd9\u4e5f\u8bb8\u4f1a\u662f\u4e2a\u9690\u79c1\u95ee\u9898\u3002</li> <li>\u4ed6\u4eec\u7ecf\u5e38\u53d7\u5230\u5ba1\u67e5\u5e76\u4f1a\u62d2\u7edd\u4e0e\u60a8\u804a\u67d0\u4e9b\u8bdd\u9898\u3002</li> </ul> <p>Warning</p> <p>\u5728\u4f7f\u7528\u4ed8\u8d39\u7f51\u7edc\u6a21\u578b\u65f6\uff0c\u4ee5\u4e0b\u7684\u884c\u4e3a\u6709\u673a\u7387\u8ba9\u4f60\u88ab\u670d\u52a1\u63d0\u4f9b\u5546\u5c01\u7981\uff1a</p> <ul> <li>\u901a\u8fc7\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\uff0c\u4e16\u754c\u4e66\u7b49\u65b9\u5f0f\u7ed5\u8fc7 LLM \u6a21\u578b\u6216\u670d\u52a1\u7684\u5b89\u5168\u673a\u5236\u7684\u884c\u4e3a\uff08\u6709\u65f6\u4f1a\u88ab\u79f0\u4f5c\u201c\u8d8a\u72f1\u201d\uff09\u3002</li> <li>\u751f\u6210\u4e0d\u7b26\u5408\u4ed6\u4eec\u7684\u53ef\u63a5\u53d7\u4f7f\u7528\u653f\u7b56\u7684\u5185\u5bb9\uff0c\u4f8b\u5982\u8272\u60c5\u548c\u8840\u8165\u66b4\u529b\u5185\u5bb9\u3002</li> </ul> <p>Important</p> <p>\u5728\u7ee7\u7eed\u4e4b\u524d\uff0c\u8bf7\u786e\u4fdd\u4f60\u5df2\u7ecf\u53d6\u5f97\u4e86\u5bf9\u5e94\u5e73\u53f0\u7684 API \u5bc6\u94a5\uff0c\u6216\u8bbe\u7f6e\u597d\u4e86\u76f8\u5e94\u7684\u5de5\u5177\u3002</p> <p>\u9664\u6b64\u4e4b\u5916\uff0c\u9664\u975e\u53e6\u5916\u8bf4\u660e\uff0c\u8fd9\u90e8\u5206\u4e2d SillyTavern API \u8fde\u63a5\u7684\u83dc\u5355\u4e2d\u9009\u62e9\u7684 API \u7c7b\u578b\u90fd\u662f \u201dChat Completion\u201c \uff08\u804a\u5929\u8865\u5168\uff09</p> <p></p> <p>\u6b64\u6587\u6863\u4e0d\u4f1a\u6d89\u53ca\u975e\u5b98\u65b9\u9014\u5f84\u7684\u8fde\u63a5</p> <p>\u518d\u6b21\u91cd\u590d\uff0c\u6b64\u6587\u6863\u4e0d\u4f1a\u6d89\u53ca\u5b98\u65b9\u9014\u5f84\u6216\u9700\u8981\u5b98\u65b9\u9014\u5f84\u53d6\u5f97\u7684\u767b\u5f55\u51ed\u636e\uff08Cookie\u6216API\u5bc6\u94a5\u7b49\uff09\u4ee5\u5916\u7684\u8fde\u63a5\u65b9\u5f0f\u3002</p> <p>\u5982\u679c\u4f60\u4e0d\u662f\u901a\u8fc7\u5b98\u65b9\u9014\u5f84\u4f7f\u7528\u7684 API \u4e14\u9047\u5230\u4e86\u95ee\u9898\uff0c\u8bf7\u8be2\u95ee\u5356\u7ed9\u4f60\u670d\u52a1\u7684\u4eba\uff0c\u800c\u4e0d\u662f ST \u5f00\u53d1\u8005\u6216\u6b64\u6587\u6863\u7ef4\u62a4\u8005\u3002</p> <p>\u5728 SillyTavern \u5b98\u65b9 Discord \u670d\u52a1\u5668\u63d0\u53ca\u975e\u5b98\u65b9\u9014\u5f84\u4ee5\u5916\u7684\u53cd\u5411\u4ee3\u7406\u548c\u4e2d\u8f6c\u4f1a\u5bfc\u81f4\u4f60\u88ab\u5c01\u7981\u3002</p>"},{"location":"chatting/sillytavern/api_connect.html#chatgpt-openai-platform","title":"ChatGPT \uff08OpenAI Platform\uff09","text":"<p>\u4ec5\u9002\u7528\u4e8e OpenAI Platform</p> <p>Azure OpenAI Service \u7684\u5bc6\u94a5\u5e76\u4e0d\u80fd\u5728\u8fd9\u91cc\u4f7f\u7528\u3002\u4f60\u4e5f\u8bb8\u9700\u8981\u4f7f\u7528 oai-reverse-proxy \u6216\u662f one-api \u4e4b\u7c7b\u7684\u4e2d\u95f4\u5c42\u5de5\u5177\u8f6c\u6362\u4e3a\u517c\u5bb9 OpenAI API \u7684\u683c\u5f0f\u3002</p> <p></p> <ul> <li>\u804a\u5929\u8865\u5168\u6765\u6e90\u9009\u62e9 \u201dOpenAI\u201c\u3002</li> <li>\u5c06\u4f60\u83b7\u5f97\u7684 API \u5bc6\u94a5\u586b\u5165\u201dOpenAI API \u5bc6\u94a5\u201c\u5185\u3002</li> </ul>"},{"location":"chatting/sillytavern/api_connect.html#claude-anthropic-console","title":"Claude \uff08Anthropic Console\uff09","text":"<p>\u4ec5\u9002\u7528\u4e8e Anthropic Console</p> <p>Google Vertex AI \u548c Amazon Bedrock \u7684\u5bc6\u94a5\u5e76\u4e0d\u80fd\u5728\u8fd9\u91cc\u4f7f\u7528\u3002\u4f60\u4e5f\u8bb8\u9700\u8981\u4f7f\u7528 oai-reverse-proxy \u6216\u662f one-api \u4e4b\u7c7b\u7684\u4e2d\u95f4\u5c42\u5de5\u5177\u8f6c\u6362\u4e3a\u517c\u5bb9 OpenAI API \u7684\u683c\u5f0f\u3002</p> <p>\u9664\u6b64\u4ee5\u5916 Clewd \u4e0d\u662f\u5728\u8fd9\u91cc\u7528\u3002Slack\u548cPoe\u7684Cookie\u5728\u8fd9\u91cc\u4e5f\u4e0d\u8d77\u4f5c\u7528\u3002</p> <p></p> <ul> <li>\u804a\u5929\u8865\u5168\u6765\u6e90\u9009\u62e9 \u201dClaude\u201c\u3002</li> <li>\u5c06\u4f60\u83b7\u5f97\u7684 API \u5bc6\u94a5\u586b\u5165 \"Claude API \u5bc6\u94a5\u201c\u5185\u3002</li> </ul>"},{"location":"chatting/sillytavern/api_connect.html#claude-clewd","title":"Claude \uff08clewd\uff09","text":"<p>\u4f60\u73b0\u5728\u5e76\u4e0d\u9700\u8981\u901a\u8fc7 Clewd \u8fde\u63a5 Claude API</p> <p>Clewd \u867d\u7136\u652f\u6301 API \u6a21\u5f0f\uff0c\u4f46\u4f60\u901a\u5e38\u4e0d\u9700\u8981\u8fd9\u6837\u7528\u3002</p> <p></p> <ul> <li>\u804a\u5929\u8865\u5168\u6765\u6e90\u9009\u62e9 \u201d\u81ea\u5b9a\u4e49\uff08\u517c\u5bb9 OpenAI\uff09\u201c\u3002</li> <li>\u81ea\u5b9a\u4e49\u7aef\u70b9\uff08\u57fa\u672c URL\uff09\u586b\u5165\u4f60 clewd \u7684\u5730\u5740\uff0c\u4f8b\u5982 <code>http://127.0.0.1:8444/v1</code> \u3002</li> <li>\u5982\u679c\u4f60\u56e0\u4e3a\u5404\u79cd\u539f\u56e0\u8981\u4f7f\u7528 Clewd \u7684 API \u6a21\u5f0f\uff0c \u5c06\u4f60\u83b7\u5f97\u7684 Claude API \u5bc6\u94a5\u586b\u5165 \"\u81ea\u5b9a\u4e49 API \u5bc6\u94a5\u201c\u5185\u3002</li> </ul>"},{"location":"chatting/sillytavern/api_connect.html#google-gemini","title":"Google Gemini","text":"<p>\u4ec5\u9002\u7528\u4e8e Google AI Studio</p> <p>Google Vertex AI \u7684\u670d\u52a1\u8d26\u6237\u548c API \u5bc6\u94a5\u5e76\u4e0d\u80fd\u5728\u8fd9\u91cc\u4f7f\u7528\u3002\u4f46\u4f60\u53ea\u4e3a\u4e86\u7528 Gemini \u6a21\u578b\u7684\u8bdd\uff0c\u4f3c\u4e4e\u4e5f\u4e0d\u9700\u8981\u7528 Vertex AI\u3002</p> <p></p> <ul> <li>\u804a\u5929\u8865\u5168\u6765\u6e90\u9009\u62e9 \u201dGoogle AI Studio\u201c \u6216 \u201dGoogle Makersuite\u201c \uff08\u5982\u679c\u4f60\u6ca1\u66f4\u65b0\u9152\u9986\uff09\u3002</li> <li>\u5c06\u4f60\u83b7\u5f97\u7684 API \u5bc6\u94a5\u586b\u5165\u201dGoogle AI Studio API \u5bc6\u94a5\u201c\u5185\u3002</li> </ul>"},{"location":"chatting/sillytavern/api_connect.html#_1","title":"\u81ea\u884c\u6258\u7ba1\u8fd0\u884c\u6a21\u578b","text":"<p>\u81ea\u6258\u7ba1\u6a21\u578b\u662f\u53ef\u4ee5\u5728\u60a8\u7684 PC \u4e0a\u8fd0\u884c\u7684\u514d\u8d39\u6a21\u578b\uff0c\u4f46\u9700\u8981\u529f\u80fd\u5f3a\u5927\u7684 PC \u548c\u66f4\u591a\u7684\u5de5\u4f5c\u6765\u8bbe\u7f6e\u3002</p> <p>\u4f18\u70b9\uff1a</p> <ul> <li>\u4e00\u65e6\u8bbe\u7f6e\u5b8c\u6bd5\uff0c\u5373\u4f7f\u6ca1\u6709\u4e92\u8054\u7f51\u63a5\u5165\u4e5f\u53ef\u4ee5\u514d\u8d39\u4f7f\u7528\u3002</li> <li>\u5b8c\u5168\u9690\u79c1\u3002\u60a8\u5199\u7684\u6240\u6709\u5185\u5bb9\u90fd\u4fdd\u7559\u5728\u60a8\u81ea\u5df1\u7684\u7535\u8111\u4e0a\u3002</li> <li>\u6a21\u578b\u79cd\u7c7b\u7e41\u591a\u3002\u4f5c\u4e3a\u4e00\u9879\u793e\u533a\u9a71\u52a8\u7684\u6280\u672f\uff0c\u60a8\u53ef\u4ee5\u627e\u5230\u9002\u5408\u60a8\u6240\u9700\u7279\u5b9a\u4efb\u52a1\u6216\u884c\u4e3a\u7684\u6a21\u578b\u3002</li> </ul> <p>\u7f3a\u70b9\uff1a</p> <ul> <li>\u5b83\u4eec\u4e0d\u5982\u5546\u4e1a\u670d\u52a1\u63d0\u4f9b\u7684\u6a21\u578b\u90a3\u4e48\u5f3a\u5927\uff08\u5373\uff0c\u5b83\u4eec\u7f16\u5199\u7684\u5bf9\u8bdd\u66f4\u5dee\uff0c\u521b\u9020\u529b\u66f4\u5dee\uff0c\u7b49\u7b49\uff09\u3002</li> <li>\u8fd0\u884c\u672c\u5730\u6a21\u578b\u9700\u8981\u81f3\u5c11\u5177\u6709 6GB VRAM \u7684 GPU\u3002</li> </ul> <p>Info</p> <p>\u56e0\u4e3a\u6587\u6863\u4f5c\u8005\u8d22\u529b\u4e0d\u8db3\uff0c\u6682\u65f6\u6ca1\u6709\u548c\u672c\u5730\u8fd0\u884c\u6a21\u578b\u76f8\u5173\u7684\u5efa\u8bae\u3002</p>"},{"location":"chatting/sillytavern/chat.html","title":"\u51c6\u5907\u548c\u5f00\u59cb\u804a\u5929","text":""},{"location":"chatting/sillytavern/chat.html#_2","title":"\u8c03\u6574\u4e0a\u4e0b\u6587/\u683c\u5f0f\u5316\u8bbe\u7f6e","text":"<p>\u9ad8\u7ea7\u683c\u5f0f\u5316\u8bbe\u7f6e\u662f\u7b2c\u4e09\u4e2a\u6309\u94ae\u3002\uff08\u90a3\u4e2a\u50cf\u4e2a\u5b57\u6bcd A \u90a3\u4e2a\uff09</p> <p></p> <p>\u5176\u5b9e\u9ad8\u7ea7\u4e0a\u4e0b\u6587\u8bbe\u7f6e\u4e2d\u7684\u7edd\u5927\u591a\u6570\u529f\u80fd\u90fd\u7528\u4e0d\u4e0a</p> <p>\u4e0d\u7136\u5b83\u4e3a\u5565\u53eb\u201d\u9ad8\u7ea7\u4e0a\u4e0b\u6587\u8bbe\u7f6e\u201c \uff08\u7b11\uff09</p> <p>\u4e0d\u5f00\u73a9\u7b11\u7684\u8bf4\u6cd5\u662f\uff0c\u4e0a\u4e0b\u6587\u6a21\u677f\uff0c\u63d0\u793a\u6a21\u677f\uff08Instruct Template\uff09\u548c\u7cfb\u7edf\u63d0\u793a\u8bcd\u5bf9\u804a\u5929\u8865\u5168 API  \uff08\u4f60\u7528\u7684 Claude\u3001GPT \u6216 Gemini \u8fd9\u4e9b\u90fd\u662f\u804a\u5929\u8865\u5168 API\uff09\u4e0d\u8d77\u4f5c\u7528\u3002</p>"},{"location":"chatting/sillytavern/chat.html#_3","title":"\u4e0a\u4e0b\u6587\u683c\u5f0f","text":"<p>Info</p> <p>\u56e0\u4e3a\u6587\u6863\u4f5c\u8005\u81ea\u5df1\u4e5f\u6ca1\u4ed4\u7ec6\u7814\u7a76\u8fc7\u8fd9\u4e9b\u9009\u9879\u7684\u4f5c\u7528\uff0c\u9700\u8981\u66f4\u591a\u77e5\u9053\u8fd9\u4e9b\u9009\u9879\u662f\u4ec0\u4e48\u7684\u4eba\u6765\u89e3\u91ca\u4e00\u4e0b\u3002</p> <p>\u63a8\u8350\u7684\u9009\u9879\u662f\u5f00\u542f\u201d\u6298\u53e0\u7a7a\u683c\u201c\uff0c\u5173\u95ed\u201d\u4fee\u526a\u4e0d\u5b8c\u6574\u7684\u53e5\u5b50\u201c\u3002\u5176\u5b83\u7684\u4fdd\u6301\u9ed8\u8ba4\u5373\u53ef\u3002</p>"},{"location":"chatting/sillytavern/chat.html#_4","title":"\u81ea\u5b9a\u4e49\u505c\u6b62\u5b57\u7b26\u4e32","text":"<p>\u4ee5 JSON \u6570\u7ec4\u683c\u5f0f\u7684\u4e00\u7ec4\u5b57\u7b26\u4e32\uff0c\u5f53\u8f93\u51fa\u5305\u542b\u8fd9\u4e9b\u5b57\u7b26\u4e32\u4e2d\u4e4b\u4e00\u65f6\u4fbf\u4f1a\u505c\u6b62\u8f93\u51fa\u3002</p> <p>\u4f46\u4f60\u9996\u5148\u5e94\u8be5\u8003\u8651\u7684\u662f\u5982\u4f55\u4e0d\u8ba9 AI \u8f93\u51fa\u88ab\u622a\u65ad\u662f\u5427\uff1f</p>"},{"location":"chatting/sillytavern/chat.html#_5","title":"\u8bcd\u7b26\u5316\u5668","text":"<p>\u7528\u4e8e\u5728\u5404\u79cd\u5730\u65b9\u8ba1\u7b97\u6d88\u606f\u7684\u8bcd\u7b26\u6570\u3002</p> <p>\u9ed8\u8ba4\u7684 Best-match \u5c31\u5f88\u5408\u9002\uff0c\u6216\u8005\u4f60\u786e\u5b9a\u4f60\u5728\u7528\u4ec0\u4e48\u6a21\u578b\u7684\u65f6\u5019\uff0c\u4e5f\u53ef\u4ee5\u8bbe\u7f6e\u6210\u76f8\u5e94\u6a21\u578b\u7684\u9009\u9879\u3002</p>"},{"location":"chatting/sillytavern/chat.html#_6","title":"\u8c03\u6574\u7528\u6237\u8bbe\u7f6e","text":"<p>\u4f3c\u66fe\u76f8\u8bc6\uff0c\u5bf9\u5427\uff1f</p> <p>\u4f60\u5e94\u8be5\u5df2\u7ecf\u5728\u4e4b\u524d\u5207\u6362\u9ad8\u7ea7\u7528\u6237\u754c\u9762\u548c\u542f\u7528\u5916\u90e8\u5a92\u4f53\u7684\u65f6\u5019\u5c31\u7528\u8fc7\u8fd9\u4e2a\u83dc\u5355\u4e86\u3002</p> <p></p> <p>\u548c\u4e0a\u4e0b\u6587\u8bbe\u7f6e\u4e00\u6837\uff0c\u5047\u5982\u4f60\u4e0d\u77e5\u9053\u90a3\u4e2a\u9009\u9879\u7684\u4f5c\u7528\uff0c\u5927\u591a\u6570\u7684\u60c5\u51b5\u4e0b\u4fdd\u6301\u9ed8\u8ba4\u5c31\u597d\u3002 \u9664\u975e\u4f60\u4e0b\u8f7d\u7684\u89d2\u8272\u5361\u7684\u4f5c\u8005\u8981\u6c42\u4f60\u6253\u5f00\u6216\u5173\u95ed\u67d0\u4e2a\u9009\u9879\u3002\uff08\u4f8b\u5982\u524d\u51e0\u9875\u4e2d\u6f14\u793a\u7684\u89d2\u8272\u5361\u5982\u679c\u5f00\u542f\u4e86\u201c\u81ea\u52a8\u4fee\u590d Markdown \u9009\u9879\u5c31\u4f1a\u51fa\u95ee\u9898\uff0c\u6240\u4ee5\u8981\u5173\u6389\u3002\uff09</p>"},{"location":"chatting/sillytavern/chat.html#_7","title":"\u5efa\u7acb\u548c\u4f7f\u7528\u7528\u6237\u89d2\u8272","text":"<p>Tips</p> <p>\u5efa\u7acb\u7528\u6237\u89d2\u8272\uff08Persona\uff09\u8fd9\u4e00\u6b65\u5176\u5b9e\u662f\u53ef\u9009\u7684\uff0c\u90e8\u5206\u89d2\u8272\u5361\u4e2d\u4e5f\u53ef\u80fd\u5728\u4e16\u754c\u4e66\u4e2d\u5df2\u7ecf\u5185\u7f6e\u4e86\u4e00\u6bb5\u7528\u6237\u89d2\u8272\u8bbe\u5b9a\u3002</p> <p>\u4f46\u5047\u5982\u4f60\u60f3\u8df3\u8131\u4f5c\u8005\u7684\u8bbe\u5b9a\u94c3\u8d77\u7089\u7076\u7684\u65f6\u5019\uff0c\u7528\u6237\u89d2\u8272\u53ef\u4ee5\u5e2e\u52a9\u4f60\uff08\u548cAI\uff09\u7a33\u5b9a\u8bbe\u5b9a\uff0c\u800c\u65e0\u9700\u5728\u6bcf\u4e00\u6b21\u5bf9\u8bdd\u4e2d\u5f3a\u8c03\u4f60\u7684\u4eba\u8bbe\u3002</p> <p></p> <p>\u90a3\u4e2a\u770b\u8d77\u6765\u50cf\u4e2a\u7b11\u8138\u7684\u5c31\u662f\u7528\u6237\u89d2\u8272\u7ba1\u7406\u83dc\u5355\u3002</p> <p></p> <p>\u8981\u65b0\u5efa\u4e00\u4e2a\u7528\u6237\u89d2\u8272\uff0c\u70b9\u51fb\u90a3\u4e2a\u201d\u65b0\u5efa\u201c\u6309\u94ae\uff0c\u7136\u540e\u4e3a\u4f60\u7684\u7528\u6237\u89d2\u8272\u8d77\u4e00\u4e2a\u540d\u5b57\u3002</p> <p></p> <p>\u70b9\u51fb\u4e00\u4e2a\u7528\u6237\u89d2\u8272\u53ef\u4ee5\u5728\u7528\u6237\u89d2\u8272\u95f4\u5207\u6362\uff08\u4f46\u4e4b\u524d\u5df2\u7ecf\u53d1\u9001\u7684\u6d88\u606f\u5bf9\u5e94\u7684\u7528\u6237\u89d2\u8272\u4e0d\u4f1a\u6539\u53d8\uff09\uff0c\u9664\u6b64\u4ee5\u5916\uff0c\u90a3\u4e00\u6392\u4e94\u4e2a\u6309\u94ae\u7684\u4f5c\u7528\u5206\u522b\u662f\uff1a</p> <ul> <li>\u5c06\u7528\u6237\u540d\u79f0\u7ed1\u5b9a\u5230\u5934\u50cf\uff1a\u5176\u5b9e\u5c31\u662f\u91cd\u547d\u540d\u3002</li> <li>\u66f4\u6539\u7528\u6237\u89d2\u8272\u5934\u50cf\uff1a\u6362\u5f20\u5927\u5934\u7167\u3002</li> <li>\u8bbe\u7f6e\u4e3a\u9ed8\u8ba4\u89d2\u8272\uff1a\u65b0\u7684\u804a\u5929\u4f1a\u7528\u4f60\u8bbe\u7f6e\u7684\u9ed8\u8ba4\u89d2\u8272\u4f5c\u4e3a\u7528\u6237\u89d2\u8272\u3002</li> <li>\u590d\u5236\u548c\u5220\u9664\u5c31\u4e0d\u7528\u4ecb\u7ecd\u4e86\u5427\uff1f</li> </ul> <p>\u7136\u540e\uff0c\u5728\u65c1\u8fb9\u7684\u201d\u7528\u6237\u89d2\u8272\u63cf\u8ff0\u201c\u6846\u5185\u8f93\u5165\u4f60\u5bf9\u4f60\u7684\u4eba\u8bbe\u7684\u63cf\u8ff0\u3002</p> <p>Tips</p> <p>\u548c\u89d2\u8272\u5361\u4e00\u6837\uff0c\u6ca1\u6709\u4e00\u4e2a\u653e\u4e4b\u56db\u6d77\u800c\u7686\u51c6\u7684\u6807\u51c6\u89c4\u5b9a\u7528\u6237\u89d2\u8272\u63cf\u8ff0\u8be5\u600e\u4e48\u5199\u3002</p> <p>\u4f60\u53ef\u4ee5\u771f\u7684\u50cf\u5360\u4f4d\u7b26\u7684\u4f8b\u5b50\u4e2d\u4e00\u6837\u7528\u7b80\u5355\u7684\u6587\u5b57\u63cf\u8ff0 \uff08\u4f60\u771f\u7684\u662f28\u5c81\u7684\u7f57\u9a6c\u5c3c\u4e9a\u732b\u5a18\uff1f\uff09 \uff0c \u4e5f\u53ef\u4ee5\u50cf\u89d2\u8272\u5361\u7684\u6837\u5f0f\u4e00\u6837\u63cf\u8ff0\u81ea\u5df1\uff08\u7136\u540e\u5c31\u6210\u4e86\u4e00\u5f20\u65b0\u5361\u662f\u5427\uff0c\u5144\u5f1f\u522b\u8349\u6211\uff09\u3002</p> <p>\u662f\u65f6\u5019\u53d1\u6325\u4f60\u65e0\u9650\u7684\u60f3\u8c61\u529b\u4e86\uff01</p> <p>\u800c\u53f3\u9762\u9664\u4e86\u4fdd\u5b58\u65b0\u7684\u7528\u6237\u540d\u7684\u5bf9\u52fe\u6309\u94ae\u4ee5\u5916\uff0c\u8fd8\u6709\u4e24\u4e2a\u6309\u94ae\u5206\u522b\u662f\uff1a</p> <ul> <li>\u9501\u5b9a\u89d2\u8272\uff1a\u53ef\u4ee5\u5c06\u4e00\u4e2a\u9009\u5b9a\u7684\u89d2\u8272\u9501\u5b9a\u5230\u5f53\u524d\u6253\u5f00\u7684\u804a\u5929\u4e2d\u3002\u5982\u679c\u5f53\u524d\u9009\u5b9a\u7684\u89d2\u8272\u4e0e\u9501\u5b9a\u7684\u89d2\u8272\u4e0d\u540c\uff0c\u5219\u6253\u5f00\u8be5\u804a\u5929\u65f6\u5c06\u81ea\u52a8\u9009\u62e9\u8be5\u89d2\u8272\u3002</li> <li>\u540c\u6b65\u89d2\u8272\uff1a\u5c06\u5f53\u524d\u6253\u5f00\u7684\u804a\u5929\u4e2d\u7684\u6240\u6709\u7528\u6237\u53d1\u9001\u7684\u6d88\u606f\u5f52\u56e0\u4e8e\u5f53\u524d\u9009\u5b9a\u7684\u89d2\u8272\u3002</li> </ul> <p>\u548c\u89d2\u8272\u7ba1\u7406\u6709\u5173\u7684\u5176\u5b83\u63d0\u793a</p> <ul> <li>\u5728\u804a\u5929\u4e2d\u5207\u6362\u7528\u6237\u89d2\u8272\u4e0d\u4f1a\u81ea\u52a8\u66f4\u6539\u4e4b\u524d\u53d1\u9001\u7684\u7528\u6237\u6d88\u606f\u7684\u5f52\u5c5e\u3002\u8fd9\u6837\u5c31\u53ef\u4ee5\u540c\u65f6\u4f7f\u7528\u591a\u4e2a\u7528\u6237\u89d2\u8272\u3002</li> <li>\u8981\u66f4\u6539\u89d2\u8272\u56fe\u50cf\u800c\u4e0d\u5220\u9664\u5b83\uff0c\u8bf7\u5c06\u9f20\u6807\u60ac\u505c\u5728\u89d2\u8272\u7ba1\u7406\u9762\u677f\u4e0a\u7684\u5934\u50cf\u4e0a\uff0c\u7136\u540e\u5355\u51fb\u5de6\u4e0b\u89d2\u7684\u6309\u94ae\u3002\u7136\u540e\u9009\u62e9\u4e00\u5f20\u65b0\u56fe\u50cf\uff0c\u5b83\u5c06\u88ab\u66ff\u6362\uff0c\u540c\u65f6\u4fdd\u7559\u60a8\u8bbe\u7f6e\u7684\u63cf\u8ff0\u548c\u804a\u5929\u9501\u5b9a\u72b6\u6001\u3002</li> <li>\u8981\u5728\u804a\u5929\u4e2d\u5feb\u901f\u66f4\u6539\u89d2\u8272\u800c\u4e0d\u6253\u5f00\u89d2\u8272\u7ba1\u7406\u9762\u677f\uff0c\u53ef\u4ee5\u4f7f\u7528 /persona \u659c\u7ebf\u547d\u4ee4\u3002\u4f8b\u5982\uff0c/persona Blaze\u3002</li> <li>\u60a8\u53ef\u4ee5\u5907\u4efd\u60a8\u7684\u7528\u6237\u89d2\u8272\uff0c\u5e76\u5728\u9700\u8981\u65f6\u4f7f\u7528\u4e4b\u524d\u4fdd\u5b58\u7684\u6587\u4ef6\u6062\u590d\u5b83\u4eec\u3002\u5728\u7528\u6237\u89d2\u8272\u7ba1\u7406\u83dc\u5355\u4e2d\u67e5\u627e\u201c\u5907\u4efd\u201d\u548c\u201c\u6062\u590d\u201d\u6309\u94ae\u3002</li> </ul>"},{"location":"chatting/sillytavern/chat.html#_8","title":"\u7b2c\u4e00\u6761\u6d88\u606f","text":"<p>\u7b2c\u4e00\u6761\u6d88\u606f\u63cf\u8ff0\u4e86\u89d2\u8272\u5c06\u5982\u4f55\u4ee5\u53ca\u4ee5\u4f55\u79cd\u98ce\u683c\u8fdb\u884c\u4ea4\u6d41\u3002\u6240\u4ee5\u4e00\u822c\u90fd\u4f1a\u5f88\u957f\u3002</p> <p>\u6709\u4e9b\u89d2\u8272\u5361\u53ef\u80fd\u4f1a\u5305\u542b\u591a\u4e2a\u7b2c\u4e00\u6761\u6d88\u606f\uff0c\u4f8b\u5982\u5212\u5206\u4e0d\u540c\u7684\u5f00\u573a\uff0c\u6216\u662f\u5728\u7b2c\u4e00\u9875\u653e\u7f6e\u4e00\u4e9b\u4fe1\u606f\u3002\u8fd9\u4e2a\u65f6\u5019\u53ef\u4ee5\u901a\u8fc7\u4e0b\u65b9\u7684\u7bad\u5934\u5728\u4e0d\u540c\u7684\u6d88\u606f\u4e2d\u5207\u6362\u3002</p> <p></p>"},{"location":"chatting/sillytavern/chat.html#_9","title":"\u7b2c\u4e00\u6761\u7528\u6237\u6d88\u606f","text":"<p>\u8be5\u4f60\u5199\u4e86\uff08\u7b11\uff09\uff0c\u5199\u5b8c\u6309\u65c1\u8fb9\u7684\u53d1\u9001\u6309\u94ae\uff0c\u6216\u8005\u952e\u76d8\u4e0a\u7684 Enter \u952e\u5c31\u884c\u4e86\u3002</p>"},{"location":"chatting/sillytavern/faq.html","title":"SillyTavern \u5e38\u89c1\u95ee\u9898","text":""},{"location":"chatting/sillytavern/get_char.html","title":"\u53d6\u5f97\u89d2\u8272","text":"<p>\u89d2\u8272\u662f\u60a8\u53ef\u4ee5\u521b\u5efa\u548c\u7ba1\u7406\u7684 AI \u8eab\u4efd\uff0c\u7528\u4e8e\u5851\u9020 AI \u5728\u5bf9\u8bdd\u4e2d\u7684\u89d2\u8272\u3002\u6bcf\u4e2a\u89d2\u8272\u90fd\u6709\u540d\u5b57\u3001\u4e2a\u6027\u548c\u5bf9\u8bdd\u5386\u53f2\u3002\u60a8\u53ef\u4ee5\u521b\u5efa\u4efb\u610f\u6570\u91cf\u7684\u89d2\u8272\uff0c\u5e76\u968f\u65f6\u5728\u5b83\u4eec\u4e4b\u95f4\u5207\u6362\u3002</p> <p>\u89d2\u8272\u53ef\u7528\u4e8e\u5355\u72ec\u804a\u5929\uff0c\u6216\u5c06\u591a\u4e2a\u89d2\u8272\u6dfb\u52a0\u5230\u7fa4\u804a\u4e2d\u4ee5\u8ba9\u4ed6\u4eec\u76f8\u4e92\u4e92\u52a8\u3002</p> <p>\u5173\u6ce8\u59ec\u8001\u5e08\u55b5</p> <p>\u8fd9\u90e8\u5206\u6559\u7a0b\u4e2d\u793a\u4f8b\u7684\u89d2\u8272\u5361\u6765\u81ea https://rentry.org/Himekaidou_Hatate \uff0c \u5173\u6ce8\u59ec\u8001\u5e08\u8c22\u8c22\u55b5\u3002</p> <p>\u6280\u672f\u4e0a\uff0c\u89d2\u8272\u5361\u5c31\u662f\u5305\u542b\u4e00\u5806\u8981\u53d1\u7ed9 AI \u7684\u4fe1\u606f\u7684\u4e00\u7ec4\u6570\u636e\uff0c\u4f46\u662f\u4e3a\u4e86\u597d\u770b\uff0c\u4e00\u822c\u4f1a\u6709\u4e00\u5f20\u56fe\u7247\u505a\u5c01\u9762\u3002 \u4e8e\u662f\u4f60\u53ef\u4ee5\u76f4\u63a5\u4e0b\u8f7d\u4f5c\u8005\u5728\u53d1\u5e03\u9875\u9762\u4e0a\u7684\u56fe\u7247\u6587\u4ef6\u5373\u53ef\u3002</p>"},{"location":"chatting/sillytavern/get_char.html#_2","title":"\u4e0b\u8f7d\u89d2\u8272\u5361\u56fe\u7247","text":"<p>\u8bb0\u5f97\u5c3d\u53ef\u80fd\u7684\u4e0b\u8f7d\u539f\u59cb\u56fe\u7247</p> <p>\u5404\u79cd\u8f6f\u4ef6\u53ef\u80fd\u4f1a\u4e3a\u4e86\u8282\u7701\u7a7a\u95f4\u7b49\u76ee\u7684\u663e\u793a\u538b\u7f29\u540e\u7684\u56fe\u7247\uff0c\u800c\u538b\u7f29\u8fc7\u7a0b\u4e2d\u53ef\u80fd\u4f1a\u7834\u574f\u5143\u6570\u636e\u4e2d\u50a8\u5b58\u7684\u89d2\u8272\u5361\u4fe1\u606f\u3002</p> <p>\u56e0\u6b64\u8bf7\u4e00\u5f8b\u9009\u62e9\u4e0b\u8f7d\u539f\u56fe\u3002</p>"},{"location":"chatting/sillytavern/get_char.html#_3","title":"\u5bfc\u5165\u89d2\u8272","text":"<p>\u70b9\u51fb\u9152\u9986\u83dc\u5355\u4e0a\u7684\u89d2\u8272\u7ba1\u7406\u56fe\u6807\uff08\u6700\u540e\u4e00\u4e2a\uff09\uff0c\u7136\u540e\u9009\u62e9\u201c\u4ece\u6587\u4ef6\u5bfc\u5165\u89d2\u8272\u201d\uff0c\u7136\u540e\u4e0a\u4f20\u4e0b\u8f7d\u5230\u7684\u6587\u4ef6\u3002</p> <p>Tips</p> <p>\u5728\u7535\u8111\u4e0a\uff0c\u4f60\u4e5f\u53ef\u4ee5\u901a\u8fc7\u76f4\u63a5\u628a\u4e0b\u8f7d\u597d\u7684\u89d2\u8272\u5361\u56fe\u62d6\u52a8\u5230 SillyTavern \u7684\u7a97\u53e3\u91cc\u8fbe\u5230\u4e00\u6837\u7684\u6548\u679c\u3002</p> <p></p> <p>\u5bf9\u4e8e\u89d2\u8272\u4fe1\u606f\u4e2d\u542b\u6709\u6807\u7b7e\u7684\u89d2\u8272\uff0c\u53ef\u4ee5\u5728\u8fd9\u4e00\u6b65\u9009\u62e9\u662f\u5426\u6dfb\u52a0\u76f8\u5e94\u7684\u6807\u7b7e\u3002</p> <p></p> <p>\u5bfc\u5165\u5b8c\u6210\u7684\u89d2\u8272\u5c31\u4f1a\u663e\u793a\u5728\u89d2\u8272\u5217\u8868\u91cc\u4e86\uff0c\u70b9\u51fb\u89d2\u8272\u5373\u53ef\u8fdb\u5165\u804a\u5929\u754c\u9762\u3002</p>"},{"location":"chatting/sillytavern/get_char.html#_4","title":"\u5bfc\u5165\u89d2\u8272\u7684\u5173\u8054\u6570\u636e","text":"<p>\u5982\u679c\u89d2\u8272\u5361\u5b9a\u4e49\u4e2d\u6709\u5305\u542b\u4e16\u754c\u4e66\uff0c\u63a5\u4e0b\u6765\u4fbf\u4f1a\u63d0\u793a\u4f60\u5bfc\u5165\u548c\u5173\u8054\u3002</p> <p></p> <p>\u5bfc\u5165\u5b8c\u6210\u4e4b\u540e\u4f1a\u81ea\u52a8\u6253\u5f00\u89d2\u8272\u5173\u8054\u7684\u4e16\u754c\u4e66\uff0c\u70b9\u51fb\u4e16\u754c\u4fe1\u606f\u6309\u94ae\u5373\u53ef\u5173\u95ed\u3002</p> <p>Tips</p> <p>\u5982\u679c\u4f60\u9519\u8fc7\u4e86\u5728\u5bfc\u5165\u89d2\u8272\u5361\u65f6\u5bfc\u5165\u89d2\u8272\u5173\u8054\u7684\u4e16\u754c\u4e66\u8fd9\u4e00\u6b65\uff0c\u7a0d\u540e\u4f60\u53ef\u4ee5\u5728\u89d2\u8272\u7684\u66f4\u591a\u9009\u9879\u91cc\uff0c \u9009\u62e9 \u201c\u5bfc\u5165\u89d2\u8272\u5361\u7684\u4e16\u754c\u4e66\u201d\u3002</p> <p></p> <p></p> <p>\u5927\u591a\u6570\u89d2\u8272\u5361\u4f1a\u4f7f\u7528\u4e00\u79cd\u53eb\u505a\u6b63\u5219\u8868\u8fbe\u5f0f\u7684\u6587\u672c\u66ff\u6362\u673a\u5236\u6765\u8fdb\u884c\u4e00\u4e9b\u64cd\u4f5c\uff0c\u4f8b\u5982\u5220\u9664\u601d\u7ef4\u94fe\uff08CoT\uff09\u7684\u5185\u5bb9\uff0c \u6216\u662f\u63d0\u4f9b\u4e00\u4e9b\u7f8e\u5316\u7684\u754c\u9762\u3002</p> <p>\u5728\u6269\u5c55\u83dc\u5355\u4e2d\uff0c\u8f6c\u5230\u6b63\u5219\u9009\u9879\uff0c\u70b9\u51fb\u5c40\u90e8\u6b63\u5219\u811a\u672c\u7684\u5f00\u5173\u4ee5\u5141\u8bb8\u4f7f\u7528\u5c40\u90e8\u6b63\u5219\u8868\u8fbe\u5f0f\u3002</p> <p>\u65e9\u671f\u7248\u672c\u7684\u884c\u4e3a\u53ef\u80fd\u4e0e\u6b64\u4e0d\u540c</p> <p>\u5728\u65e7\u7248\u672c\u4e2d\uff08&lt;1.12.5\uff09\uff0c\u5bfc\u5165\u5e26\u6709\u5c40\u90e8\u6b63\u5219\u7684\u89d2\u8272\u5361\u65f6\u4f1a\u50cf\u5bfc\u5165\u4e16\u754c\u4e66\u65f6\u63d0\u793a\u662f\u5426\u542f\u7528\u3002</p> <p>\u5982\u4f55\u4f7f\u7528\u89d2\u8272\u5361\u4e2d\u7684\u5916\u90e8\u5a92\u4f53\uff08\u63d2\u56fe\uff0c\u6837\u5f0f\u8868\u7b49\uff09</p> <p></p> <p>\u5bf9\u4e8e\u5f88\u591a\u6709\u5916\u90e8\u63d2\u56fe\u7684\u89d2\u8272\u5361\uff0c\u5f00\u542f\u5c40\u90e8\u6b63\u5219\u540e\u4f1a\u63d0\u793a\u4f60\u5916\u90e8\u5a92\u4f53\u76ee\u524d\u88ab\u7981\u7528\u3002</p> <p></p> <p>\u8fd9\u4e2a\u65f6\u5019\u8981\u524d\u5f80\u7528\u6237\u8bbe\u7f6e\uff0c\u53d6\u6d88\u9009\u62e9\u201c\u7981\u6b62\u5916\u90e8\u5a92\u4f53\u201d\u9009\u9879\u3002</p> <p></p> <p>\u90e8\u5206\u89d2\u8272\u5361\u53ef\u80fd\u8981\u6c42\u624b\u52a8\u5bfc\u5165\u66f4\u591a\u5173\u8054\u6570\u636e</p> <p>\u90e8\u5206\u89d2\u8272\u5361\u53ef\u80fd\u8981\u6c42\u624b\u52a8\u5bfc\u5165\u66f4\u591a\u5173\u8054\u6570\u636e\uff0c\u4f8b\u5982\u5feb\u901f\u56de\u590d\u811a\u672c\u3001\u989d\u5916\u7684\u77e5\u8bc6\u4e66\u7b49\u7b49\u3002</p> <p>\u6216\u53d6\u5176\u5b83\u5468\u8fb9\u4fe1\u606f\u4e00\u8282\u4e2d\u4ecb\u7ecd\u4e86\u5982\u4f55\u5bfc\u5165\u5b83\u4eec\u3002</p>"},{"location":"chatting/sillytavern/get_preset.html","title":"\u53d6\u5f97\u548c\u5bfc\u5165\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe","text":"<p>\u201c\u7834\u9650\u201d\u6709\u65f6\u4e5f\u662f\u6307\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe</p> <p>\u5927\u591a\u6570\u63d0\u4f9b LLM \u7684\u670d\u52a1\u5546\u4e3a\u4e86\u5b89\u5168\u8d77\u89c1\uff0c\u4f1a\u5728\u8bad\u7ec3\u6a21\u578b\u65f6\u8ba9\u5b83\u4eec\u56de\u907f\u67d0\u4e9b\u8bdd\u9898\uff0c\u6216\u662f\u8fc7\u6ee4\u5305\u542b\u8fd9\u4e9b\u5185\u5bb9\u7684\u8f93\u51fa\u3002 \u4f46\u5f88\u591a\u65f6\u5019\u5b83\u4eec\u5f80\u5f80\u77eb\u6789\u8fc7\u6b63\u4e86\u3002</p> <p>\u6709\u7684\u65f6\u5019\uff0c\u4e00\u4e2a\u8bbe\u8ba1\u826f\u597d\u7684\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\u53ef\u4ee5\u7f13\u89e3\u8fd9\u4e9b\u9632\u5fa1\u63aa\u65bd\u5728\u804a\u5929\u8fc7\u7a0b\u4e2d\u5e26\u6765\u7684\u4e0d\u4fbf\u3002 \u51fa\u4e8e\u5386\u53f2\u539f\u56e0\uff0c\u6709\u4e9b\u4eba\u4f1a\u628a\u5305\u542b\u8fd9\u90e8\u5206\u5185\u5bb9\u7684\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\u53eb\u505a\u201c\u7834\u9650\u201d\u3002</p> <p>\u4f46\u672c\u6587\u6863\u4e2d\u4f9d\u7136\u8ddf\u968f\u9152\u9986\u5b98\u65b9\u7684\u79f0\u547c\uff0c\u79f0\u5b83\u4eec\u4e3a\u201c\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\u201d\u3002</p> <p>\u6ca1\u6709\u4e00\u4e2a\u6a21\u578b\u80fd\u9002\u5e94\u6240\u6709\u9884\u8bbe\uff0c\u4e5f\u6ca1\u6709\u4e00\u79cd\u9884\u8bbe\u80fd\u591f\u5305\u6253\u5929\u4e0b</p> <p>\u56e0\u4e3a\u4e0d\u540c\u7684 LLM \u80fd\u591f\u63a5\u53d7\u7684\u8f93\u5165\u7c7b\u578b\uff0c\u7cfb\u7edf\u63d0\u793a\u683c\u5f0f\uff0c\u4ee5\u53ca\u5ba1\u67e5\u7a0b\u5ea6\u90fd\u4e92\u4e0d\u76f8\u540c\uff0c\u56e0\u6b64\u5e76\u4e0d\u5b58\u5728\u67d0\u79cd\u80fd\u591f\u901a\u5403\u6240\u6709\u6a21\u578b\u7684\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\u3002</p> <p>\u90e8\u5206\u89d2\u8272\u5361\u5bf9\u7279\u5b9a\u9884\u8bbe\u7684\u76f8\u6027\u4e5f\u8bb8\u4f1a\u66f4\u4f73\uff0c\u4f60\u4e5f\u8bb8\u4f1a\u5728\u804a\u4e0a\u4e00\u9635\u5b50\u4e4b\u540e\uff0c\u9010\u6e10\u4e60\u60ef\u8d77\u8fd9\u4e2a\u9884\u8bbe\u7684\u6587\u98ce\u548c\u6548\u679c\u3002</p>"},{"location":"chatting/sillytavern/get_preset.html#_2","title":"\u5bfc\u5165\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe","text":"<p>\u4f60\u4e0b\u8f7d\u5230\u7684\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\u5e94\u8be5\u662f\u4e00\u4e2a JSON \u683c\u5f0f\u7684\u6587\u4ef6\u3002</p> <p></p> <p>\u70b9\u51fb\u6700\u5de6\u8fb9\u7684 \u201cAI \u54cd\u5e94\u914d\u7f6e\u201d\u6309\u94ae\u6253\u5f00\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\u83dc\u5355\u3002\u627e\u622a\u56fe\u4e2d\u7528\u9f20\u6807\u60ac\u505c\u7740\u7684\u6309\u94ae\uff0c\u5c31\u662f\u5bfc\u5165\u6309\u94ae\u3002</p> <p>\u627e\u4e0d\u5230\u5bfc\u5165\u6309\u94ae\uff1f</p> <p>\u5982\u679c\u4f60\u56e0\u4e3a\u5404\u79cd\u539f\u56e0\u8fd8\u5728\u4f7f\u7528 1.12.5 \u53ca\u4ee5\u524d\u7248\u672c\uff0c\u8bf7\u56de\u5230\u5b89\u88c5\u4e00\u8282\u7684\u672b\u5c3e\uff0c\u786e\u4fdd\u7528\u6237\u8bbe\u7f6e\u662f\u201d\u9ad8\u7ea7\u201c\u6a21\u5f0f\u3002</p>"},{"location":"chatting/sillytavern/get_preset.html#_3","title":"\u8c03\u6574\u9884\u8bbe\u5171\u901a\u8bbe\u7f6e","text":"<p>\u4e5f\u5c31\u662f\u9009\u62e9\u9884\u8bbe\u4e0b\u9762\u7684\u8fd9\u4e9b\u90e8\u5206\u3002</p> <p></p> <p>\u5982\u679c\u4f60\u4f7f\u7528\u7684\u662f Claude \u6216\u8005 Gemini \u7684\u8bdd\uff0c\u4f60\u7684\u8bbe\u7f6e\u9009\u9879\u4e5f\u8bb8\u4f1a\u77ed\u4e00\u4e9b\u3002</p> <p></p>"},{"location":"chatting/sillytavern/get_preset.html#_4","title":"\u4e0a\u4e0b\u6587\u957f\u5ea6\uff0c\u6700\u5927\u56de\u590d\u957f\u5ea6\u548c\u6d41\u5f0f\u4f20\u8f93\u6a21\u5f0f","text":"<p>\u63a8\u8350\u52fe\u9009\u201c\u89e3\u9501\u4e0a\u4e0b\u6587\u957f\u5ea6\u201d\u9009\u9879\uff0c\u8fd9\u53ea\u662f\u8ba9\u4f60\u5728\u9152\u9986\u7684\u83dc\u5355\u4e2d\u53ef\u8c03\u8282\u7684\u8303\u56f4\u589e\u5927\uff0c\u5e76\u4e0d\u4f1a\u771f\u6b63\u7684\u63d0\u9ad8\u6bcf\u6b21\u53d1\u9001 Tokens \u7684\u6570\u91cf\u3002</p> <p>\u91cd\u8981\u7684\u662f\u4e0b\u9762\u201c\u4e0a\u4e0b\u6587\u957f\u5ea6\u201d\u7684\u6ed1\u5757\u3002\u4e0a\u4e0b\u6587\u957f\u5ea6\u8d8a\u5927\uff0c\u4f60\u6bcf\u4e00\u8f6e\u5bf9\u8bdd\u4e2d\u80fd\u591f\u53d1\u9001\u7684\u4e16\u754c\u4e66\u6761\u76ee\u548c\u5386\u53f2\u8bb0\u5f55\u5c31\u66f4\u591a\uff0c\u5f53\u7136\u82b1\u7684\u94b1\u4e5f\u4f1a\u53d8\u591a\u3002</p> <p>\u81f3\u4e8e\u6700\u5927\u56de\u590d\u957f\u5ea6\uff0c\u5efa\u8bae\u662f\u8bbe\u7f6e\u6210\u4f60\u7684\u6a21\u578b\u80fd\u591f\u63d0\u4f9b\u7684\u8f93\u51fa\u4e0a\u9650\uff08\u4f8b\u5982 Gemini \u6700\u957f 8192 \u4e2a Token\uff0cClaude \u6700\u957f 4096 \u4e2a\u8fd9\u6837\uff09\u3002 \u6216\u8005\uff0c\u4f60\u4e5f\u53ef\u4ee5\u7a0d\u5fae\u964d\u4f4e\u4e00\u4e9b\u6765\u51cf\u5c11\u51fa\u73b0\u91cd\u590d\u7684\u673a\u7387\u3002</p> <p>\u6d41\u5f0f\u4f20\u8f93\u6a21\u5f0f\u4e0b\uff0cAI \u7684\u56de\u590d\u4f1a\u51e0\u4e2a\u8bcd\u51e0\u4e2a\u8bcd\u7684\u663e\u793a\uff0c\u5173\u95ed\u53ef\u4ee5\u51cf\u8f7b Gemini \u4e00\u7c7b\u7684\u6a21\u578b\u5728\u8f93\u51fa\u65f6\u53d1\u751f\u622a\u65ad\u7684\u53ef\u80fd\u6027\u3002</p>"},{"location":"chatting/sillytavern/get_preset.html#_5","title":"\u90a3\u4e9b\u6ed1\u5757\u5bf9\u5e94\u7684\u53c2\u6570","text":"<p>Important</p> <p>\u5047\u5982\u4f60\u770b\u4e0d\u61c2\u662f\u4ec0\u4e48\u610f\u601d\uff0c\u90a3\u4e48\u9884\u8bbe\u7684\u9ed8\u8ba4\u503c\u5e94\u8be5\u5c31\u8db3\u591f\u4e86\u3002</p> <ul> <li> <p>\u6e29\u5ea6\u63a7\u5236 token \u9009\u62e9\u7684\u968f\u673a\u6027\u3002</p> <ul> <li> <p>\u5f53\u60a8\u671f\u671b\u5f97\u5230\u771f\u5b9e\u6216\u6b63\u786e\u7684\u56de\u7b54\u65f6\uff0c\u6e29\u5ea6\u8d8a\u4f4e\u8d8a\u597d\u3002\u6e29\u5ea6\u4e3a 0 \u8868\u793a\u901a\u5e38\u4f1a\u9009\u62e9\u6982\u7387\u6700\u9ad8\u7684 token\u3002 \u8f83\u9ad8\u7684\u6e29\u5ea6\u53ef\u80fd\u4f1a\u5f15\u53d1\u591a\u6837\u5316\u6216\u610f\u60f3\u4e0d\u5230\u7684\u7ed3\u679c\u3002\u6709\u4e9b\u6a21\u578b\u8bbe\u7f6e\u4e86\u66f4\u9ad8\u7684\u6e29\u5ea6\u4e0a\u9650\uff0c\u4ee5\u9f13\u52b1\u66f4\u4e3a\u968f\u673a\u7684\u56de\u7b54\u3002</p> </li> <li> <p>\u5927\u90e8\u5206\u6a21\u578b\u7684\u6e29\u5ea6\u8303\u56f4\u662f 0-2\u3002</p> </li> </ul> </li> <li> <p>Top-K \u548c Top-P \u662f\u4e24\u79cd\u4e0d\u540c\u7684\u63a7\u5236\u6a21\u578b\u5728\u9009\u62e9\u8f93\u51fa token \u7684\u65b9\u5f0f\u3002</p> <ul> <li>Top-K \u6307\u5b9a\u6a21\u578b\u5728\u9009\u62e9\u8f93\u51fa token \u65f6\u5019\u9009 token \u7684\u6570\u91cf\u3002\u4f7f\u7528\u8f83\u4f4e\u7684\u503c\u53ef\u83b7\u5f97\u968f\u673a\u7a0b\u5ea6\u8f83\u4f4e\u7684\u56de\u7b54\uff0c\u6307\u5b9a\u8f83\u9ad8\u7684\u503c\u53ef\u83b7\u5f97\u968f\u673a\u7a0b\u5ea6\u8f83\u9ad8\u7684\u56de\u7b54\u3002</li> <li>Top-P \u53ef\u66f4\u6539\u6a21\u578b\u9009\u62e9\u8f93\u51fa token \u7684\u65b9\u5f0f\u3002\u7cfb\u7edf\u4f1a\u6309\u7167\u6982\u7387\u4ece\u6700\u9ad8\u5230\u6700\u4f4e\u7684\u987a\u5e8f\u9009\u62e9 token\uff0c\u76f4\u5230\u6240\u9009 token \u7684\u6982\u7387\u603b\u548c\u7b49\u4e8e Top-p \u7684\u503c\u3002\u4f8b\u5982\uff0c\u5982\u679c token A\u3001B \u548c C \u7684\u6982\u7387\u5206\u522b\u662f 0.3\u30010.2 \u548c 0.1\uff0c\u5e76\u4e14 Top-p \u7684\u503c\u4e3a 0.5\uff0c\u5219\u6a21\u578b\u5c06\u9009\u62e9 A \u6216 B \u4f5c\u4e3a\u4e0b\u4e00\u4e2a token\uff08\u901a\u8fc7\u6e29\u5ea6\u786e\u5b9a\uff09\u3002\u5982\u9700\u83b7\u5f97\u53d8\u5316\u7a0b\u5ea6\u6700\u4f4e\u7684\u7ed3\u679c\uff0c\u8bf7\u5c06 top-P \u8bbe\u7f6e\u4e3a 0\u3002</li> </ul> </li> <li> <p>\u9891\u7387\u60e9\u7f5a\u548c\u5b58\u5728\u60e9\u7f5a\u662f OpenAI API \u5e38\u7528\u7684\u63a7\u5236\u6a21\u578b\u8f93\u51fa\u91cd\u590d\u7a0b\u5ea6\u7684\u53c2\u6570\u3002</p> <ul> <li>\u9891\u7387\u60e9\u7f5a\u7528\u4e8e\u963b\u6b62\u6a21\u578b\u5728\u751f\u6210\u7684\u6587\u672c\u4e2d\u8fc7\u4e8e\u9891\u7e41\u5730\u91cd\u590d\u76f8\u540c\u7684\u5355\u8bcd\u6216\u77ed\u8bed\u3002\u6bcf\u6b21\u5728\u751f\u6210\u7684\u6587\u672c\u4e2d\u51fa\u73b0\u4e00\u4e2a\u6807\u8bb0\u65f6\uff0c\u5b83\u90fd\u4f1a\u88ab\u52a0\u5230\u8be5\u6807\u8bb0\u7684\u5bf9\u6570\u6982\u7387\u4e0a\u3002\u503c\u8d8a\u9ad8\uff0c\u6a21\u578b\u5728\u4f7f\u7528\u91cd\u590d\u6807\u8bb0\u65f6\u5c31\u8d8a\u4fdd\u5b88\u3002</li> <li>\u5b58\u5728\u60e9\u7f5a\u7528\u4e8e\u9f13\u52b1\u6a21\u578b\u5728\u751f\u6210\u7684\u6587\u672c\u4e2d\u5305\u542b\u5404\u79cd\u6807\u8bb0\u3002\u6bcf\u6b21\u751f\u6210\u4e00\u4e2a\u6807\u8bb0\u65f6\uff0c\u90fd\u4f1a\u4ece\u8be5\u6807\u8bb0\u7684\u5bf9\u6570\u6982\u7387\u4e2d\u51cf\u53bb\u4e00\u4e2a\u503c\u3002\u8f83\u9ad8\u7684\u5b58\u5728\u60e9\u7f5a\u503c\u5c06\u5bfc\u81f4\u6a21\u578b\u66f4\u6709\u53ef\u80fd\u751f\u6210\u5c1a\u672a\u5305\u542b\u5728\u751f\u6210\u6587\u672c\u4e2d\u7684\u6807\u8bb0\u3002</li> </ul> </li> </ul>"},{"location":"chatting/sillytavern/get_preset.html#_6","title":"\u5f00\u542f\u6216\u5173\u95ed\u9884\u8bbe\u6761\u76ee","text":"<p>\u5927\u591a\u6570\u7684\u9884\u8bbe\u90fd\u4f1a\u63d0\u4f9b\u4e0d\u540c\u7684\u53ef\u4ee5\u9009\u62e9\u5f00\u5173\u7684\u5206\u6bb5\u3002\u5bf9\u4e8e\u6bcf\u4e00\u4e2a\u5c0f\u8282\uff1a</p> <ul> <li>\u7b2c\u4e00\u4e2a\u7ea2\u8272\u7684\u5220\u9664\u94fe\u63a5\u56fe\u6807\u662f\u5c06\u8fd9\u6bb5\u4ece\u8981\u53d1\u9001\u7684\u5185\u5bb9\u4e2d\u65ad\u5f00\u94fe\u63a5\u3002   \u9884\u8bbe\u7684\u7b2c\u4e00\u5206\u6bb5\uff0c\u548c\u9152\u9986\u5185\u7f6e\u7684\u5206\u6bb5\uff08\u4e16\u754c\u4fe1\u606f\u3001\u4eba\u7269\u4fe1\u606f\u548c\u804a\u5929\u8bb0\u5f55\u7b49\uff09\u6ca1\u6709\u8fd9\u79cd\u9009\u9879\uff0c\u901a\u5e38\u4f60\u4e5f\u6ca1\u6709\u5fc5\u8981\u7528\u5b83\u3002</li> </ul> <p></p> <ul> <li> <p>\u7b2c\u4e8c\u4e2a\u94c5\u7b14\u6309\u94ae\u53ef\u4ee5\u67e5\u770b\u548c\u7f16\u8f91\u8fd9\u4e00\u5206\u6bb5\u4e2d\u7684\u5185\u5bb9\uff0c\u6709\u4e9b\u9884\u8bbe\u4f5c\u8005\u4f1a\u628a\u5982\u4f55\u4f7f\u7528\u7b49\u4fe1\u606f\u586b\u5728\u7b2c\u4e00\u4e2a\u5206\u6bb5\u5185\uff0c\u5efa\u8bae\u8bfb\u5b8c\u5b83\u3002</p> </li> <li> <p>\u7b2c\u4e09\u4e2a\u6309\u94ae\u5c31\u662f\u5f00\u5173\uff0c\u70b9\u51fb\u53ef\u5728\u542f\u7528\u6216\u7981\u7528\u6b64\u5206\u6bb5\u95f4\u5207\u6362\u3002</p> </li> <li> <p>\u6700\u540e\u7684\u6570\u5b57\u8868\u793a\u8fd9\u4e2a\u5206\u6bb5\u5360\u7528\u7684\u8bcd\u7b26\uff08Token\uff09\u6570\u91cf\u3002</p> </li> </ul> <p>\u8bb0\u5f97\u786e\u8ba4\u603b\u8bcd\u7b26\u6570</p> <p>\u9884\u8bbe\u5206\u6bb5\u6700\u4e0a\u9762\u7684\u201c\u603b\u8bcd\u7b26\u6570\u201d\u8868\u793a\u5f53\u524d\u9884\u8bbe\u6240\u6709\u9879\u76ee\u4f1a\u5360\u7528\u591a\u5c11 Token ,\u8bf7\u786e\u4fdd\u4f60\u4e0a\u9762\u8bbe\u7f6e\u7684\u4e0a\u4e0b\u6587\u4e0a\u9650\u6bd4\u603b\u8bcd\u7b26\u6570\u8981\u5927\u3002</p>"},{"location":"chatting/sillytavern/get_resource.html","title":"\u53d6\u5f97\u5176\u5b83\u5468\u8fb9\u8d44\u6e90","text":""},{"location":"chatting/sillytavern/get_resource.html#_2","title":"\u4e16\u754c\u4e66","text":"<p>\u4e16\u754c\u4e66\u662f\u4ec0\u4e48\uff1f</p> <p>\u4e16\u754c\u4e66\uff08\u4e5f\u79f0\u4e3a Lore Books \u6216\u8bb0\u5fc6\u4e66\uff09\u662f ST \u4e2d\u5f3a\u5927\u7684\u5de5\u5177\uff0c\u53ef\u5728\u804a\u5929\u4e2d\u52a8\u6001\u63d2\u5165\u63d0\u793a\u4ee5\u5e2e\u52a9\u5f15\u5bfc AI \u56de\u590d\u3002</p> <p>\u901a\u5e38\uff0c\u4e16\u754c\u4fe1\u606f\uff08\u7b80\u79f0 WI\uff09\u7528\u4e8e\u589e\u5f3a AI \u5bf9\u865a\u6784\u4e16\u754c\u4e2d\u7684\u7ec6\u8282\u7684\u7406\u89e3\uff0c\u4f46\u662f\u60a8\u53ef\u4ee5\u4f7f\u7528\u4e16\u754c\u4fe1\u606f\u6761\u76ee\u6765\u63d2\u5165\u60a8\u60f3\u8981\u63d2\u5165\u63d0\u793a\u4e2d\u7684\u4efb\u4f55\u5185\u5bb9\u3002</p> <p>\u5b83\u7684\u529f\u80fd\u7c7b\u4f3c\u4e8e\u4e00\u672c\u52a8\u6001\u8bcd\u5178\uff0c\u4ec5\u5f53\u6d88\u606f\u6587\u672c\u4e2d\u5b58\u5728\u4e0e\u6761\u76ee\u76f8\u5173\u7684\u5173\u952e\u5b57\u65f6\uff0c\u624d\u4f1a\u63d2\u5165\u6765\u81ea\u4e16\u754c\u4fe1\u606f\u6761\u76ee\u7684\u76f8\u5173\u4fe1\u606f\u3002</p> <p>SillyTavern \u5f15\u64ce\u6fc0\u6d3b\u5e76\u5c06\u9002\u5f53\u7684\u4f20\u8bf4\u65e0\u7f1d\u96c6\u6210\u5230\u63d0\u793a\u4e2d\uff0c\u4e3a AI \u63d0\u4f9b\u80cc\u666f\u4fe1\u606f\u3002</p> <p>\u503c\u5f97\u6ce8\u610f\u7684\u662f\uff0c\u867d\u7136 World Info \u6709\u52a9\u4e8e\u5f15\u5bfc AI \u627e\u5230\u6240\u9700\u5185\u5bb9\uff0c\u4f46\u5b83\u5e76\u4e0d\u80fd\u4fdd\u8bc1\u5176\u51fa\u73b0\u5728\u751f\u6210\u7684\u8f93\u51fa\u6d88\u606f\u4e2d\u3002\u8fd9\u53d6\u51b3\u4e8e\u60a8\u7684\u6a21\u578b\u5229\u7528\u9644\u52a0\u4fe1\u606f\u7684\u80fd\u529b\uff01</p> <p>-- World Info | docs.ST.app </p>"},{"location":"chatting/sillytavern/get_resource.html#_3","title":"\u8c03\u6574\u4e16\u754c\u4fe1\u606f/\u77e5\u8bc6\u4e66\u6fc0\u6d3b\u8bbe\u7f6e","text":"<p>\u7279\u4f8b\u4f18\u5148</p> <p>\u8fd9\u91cc\u63d0\u4f9b\u7684\u8bbe\u7f6e\u4f9b\u53c2\u8003\uff0c\u5982\u679c\u4f60\u83b7\u53d6\u7684\u89d2\u8272\u5361\u5efa\u8bae\u7684\u8bbe\u7f6e\u548c\u8fd9\u91cc\u4e0d\u540c\uff0c\u542c\u4f5c\u8005\u7684\u3002</p> <p>\u70b9\u51fb\u4ece\u5de6\u81f3\u53f3\u7b2c\u56db\u4e2a\u6309\u94ae\uff08\u4e16\u754c\u4fe1\u606f\uff09\u6765\u6253\u5f00\u4e16\u754c\u4fe1\u606f\u7ba1\u7406\uff0c\u7136\u540e\u70b9\u51fb\u201d\u5168\u5c40\u4e16\u754c\u4fe1\u606f/\u77e5\u8bc6\u4e66\u6fc0\u6d3b\u8bbe\u7f6e\u201c \u4e0b\u65b9\u7684\u201d\u70b9\u51fb\u5c55\u5f00\u201c\u5c55\u5f00\u8bbe\u7f6e\u3002</p> <p></p> <p>\u4e0a\u56fe\u4e2d\u7684\u53c2\u6570\u5c31\u662f\u63a8\u8350\u7684\u8bbe\u7f6e\u4e86\uff0c\u4f46\u5982\u679c\u4f60\u60f3\u8fdb\u4e00\u6b65\u4e86\u89e3\u8fd9\u4e9b\u9009\u9879\u7684\u4f5c\u7528\u7684\u8bdd\u2026\u2026</p> \u90a3\u4e9b\u9009\u9879\u90fd\u6709\u4ec0\u4e48\u4f5c\u7528\uff1f <p>\u626b\u63cf\u6df1\u5ea6</p> <p>\u5b9a\u4e49\u5e94\u5728\u804a\u5929\u5386\u53f2\u8bb0\u5f55\u4e2d\u626b\u63cf\u591a\u5c11\u6761\u6d88\u606f\u6765\u83b7\u53d6\u6fc0\u6d3b\u4e16\u754c\u4e66\u6761\u76ee\u7684\u5173\u952e\u5b57\u3002</p> <ul> <li>\u5982\u679c\u8bbe\u7f6e\u4e3a 0\uff0c\u5219\u53ea\u626b\u63cf\u4e16\u754c\u4e66\u6761\u76ee\u672c\u8eab\u548c\u4f5c\u8005\u6ce8\u91ca\u3002</li> <li>\u5982\u679c\u8bbe\u7f6e\u4e3a 1\uff0c\u90a3\u4e48 Sillytavern \u53ea\u626b\u63cf\u6700\u540e\u4e00\u6761\u6d88\u606f\u3002</li> <li>2 = \u6700\u540e\u4e24\u6761\u6d88\u606f\uff0c\u7b49\u7b49\u3002</li> </ul> <p>\u626b\u63cf\u6df1\u5ea6\u4e0d\u662f\u8d8a\u591a\u8d8a\u597d</p> <p>\u8fc7\u9ad8\u7684\u626b\u63cf\u6df1\u5ea6\u4f1a\u5bfc\u81f4\u5728\u53d1\u9001\u6d88\u606f\u4e4b\u524d\u9700\u8981\u5904\u7406\u7684\u65f6\u95f4\u5ef6\u957f\uff0c\u540c\u4e00\u65f6\u95f4\u5185\u6fc0\u6d3b\u7684\u4e16\u754c\u4e66\u6761\u76ee\u8fc7\u591a\u4e5f\u6709\u53ef\u80fd\u5206\u6563 AI \u7684\u6ce8\u610f\u529b\u3002</p> <p>\u4e0a\u4e0b\u6587\u767e\u5206\u6bd4\u548c Token \u9884\u7b97</p> <p>\u5b9a\u4e49\u4e16\u754c\u4e66\u6761\u76ee\u4f7f\u7528\u7684 Token \u4e0a\u9650\u3002 \u53ef\u4ee5\u5b9a\u4e49\u76f8\u5bf9\u4e8e API \u7684\u6700\u5927\u4e0a\u4e0b\u6587\u8bbe\u7f6e\u7684\u9608\u503c\uff08\u4e0a\u4e0b\u6587\u767e\u5206\u6bd4\uff0c100%\u5373\u4e16\u754c\u4e66\u6761\u76ee\u53ef\u4ee5\u4f7f\u7528\u5168\u90e8\u7684\u4e0a\u4e0b\u6587\u957f\u5ea6\uff09\u6216\u76f4\u63a5\u6307\u5b9a Token \u4e0a\u9650\uff08\u9884\u7b97\uff0c0\u4e3a\u7981\u7528\uff09\u3002</p> <ul> <li>\u8d85\u8fc7\u9884\u7b97\u4e0a\u9650\u7684\u6761\u76ee\u5c06\u4e0d\u4f1a\u4f5c\u4e3a\u63d0\u793a\u53d1\u9001\u7ed9\u6a21\u578b\u3002</li> <li>\u5e38\u91cf\u6761\u76ee\u5c06\u9996\u5148\u63d2\u5165\u3002\u7136\u540e\u662f\u5177\u6709\u66f4\u9ad8\u987a\u5e8f\u53f7\u7684\u6761\u76ee\u3002</li> <li>\u901a\u8fc7\u76f4\u63a5\u63d0\u53ca\u5176\u952e\u63d2\u5165\u7684\u6761\u76ee\u6bd4\u5728\u5176\u4ed6\u6761\u76ee\u5185\u5bb9\u4e2d\u63d0\u53ca\u7684\u6761\u76ee\u5177\u6709\u66f4\u9ad8\u7684\u4f18\u5148\u7ea7\u3002</li> </ul> <p>\u6700\u5c0f\u6fc0\u6d3b\u6b21\u6570\u548c\u6700\u5927\u6df1\u5ea6</p> <p>\u6700\u5c0f\u6fc0\u6d3b\u6b21\u6570\u5982\u679c\u8bbe\u7f6e\u4e3a\u975e\u96f6\u503c\uff0c\u5219\u5c06\u5ffd\u7565\u201c\u626b\u63cf\u6df1\u5ea6\u201d\u7684\u9650\u5236\uff0c\u4ece\u6700\u65b0\u6d88\u606f\u5f00\u59cb\u5411\u540e\u641c\u7d22\u6240\u6709\u804a\u5929\u8bb0\u5f55\u4e2d\u7684\u5173\u952e\u5b57\uff0c\u76f4\u5230\u89e6\u53d1\u4e86\u6700\u5c0f\u6fc0\u6d3b\u6b21\u6570\u4e2d\u6307\u5b9a\u7684\u6761\u76ee\u3002\u8fd9\u4ecd\u5c06\u53d7\u5230\u6700\u5927\u6df1\u5ea6\u8bbe\u7f6e\u6216\u603b\u4f53\u9884\u7b97\u4e0a\u9650\u7684\u9650\u5236\u3002</p> <p>\u6700\u5c0f\u6fc0\u6d3b\u6b21\u6570\u4e0e\u6700\u5927\u9012\u5f52\u6b65\u6570\u4e92\u65a5</p> <p>\u4e00\u65e6\u8bbe\u7f6e\u4e86\u6700\u5927\u9012\u5f52\u6b65\u6570\uff0c\u5219\u6700\u5c0f\u6fc0\u6d3b\u6b21\u6570\u5c31\u4e0d\u8d77\u4f5c\u7528\u3002</p> <p>\u6700\u5927\u9012\u5f52\u6b65\u6570</p> <p>\u5f53\u8bbe\u7f6e\u4e3a\u96f6\u65f6\uff0c\u9012\u5f52\u5d4c\u5957\u4ec5\u53d7\u63d0\u793a\u9884\u7b97\u7684\u9650\u5236\u3002\u5f53\u8bbe\u7f6e\u4e3a\u975e\u96f6\u503c\u65f6\uff0c\u5c06\u626b\u63cf\u603b\u6570\u9650\u5236\u4e3a\u6240\u9700\u7684\u6700\u5927\u201c\u5d4c\u5957\u7ea7\u522b\u201d\u3002</p> <p>\u4f8b\u5982\uff1a </p> <pre><code>* \u8bbe\u7f6e\u4e3a 1 \u5b9e\u9645\u76f8\u5f53\u4e8e\u7981\u7528\u4e86\u9012\u5f52\uff0c\u56e0\u4e3a\u68c0\u67e5\u5728\u7b2c\u4e00\u6b65\u4e4b\u540e\u5c31\u505c\u6b62\u4e86\u3002\n* \u8bbe\u7f6e\u4e3a 2 \u8868\u793a\u53ea\u80fd\u6fc0\u6d3b\u4e00\u6b21\u9012\u5f52\u6761\u76ee\uff0c\u8bbe\u7f6e\u4e3a 3 \u53ef\u4ee5\u89e6\u53d1\u4e24\u6b21\u9012\u5f52......\n</code></pre> <p>\u533a\u5206\u5927\u5c0f\u5199</p> <p>\u542f\u7528\u5219\u8868\u793a\u4e3a\u4e86\u8fdb\u5165\u4e0a\u4e0b\u6587\uff0c\u8f93\u5165\u952e\u9700\u8981\u4e0e\u201c\u4e16\u754c\u4fe1\u606f\u201d\u6761\u76ee\u4e2d\u5b9a\u4e49\u7684\u5927\u5c0f\u5199\u76f8\u5339\u914d\u3002</p> <p>\u4f8b\u5982\uff0c\u542f\u7528\u6b64\u9009\u9879\u4e4b\u540e\uff0c \"Foo\" \u4f1a\u6fc0\u6d3b\u5173\u952e\u5b57\u4e3a \"Foo\" \u7684\u6761\u76ee\uff0c\u800c\u4e0d\u4f1a\u6fc0\u6d3b\u5173\u952e\u5b57\u4e3a \"foo\" \u7684\u6761\u76ee\u3002</p> <p>\u5305\u62ec\u540d\u79f0</p> <p>\u5b9a\u4e49\u662f\u5426\u5e94\u5c06\u804a\u5929\u53c2\u4e0e\u8005\u7684\u59d3\u540d\u4f5c\u4e3a\u6d88\u606f\u524d\u7f00\u5305\u542b\u5728\u626b\u63cf\u6587\u672c\u7f13\u51b2\u533a\u4e2d\u3002\u8fd9\u5141\u8bb8\u6fc0\u6d3b\u4f7f\u7528\u59d3\u540d\u4f5c\u4e3a\u5173\u952e\u5b57\u7684\u6761\u76ee\uff0c\u800c\u65e0\u9700\u5728\u6d88\u606f\u4e2d\u76f4\u63a5\u63d0\u53ca\u59d3\u540d\u3002</p> <p>\u5339\u914d\u6574\u4e2a\u5355\u8bcd</p> <p>\u4ec5\u5f53\u641c\u7d22\u6587\u672c\u4e2d\u5b58\u5728\u6574\u4e2a\u5355\u8bcd\u65f6\uff0c\u952e\u4ec5\u5305\u542b\u4e00\u4e2a\u5355\u8bcd\u7684\u6761\u76ee\u624d\u4f1a\u88ab\u5339\u914d\u3002\u9ed8\u8ba4\u60c5\u51b5\u4e0b\u542f\u7528\u3002</p> <p>\u6bd4\u5982\u5f00\u542f\u8be5\u8bbe\u7f6e\uff0c\u8f93\u5165\u952e\u4e3a \"King\u201d\uff0c\u90a3\u4e48\"long live the king\"\u4e4b\u7c7b\u7684\u6587\u5b57\u5c31\u4f1a\u88ab\u5339\u914d\uff0c\u4f46\u662f \"it's not to my liking\" \u5c31\u4e0d\u4f1a\u88ab\u5339\u914d\u3002</p> <p>\u6b64\u8bbe\u7f6e\u5bf9\u4e0d\u4f7f\u7528\u7a7a\u683c\u5206\u9694\u5355\u8bcd\u7684\u8bed\u8a00\uff08\u4f8b\u5982\u65e5\u8bed\u6216\u4e2d\u6587\uff09\u4f7f\u7528\u65f6\u53ef\u80fd\u4f1a\u4ea7\u751f\u4e0d\u5229\u5f71\u54cd\u3002\u6240\u4ee5\u5728\u5927\u591a\u6570\u65f6\u5019\uff0c\u8fd9\u4e2a\u9009\u9879\u90fd\u5e94\u8be5\u662f\u5173\u95ed\u7684\u3002</p>"},{"location":"chatting/sillytavern/get_resource.html#_4","title":"\u5bfc\u5165\u989d\u5916\u7684\u4e16\u754c\u4e66","text":"<p>\u4f60\u4e0b\u8f7d\u5230\u7684\u4e16\u754c\u4e66\u4e5f\u662f JSON \u683c\u5f0f\u3002 \u53ea\u8981\u627e\u548c\u5bfc\u5165\u9884\u8bbe\u4e00\u6837\u7684\u5bfc\u5165\u6309\u94ae\u6309\u4e0b\u53bb\uff0c\u7136\u540e\u9009\u62e9\u4e0b\u8f7d\u5230\u7684\u4e16\u754c\u4e66\u5c31\u597d\u3002</p> <p></p>"},{"location":"chatting/sillytavern/get_resource.html#_5","title":"\u4e3a\u6240\u6709\u804a\u5929\u542f\u7528\u4e16\u754c\u4e66","text":"<p>\u70b9\u51fb\u201d\u5df2\u542f\u7528\u7684\u4e16\u754c\uff08\u5168\u5c40\u6709\u6548\uff09\u201d\u4e0b\u9762\u7684\u8f93\u5165\u6846\uff0c\u9009\u62e9\u60f3\u8981\u542f\u7528\u7684\u4e16\u754c\u4e66\u5373\u53ef\u3002</p>"},{"location":"chatting/sillytavern/get_resource.html#_6","title":"\u4e3a\u89d2\u8272\u542f\u7528\u989d\u5916\u7684\u4e16\u754c\u4e66","text":"<p>\u8f6c\u5230\u89d2\u8272\u7ba1\u7406\u9762\u677f\uff0c\u9009\u62e9\u66f4\u591a\u83dc\u5355\u4e0b\u9762\u7684 \u201c\u5bfc\u5165\u89d2\u8272\u7684\u4e16\u754c\u4e66\u201d \u6309\u94ae\u3002</p> <p></p> <p>\u70b9\u51fb\u9644\u52a0\u77e5\u8bc6\u4e66\u4e0b\u9762\u7684\u8f93\u5165\u6846\uff0c\u9009\u62e9\u5e0c\u671b\u4e3a\u89d2\u8272\u542f\u7528\u7684\u4e16\u754c\u4e66\u3002\u5f53\u7136\u522b\u5fd8\u4e86\u4fdd\u5b58\u3002</p> <p></p>"},{"location":"chatting/sillytavern/get_resource.html#_7","title":"\u5f00\u542f\u6216\u5173\u95ed\u4e16\u754c\u4e66\u6761\u76ee","text":"<p>\u67d0\u4e9b\u65f6\u5019\u4f60\u4e5f\u8bb8\u60f3\u8981\uff08\u6216\u8005\u4f5c\u8005\u63d0\u9192\u4f60\u53ef\u4ee5\uff09\u542f\u7528\u6216\u7981\u7528\u67d0\u4e00\u4e16\u754c\u4e66\u6761\u76ee\uff0c\u4f8b\u5982\u4e16\u754c\u4e66\u63d0\u4f9b\u4e86\u4e00\u4efd\u7528\u6237\u89d2\u8272\u8bbe\u5b9a\u4f46\u4f60\u60f3\u4f7f\u7528\u81ea\u5df1\u7684\u4eba\u8bbe\u7684\u65f6\u5019\u3002</p> <p></p> <p>\u5728\u4e16\u754c\u4fe1\u606f\u754c\u9762\u4e2d\u9009\u62e9\u4e00\u4e2a\u4e16\u754c\u4e66\u4e4b\u540e\uff0c\u53ef\u4ee5\u70b9\u51fb\u5c55\u5f00\u6309\u94ae\uff08\u5411\u4e0b\u7684\u7bad\u5934\uff09\u65c1\u8fb9\u7684\u5f00\u5173\u5207\u6362\u4e16\u754c\u4e66\u6761\u76ee\u7684\u542f\u7528\u6216\u7981\u7528\u72b6\u6001\u3002</p>"},{"location":"chatting/sillytavern/get_resource.html#re","title":"\u6b63\u5219\u8868\u8fbe\u5f0f\uff08\u7b80\u79f0 RE\uff09","text":"<p>\u5927\u591a\u6570\u89d2\u8272\u5361\u4f1a\u4f7f\u7528\u4e00\u79cd\u53eb\u505a\u6b63\u5219\u8868\u8fbe\u5f0f\u7684\u6587\u672c\u66ff\u6362\u673a\u5236\u6765\u8fdb\u884c\u4e00\u4e9b\u64cd\u4f5c\uff0c\u4f8b\u5982\u5220\u9664\u601d\u7ef4\u94fe\uff08CoT\uff09\u7684\u5185\u5bb9\uff0c \u6216\u662f\u63d0\u4f9b\u4e00\u4e9b\u7f8e\u5316\u7684\u754c\u9762\u3002\u90e8\u5206\u7684\u9884\u8bbe\u53ef\u80fd\u4e5f\u4f1a\u4f7f\u7528\u6b63\u5219\u8868\u8fbe\u5f0f\u6765\u9690\u85cf\u6216\u5220\u9664\u8f93\u51fa\u4e2d\u7684\u6742\u8baf\u3002</p> <p></p> <p>\u5728\u6269\u5c55\u83dc\u5355\u4e2d\uff0c\u8f6c\u5230\u6b63\u5219\u9009\u9879\uff0c\u4f60\u5c31\u80fd\u770b\u89c1\u5bfc\u5165\u6b63\u5219\u7684\u6309\u94ae\u4e86\u3002</p>"},{"location":"chatting/sillytavern/get_resource.html#qr","title":"\u5feb\u901f\u56de\u590d\uff08\u7b80\u79f0 QR\uff09","text":"<p>\u5feb\u901f\u56de\u590d\u7684\u53ef\u7528\u6027\u548c\u9152\u9986\u7248\u672c\u5341\u5206\u76f8\u5173</p> <p>STscript \u4ecd\u5728\u79ef\u6781\u5f00\u53d1\u4e2d\uff0c\u56e0\u6b64\u8bf7\u4f7f\u7528\u6700\u65b0\u7248\u672c\u7684\u9152\u9986\u3002</p> <p>\u4e0d\u8981\u968f\u610f\u8fd0\u884c\u6765\u6e90\u4e0d\u540d\u7684\u5feb\u901f\u56de\u590d\u811a\u672c</p> <p>\u80fd\u529b\u8d8a\u5927\uff0c\u8d23\u4efb\u8d8a\u5927\u3002\u6267\u884c\u811a\u672c\u524d\u8bf7\u52a1\u5fc5\u5c0f\u5fc3\u5e76\u68c0\u67e5\u811a\u672c\u3002</p> <p>STscript \u662f\u4e00\u79cd\u7b80\u5355\u4f46\u529f\u80fd\u5f3a\u5927\u7684\u811a\u672c\u8bed\u8a00\uff0c\u53ef\u7528\u4e8e\u6269\u5c55 SillyTavern \u7684\u529f\u80fd\u800c\u65e0\u9700\u8fdb\u884c\u5927\u91cf\u7f16\u7801\uff0c\u800c\u5feb\u901f\u56de\u590d\u5219\u662f\u5185\u7f6e\u7684 SillyTavern \u6269\u5c55\uff0c\u63d0\u4f9b\u4e86\u4e00\u79cd\u5b58\u50a8\u548c\u6267\u884c\u811a\u672c\u7684\u7b80\u5355\u65b9\u6cd5\u3002</p> <p></p> <p>\u5feb\u901f\u56de\u590d\u83dc\u5355\u4f4d\u4e8e\u6269\u5c55\u83dc\u5355\u5185\uff0c\u4f9d\u7136\u662f\u70b9\u51fb\u90a3\u4e2a\u719f\u6089\u7684\u5bfc\u5165\u6309\u94ae\u5bfc\u5165\u3002</p> <p></p> <p>\u70b9\u51fb\u5168\u5c40\u6216\u804a\u5929\u5feb\u901f\u56de\u590d\u65c1\u8fb9\u7684\u52a0\u53f7\uff0c\u5c31\u4f1a\u65b0\u589e\u4e00\u884c\uff0c\u7136\u540e\u5c31\u53ef\u4ee5\u901a\u8fc7\u65c1\u8fb9\u7684\u4e0b\u62c9\u83dc\u5355\u542f\u7528\u4f60\u9009\u62e9\u7684\u5feb\u901f\u56de\u590d\u811a\u672c\u96c6\u5408\u3002</p> <p></p> <p>\u5df2\u7ecf\u542f\u7528\u7684\u5feb\u901f\u56de\u590d\u4f1a\u663e\u793a\u5728\u8f93\u5165\u6846\u7684\u4e0a\u65b9\uff0c\u5728\u7535\u8111\u4e0a\u4f60\u4e5f\u53ef\u4ee5\u901a\u8fc7\u53f3\u4e0a\u89d2\u7684\u6309\u94ae\u628a\u5feb\u901f\u56de\u590d\u653e\u5728\u4fa7\u8fb9\u3002</p>"},{"location":"chatting/sillytavern/install.html","title":"\u5b89\u88c5 SillyTavern","text":"<p>SillyTavern-Launcher \u662f\uff1f</p> <p>SillyTavern-Launcher \u662f\u4e00\u7ec4\u80fd\u591f\u81ea\u52a8\u5b89\u88c5 SillyTavern \u53ca\u5176\u4f9d\u8d56\uff0c\u4ee5\u53ca\u5176\u5b83\u8f85\u52a9\u529f\u80fd\u7684\u4e00\u4e9b\u811a\u672c\u3002</p> <p>\u4f46\u4ecb\u4e8e\u6587\u6863\u4f5c\u8005\u6ca1\u6709\u7528\u8fc7\uff0c\u6240\u4ee5\u4e5f\u4e0d\u4f1a\u6d89\u53ca\u76f8\u5173\u5185\u5bb9\u3002</p> <p>\u4e0d\u63a8\u8350\u5728\u6ca1\u6709\u4efb\u4f55\u51c6\u5907\u7684\u60c5\u51b5\u4e0b\u5728 VPS \u7b49\u4e91\u670d\u52a1\u4e0a\u642d\u5efa SillyTavern</p> <p>4202 \u5e74\u4e86\uff0c\u6d4f\u89c8\u5668\u90fd\u628a\u4e0d\u652f\u6301 HTTPS \u7684\u7f51\u7ad9\u6807\u8bb0\u6210\u4e0d\u5b89\u5168\u4e86\u3002 \u5018\u82e5\u4f60\u4e00\u610f\u5b64\u884c\u7684\u8bdd\uff0c\u522b\u6709\u7528\u5fc3\u7684\u4eba\u4fbf\u6709\u673a\u4f1a\u5077\u7aa5\u4f60\u7684\u804a\u5929\u8bb0\u5f55\uff0c\u751a\u81f3\u5077\u8d70\u4f60\u7684API\u5bc6\u94a5\uff0c\u8ba9\u4f60\u4ea7\u751f\u5927\u7b14\u8d26\u5355\u3002</p> <p>\u4f46\u662f\u4e0d\u5e78\u7684\u662f\uff0c\u51e0\u4e4e\u6ca1\u6709 CA \u4f1a\u4e3a IP \u7b7e\u53d1\u6709\u6548\u7684\u8bc1\u4e66\uff0c\u6240\u4ee5\u4e00\u4e2a\u57df\u540d\u663e\u7136\u662f\u5fc5\u987b\u7684\u3002\u6211\u4e5f\u4e0d\u80fd\u5efa\u8bae\u4f60\u7528\u81ea\u7b7e\u540d\u8bc1\u4e66\u7136\u540e\u5ffd\u7565\u8bc1\u4e66\u95ee\u9898\u3002</p> <p>\u4f46\u5047\u5982\u4f60\u90fd\u6709\u8db3\u591f\u7684\u667a\u6167\u4e70\u5230\u4e00\u4e2a\u57df\u540d\u7684\u8bdd\uff0c\u4f60\u4e5f\u5e94\u8be5\u6709\u8db3\u591f\u7684\u667a\u6167\u505a\u5230\u4e0a\u9762\u90a3\u4e9b\uff0c\u4e8e\u662f\u6211\u7684\u8bdd\u5c31\u771f\u7684\u6210\u5e9f\u8bdd\u4e86\u3002\uff08x\uff09</p> <p>\u56e0\u6b64\uff0c\u672c\u6587\u6863\u4e0d\u4f1a\u6d89\u53ca\u5728\u4e91\u7aef\u642d\u5efa SillyTavern \u7684\u65b9\u6cd5\u3002\u4f46\u5047\u5982\u4f60\u5df2\u7ecf\u6709\u4e86\u4e00\u4e2a\u57df\u540d\uff0c\u53ef\u4ee5\u53c2\u8003\u5b98\u65b9\u6587\u6863\u7684\u76f8\u5173\u90e8\u5206\u3002</p> <p>\u5f00\u59cb\u4e4b\u524d</p> <p>\u786e\u4fdd\u4f60\u8981\u8fd0\u884c SillyTavern \u7684\u73af\u5883\u4e2d\u5df2\u7ecf\u5b89\u88c5\u597d\u4e86 Git \u548c Node.js \u3002\u800c\u4e14\u80fd\u591f\u6b63\u5e38\u7684\u8fde\u63a5\u5230 GitHub \u548c npmjs \uff08\u6216\u5176\u955c\u50cf\uff09\u3002</p> <p>\u8fd9\u90e8\u5206\u6587\u6863\u4e0d\u4f1a\u518d\u6d89\u53ca\u5982\u4f55\u5b89\u88c5\u5b83\u4eec\uff0c\u4e5f\u4e0d\u4f1a\u89e3\u7b54\u5f62\u5982\u201c\u672a\u627e\u5230\u547d\u4ee4\u201d\u4e4b\u7c7b\u95ee\u9898\u3002</p>"},{"location":"chatting/sillytavern/install.html#sillytavern_1","title":"\u514b\u9686 SillyTavern \u4ed3\u5e93","text":"<pre><code>$ git clone https://github.com/SillyTavern/SillyTavern.git\n</code></pre> <p>\u9ed8\u8ba4\u60c5\u51b5\u4e0b\uff0c\u8fd9\u6b65\u64cd\u4f5c\u4f1a\u514b\u9686\u6700\u65b0\u7a33\u5b9a\u7248\u672c\u7684 release \u5206\u652f\u3002 \u65e2\u7136\u8fd9\u662f\u9ed8\u8ba4\u60c5\u51b5\uff0c\u8fd9\u5c31\u9002\u5408\u5927\u591a\u6570\u4eba\u3002</p> <p>\u5982\u679c\u4f60\u51fa\u4e8e\u67d0\u79cd\u8ff7\u4e4b\u81ea\u4fe1\u60f3\u8981\u7528\u5f00\u53d1\u4e2d\u7684 Staging \u7248\u672c\uff0c\u6216\u662f\u67d0\u4e2a\u65e7\u7248\u672c\u7684\u8bdd\uff0c\u5207\u6362\u76f8\u5e94\u7684\u5206\u652f\u548c\u7248\u672c\u6807\u7b7e\u5c31\u6210\u3002</p> <pre><code># \u5207\u6362\u5230 staging \u5206\u652f\nSillyTavern $ git checkout staging\n# \u5207\u6362\u5230\u67d0\u4e2a\u7248\u672c\uff0c\u4f8b\u5982 1.12.6\nSillyTavern $ git checkout 1.12.6\n# \u5207\u6362\u56de\u9ed8\u8ba4\u5206\u652f\nSillyTavern $ git checkout release\n</code></pre>"},{"location":"chatting/sillytavern/install.html#_1","title":"\u5b89\u88c5\u4f9d\u8d56","text":"<pre><code># install \u540e\u9762\u7684\u53c2\u6570\u5206\u522b\u8868\u793a\uff1a\n# --no-audit: \u9690\u85cf npm audit \u7684\u62a5\u544a\u4f9d\u8d56\u53ef\u80fd\u5b58\u5728\u6f0f\u6d1e\u7684\u8f93\u51fa\u3002\n# --no-fund: \u9690\u85cf npm fund \u63d0\u9192\u90e8\u5206\u6a21\u5757\u6b63\u5728\u5bfb\u6c42\u7ef4\u62a4\u8005\u6216\u8d44\u91d1\u652f\u6301\u7684\u63d0\u793a\u3002\n# --loglevel=error: \u5728\u8f93\u51fa\u4e2d\u9690\u85cf\u5927\u591a\u6570\u4e0d\u662f\u9519\u8bef\u7684\u8f93\u51fa\u3002\n# --no-progress: \u4e0d\u5728\u8fd0\u884c\u8fc7\u7a0b\u4e2d\u663e\u793a\u8fdb\u5ea6\u6761\u3002\n# --omit=dev: \u5ffd\u7565\u53ea\u5728\u5f00\u53d1\u8fc7\u7a0b\u4e2d\u624d\u9700\u8981\u7684\u4f9d\u8d56\u3002\nSillyTavern $ npm install --no-audit --no-fund --loglevel=error --no-progress --omit=dev\n</code></pre> \u8fd9\u662f\u8f93\u51fa<pre><code>&gt; sillytavern@1.12.7 postinstall\n&gt; node post-install.js\n\n\nup to date in 899ms\n</code></pre> <p>\u5728\u6bcf\u6b21\u66f4\u65b0\u9152\u9986\u540e\uff0c\u4f60\u6700\u597d\u4e5f\u66f4\u65b0\u4e00\u4e0b\u4f9d\u8d56\uff08\u518d\u6b21\u8fd0\u884c\u4e0a\u9762\u7684\u547d\u4ee4\uff09\u4ee5\u907f\u514d\u53ef\u80fd\u4f1a\u53d1\u751f\u7684\u610f\u5916\u60c5\u51b5\u3002</p>"},{"location":"chatting/sillytavern/install.html#_2","title":"\u542f\u52a8","text":"<p>Tips</p> <p>\u5728 Windows \u4e0a\uff0c\u4f60\u4e5f\u53ef\u4ee5\u901a\u8fc7\u53cc\u51fb <code>SillyTavern</code> \u76ee\u5f55\u4e2d\u7684 <code>start.bat</code> \u6765\u8fd0\u884c\u3002</p> <pre><code># \u8fd9\u4e24\u4e2a\u547d\u4ee4\u7684\u6548\u679c\u51e0\u4e4e\u662f\u4e00\u6837\u7684\u3002\u533a\u522b\u5c31\u662f\u4e0b\u9762\u7684\u547d\u4ee4\u4f1a\u5e2e\u4f60\u8fd0\u884c\u4e0a\u4e00\u6b65\u3002\nSillyTavern $ node server.js\n# Termux\nSillyTavern $ ./start.sh\n# Windows \u7ec8\u7aef\uff08PowerShell\uff09\nSillyTavern $ .\\start.bat\n</code></pre> \u8fd9\u662f\u8f93\u51fa<pre><code>Node version: v22.9.0. Running in undefined environment. Server directory: /Users/Foo/repo/SillyTavern\nPreferring IPv4 for DNS resolution\nUsing data root: ./data\n\n\nSillyTavern 1.12.7\nRunning 'staging' (b837c482f) - 2024-11-01 20:17:29 +0200\n\n&lt;i&gt; [webpack-dev-middleware] wait until bundle finished\nwebpack 5.95.0 compiled successfully in 5750 ms\nLaunching...\nSillyTavern is listening on IPv4: 127.0.0.1:8000\n\n=================================================\n\nGo to: http://127.0.0.1:8000/ to open SillyTavern\n\n=================================================\n</code></pre> <p>\u63a5\u4e0b\u6765\uff0c\u5728\u6d4f\u89c8\u5668\u4e2d\u6253\u5f00 http://127.0.0.1:8000/ \u6216\u4f60\u7684\u8f93\u51fa\u4e2d\u663e\u793a\u7684\u5730\u5740\uff0c\u5373\u53ef\u6253\u5f00 SillyTavern \u7684\u754c\u9762\u3002</p> <p></p> <p>SillyTavern \u4f1a\u6839\u636e\u6d4f\u89c8\u5668\u6240\u4f7f\u7528\u7684\u8bed\u8a00\u81ea\u52a8\u9009\u62e9\u754c\u9762\u7684\u8bed\u8a00\u3002</p> <p>(1.12.5\u53ca\u4ee5\u524d\u7248\u672c) \u786e\u4fdd\u7528\u6237\u8bbe\u7f6e\u662f\u201d\u9ad8\u7ea7\u201c\u6a21\u5f0f</p> <p>\u67d0\u4e9b\u64cd\u4f5c\uff08\u4f8b\u5982\u5bfc\u5165\u5bf9\u8bdd\u8865\u5168\u9884\u8bbe\uff09\u9700\u8981\u5728\u201d\u9ad8\u7ea7\u201c\u6a21\u5f0f\u4e0b\u8fdb\u884c\uff0c\u5982\u679c\u4f60\u627e\u4e0d\u5230\u5bfc\u5165\u6309\u94ae\uff0c\u4f60\u53ef\u80fd\u9700\u8981\u4fee\u6539\u7528\u6237\u754c\u9762\u6a21\u5f0f\u3002</p> <p>\u70b9\u51fb\u201d\u7528\u6237\u8bbe\u7f6e\u201c\u6309\u94ae\uff08\u7b2c\u4e94\u4e2a\uff09\u53ef\u4ee5\u6253\u5f00\u7528\u6237\u8bbe\u7f6e\u7a97\u53e3\uff0c\u7b80\u5355\u548c\u9ad8\u7ea7\u6a21\u5f0f\u7684\u533a\u522b\u5982\u4e0b\u3002</p> <p></p> <p></p> <p>\\1.12.6 \u7248\u672c\u5f00\u59cb\u5220\u9664\u4e86\u7b80\u5355\u6a21\u5f0f\uff0c\u56e0\u6b64\u4e0d\u9700\u8981\u8fd9\u4e48\u505a\u4e86\u3002</p>"},{"location":"chatting/sillytavern/termux_deployment_script/index.html","title":"\u6742\u9c7c\u7528 SillyTavern \u90e8\u7f72\u811a\u672c on Termux","text":"<p>\u5728 Termux \u4e0a\u90e8\u7f72 SillyTavern \u548c Clewd\u3002</p> <p>\u6742\u9c7c~\u6742\u9c7c~</p> <p>\ud83d\ude08 \u627f\u8ba4\u4f60\u662f\u770b\u4e0d\u61c2\u624b\u52a8\u5b89\u88c5\u6559\u7a0b\u6216\u662f\u61d2\u72d7\u6742\u9c7c\u4e86\uff1f</p>"},{"location":"chatting/sillytavern/termux_deployment_script/index.html#_1","title":"\u7cfb\u7edf\u9700\u6c42","text":"<ul> <li>\u5b89\u88c5 Termux\uff0c\u4ee5\u53ca Termux:API \u548c Termux:Widgets \u63d2\u4ef6\u3002</li> <li>\u62e5\u6709\u80fd\u591f\u826f\u597d\u7684\u8fde\u63a5\u5230 Github \u548c/\u6216 npmjs \u7684\u56fd\u9645\u4e92\u8054\u7f51\u8fde\u63a5\u3002</li> </ul>"},{"location":"chatting/sillytavern/termux_deployment_script/index.html#_2","title":"\u8fd0\u884c\u6b65\u9aa4","text":"<ul> <li>\u5728 Termux \u4e0a\u8fd0\u884c\u4ee5\u4e0b\u547d\u4ee4\uff1a</li> </ul> <pre><code>curl -O https://raw.githubusercontent.com/foobarz076/gtss_ai_docs/refs/heads/main/docs/chatting/sillytavern/termux_deployment_script/setup-termux.sh &amp;&amp; chmod +x setup-termux.sh &amp;&amp; ./setup-termux.sh\n</code></pre> <ul> <li>\u6309\u63d0\u793a\u8fd0\u884c\u811a\u672c\uff0c\u76f4\u5230\u770b\u5230\u4e0b\u9762\u4e24\u884c\uff1a</li> </ul> <pre><code>\u2705 \u9152\u9986\u548c Clewd \u5b89\u88c5\u5b8c\u6bd5\n\ud83d\udc49 \u6dfb\u52a0 Termux:Widget \u5c0f\u90e8\u4ef6\u6216\u5feb\u6377\u65b9\u5f0f\u5373\u53ef\u5206\u522b\u8fd0\u884c clewd \u548c\u9152\u9986\u3002\n</code></pre> <p>Info</p> <p>\u9664\u4e86\u4e0b\u9762\u7684\u65b9\u5f0f\u4ee5\u5916\uff0c\u4f60\u4e5f\u53ef\u4ee5\u901a\u8fc7 SillyTavern \u548c Clewd \u5b89\u88c5\u6559\u7a0b\u4e2d\u7684\u547d\u4ee4\u624b\u52a8\u542f\u52a8 SillyTavern \u548c Clewd\u3002</p> <ul> <li>\u6dfb\u52a0 Termux:Widget \u5c0f\u7ec4\u4ef6\u6216\u5feb\u6377\u65b9\u5f0f\u3002</li> </ul> <p>Info</p> <p>\u5177\u4f53\u65b9\u5f0f\u56e0\u4f60\u4f7f\u7528\u7684\u684c\u9762\u4e0d\u540c\u800c\u5f02\uff0c\u8fd9\u91cc\u4ee5 Pixel \u542f\u52a8\u5668\u4e3a\u4f8b\u3002 \u57fa\u4e8e AOSP \u542f\u52a8\u5668\uff08Launcher3\uff09\u7684\u5176\u5b83\u684c\u9762\uff0c\u4f8b\u5982 Lawnchair \u7684\u64cd\u4f5c\u65b9\u5f0f\u7c7b\u4f3c\u3002</p> <p></p> <pre><code>* \u6309\u4f4f Termux:Widget \u7684\u56fe\u6807\uff0c\u9009\u62e9\u201c\u5fae\u4ef6\u201d\u3002\n</code></pre> <p></p> <pre><code>* \u5c06\u5c0f\u7ec4\u4ef6\u6216\u5feb\u6377\u65b9\u5f0f\u62d6\u653e\u5230\u684c\u9762\u4e0a\u3002\n</code></pre> <p></p>"},{"location":"drawing/index.html","title":"Index","text":"<ul> <li>Section:<ul> <li>section/index.md </li> <li>Page 1: section/page-1.md</li> <li>Page n: section/page-n.md</li> </ul> </li> </ul>"},{"location":"drawing/index.html#welcome-to-mkdocs","title":"Welcome to MkDocs","text":"<p>For full documentation visit mkdocs.org.</p>"},{"location":"drawing/index.html#commands","title":"Commands","text":"<ul> <li><code>mkdocs new [dir-name]</code> - Create a new project.</li> <li><code>mkdocs serve</code> - Start the live-reloading docs server.</li> <li><code>mkdocs build</code> - Build the documentation site.</li> <li><code>mkdocs -h</code> - Print help message and exit.</li> </ul>"},{"location":"drawing/index.html#project-layout","title":"Project layout","text":"<pre><code>mkdocs.yml    # The configuration file.\ndocs/\n    index.md  # The documentation homepage.\n    ...       # Other markdown pages, images and other files.\n</code></pre>"},{"location":"resources/index.html","title":"Index","text":"<ul> <li>Section:<ul> <li>section/index.md </li> <li>Page 1: section/page-1.md</li> <li>Page n: section/page-n.md</li> </ul> </li> </ul>"},{"location":"resources/index.html#welcome-to-mkdocs","title":"Welcome to MkDocs","text":"<p>For full documentation visit mkdocs.org.</p>"},{"location":"resources/index.html#commands","title":"Commands","text":"<ul> <li><code>mkdocs new [dir-name]</code> - Create a new project.</li> <li><code>mkdocs serve</code> - Start the live-reloading docs server.</li> <li><code>mkdocs build</code> - Build the documentation site.</li> <li><code>mkdocs -h</code> - Print help message and exit.</li> </ul>"},{"location":"resources/index.html#project-layout","title":"Project layout","text":"<pre><code>mkdocs.yml    # The configuration file.\ndocs/\n    index.md  # The documentation homepage.\n    ...       # Other markdown pages, images and other files.\n</code></pre>"}]}